-- Poems batch 220
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('21780b19-c4f5-4619-973b-285cd4945ab3','再和聾字韻詩一謝史宰一呈黎丞  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','化感兒嬉七十翁，波餘猶足活瘖聾。',64,'全唐诗/poet.song.203000.json','["化感兒嬉七十翁，波餘猶足活瘖聾。", "肯安恬退淡中味，大覺催科拙處工。", "及物坐看馴乳雉，蘇民更欲駡尸蟲。", "恢恢游刃渾餘地，贏得賡酬伴贊公。"]'),
('aa3d265b-b3b1-4820-8d8e-fff070924736','再和聾字韻詩一謝史宰一呈黎丞  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','脩齡閬苑一仙翁，拜跪無妨豈是聾。',64,'全唐诗/poet.song.203000.json','["脩齡閬苑一仙翁，拜跪無妨豈是聾。", "松柏耐寒宜歲晚，池塘入夢泄春工。", "群趨摘尾渾行鷺，一見降心賦草蟲。", "莫謂田園動歸興，渭濱垂老尚三公。"]'),
('ad68197f-2718-4018-a64e-4bfcd1ced918','林府判和前三蘇圖詩再依韻爲謝','徐鹿卿','宋','宋诗','song-poetry','','[]','蜀道山川鬼斸開，文星屢謫北中來。',64,'全唐诗/poet.song.203000.json','["蜀道山川鬼斸開，文星屢謫北中來。", "凌雲賦客邀難住，捉月仙人喚不迴。", "坡潁與泉同一姓，漢唐比宋孰多材。", "公詩狀出眉州畫，不學香山詠馬嵬。"]'),
('e2312be5-c1f9-4087-8863-ad17191c1a7e','張法示詩集爲題其後','徐鹿卿','宋','宋诗','song-poetry','','[]','聞名每恨不相識，相識梅關眼带青。',64,'全唐诗/poet.song.203000.json','["聞名每恨不相識，相識梅關眼带青。", "雪幹冰姿披宿霧，銀鈎玉唾麗繁星。", "居隣山谷傳宗派，系出燕公有典刑。", "陶寫風光吟咏了，更培勳業照青冥。"]'),
('5d1742d9-93dc-499b-ac88-657f5d4df2f6','次韻史宰賀受薦','徐鹿卿','宋','宋诗','song-poetry','','[]','玉立青規照眼新，封侯端合踵平津。',64,'全唐诗/poet.song.203000.json','["玉立青規照眼新，封侯端合踵平津。", "公車久滿三千牘，屬國猶淹十九春。", "一覩雉馴知善政，雙飛鶚薦爨陳人。", "焦桐會有知音在，未必終爲爨下薪。"]'),
('67f579aa-4349-465d-8c88-0237c82d2efc','送何生龔生歸曲江','徐鹿卿','宋','宋诗','song-poetry','','[]','肯爲從師出嶺來，三千子亦可人哉。',64,'全唐诗/poet.song.203000.json','["肯爲從師出嶺來，三千子亦可人哉。", "文章要似風騷體，學問非爲利祿媒。", "泥迹尚留鴻爪在，雲程已報鶚書催。", "儀刑只在鄉關近，前有張余後有崔。"]'),
('60042ad2-6055-4db5-8b76-6c11182e0839','和南康趙簿贈詩','徐鹿卿','宋','宋诗','song-poetry','','[]','瑞世詞章響佩琚，過人學力更充餘。',64,'全唐诗/poet.song.203000.json','["瑞世詞章響佩琚，過人學力更充餘。", "盤空紫氣難藏劍，照坐青藜趣校書。", "已脫塵埃辭矮屋，還將清泚映污渠。", "雲霄此去功名逼，詩酒生涯莫作疎。"]'),
('c5fc6062-bad0-42ed-ae96-cba2e7bb3e06','次史君喜雨韻併呈府判','徐鹿卿','宋','宋诗','song-poetry','','[]','明公閔雨志平民，祈禱無他只一真。',64,'全唐诗/poet.song.203000.json','["明公閔雨志平民，祈禱無他只一真。", "萬里天高隨感應，半空雷震忽亨屯。", "挽回庾嶠生生意，化作商霖處處均。", "歸斡元功調玉燭，從今三過續絲綸。"]'),
('9e16e6fa-bbbf-4738-8510-5f4692e81403','次史君喜雨偈韻  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','朱轓臨蒞甫經秋，已報民庸總若疇。',64,'全唐诗/poet.song.203000.json','["朱轓臨蒞甫經秋，已報民庸總若疇。", "剩有心思圖惠養，更無毫末事誅求。", "操存對越神明久，應禱旋銷旱魃憂。", "天意念功殊未別，且將甘露略相酬。"]'),
('62600977-760a-4a79-9f66-3a44fef89914','次史君喜雨偈韻  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','田里懽傳歲有秋，已占休證叶龜疇。',64,'全唐诗/poet.song.203000.json','["田里懽傳歲有秋，已占休證叶龜疇。", "連朝霪雨忻從欲，一念通神只反求。", "暫向嶺邊宣主澤，每先天下爲民憂。", "藩方久袖爲霖手，百萬蒼生願未酬。"]'),
('f0bed823-06c9-43a6-bc7a-69b4587a3c54','追挽監簿李公','徐鹿卿','宋','宋诗','song-poetry','','[]','誰將僞學涴忠良，滿眼脂韋時樣粧。',64,'全唐诗/poet.song.203000.json','["誰將僞學涴忠良，滿眼脂韋時樣粧。", "敢斥弘羊蘇歲旱，始驚鳴鳳見朝陽。", "生前運蹇官三品，死後流傳紙一張。", "前輩遺風今寂寞，狂歌聊復弔清湘。"]'),
('21f106a1-c03f-44ee-a7d3-2d61347f2bba','送表伯朱丞尉  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','瘴嵐窟裏抱琴歸，髭鬢青青只舊時。',64,'全唐诗/poet.song.203000.json','["瘴嵐窟裏抱琴歸，髭鬢青青只舊時。", "人道器之真鐵漢，我疑方朔到瑶池。", "從前日月忙中過，此去山林分外宜。", "晚歲栽培無別計，萬金良産在孫枝。"]'),
('c1c3ca54-0cea-42e7-844a-faec52ff9b70','送表伯朱丞尉  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','十年蹤跡兩相望，邂逅崆峒喜欲狂。',64,'全唐诗/poet.song.203000.json','["十年蹤跡兩相望，邂逅崆峒喜欲狂。", "見說橋成鞭巨石，忽看水駃舞歸艎。", "面無慚色言何卹，民有遺思味最長。", "故國蓴鱸勞夢想，從公鷗浦弄斜陽。"]'),
('ee6d53f7-c4da-4974-8ef8-544dd757c771','黎丞命飲辭之以詩','徐鹿卿','宋','宋诗','song-poetry','','[]','湛泉問訊十分春，安得搘筇踵後塵。',64,'全唐诗/poet.song.203000.json','["湛泉問訊十分春，安得搘筇踵後塵。", "不是稽山無賀老，定應坐客畏陳遵。", "鳬飛渤島姑容我，馬繫堂階解笑人。", "重約焦坑新茗熟，一甌相對話情親。"]'),
('942f17df-ab79-4839-9ad4-fb0a55879840','爲曾僉喜雨','徐鹿卿','宋','宋诗','song-poetry','','[]','隔年亢旱到初春，才掛征帆雨浥塵。',64,'全唐诗/poet.song.203000.json','["隔年亢旱到初春，才掛征帆雨浥塵。", "諒得靖共神所介，更留約束後來遵。", "今朝南浦悲行子，明日陽關憶故人。", "老我滯留歸未得，斗升全爲白頭親。"]'),
('4ce37b66-1c0c-4a77-9fce-5b509f7edeca','史宰見和依韻爲謝','徐鹿卿','宋','宋诗','song-poetry','','[]','巧釀河陽滿縣春，居然盡洗簿書塵。',64,'全唐诗/poet.song.203000.json','["巧釀河陽滿縣春，居然盡洗簿書塵。", "桑間馴雉誠爲異，渚畔飛鷗祇漸遵。", "良玉自應求即我，明珠寧肯暗投人。", "冷官竊笑詩情淺，無計能令子建親。"]'),
('9bcd921e-ca40-43e6-92cc-6cb8717b9ba8','依韻戲呈諸丈','徐鹿卿','宋','宋诗','song-poetry','','[]','雲萍邂逅總青春，意氣飄飄足絕塵。',64,'全唐诗/poet.song.203000.json','["雲萍邂逅總青春，意氣飄飄足絕塵。", "酒有盈罇聊共醉，食無重味恐難遵。", "浮生百歲風和月，官路連年我送人。", "自此彈冠知有喜，莫言非故亦非親。"]'),
('fe3a3634-c8e6-4236-97f3-287e38353ae8','再呈曾僉','徐鹿卿','宋','宋诗','song-poetry','','[]','去去榮觀上國春，幾人竚立望車塵。',64,'全唐诗/poet.song.203000.json','["去去榮觀上國春，幾人竚立望車塵。", "如星於北常懷拱，自海而南不必遵。", "簷雨挑燈三益友，錦帆載酒一詩人。", "勳名自致男兒事，莫倚金張肺腑親。"]'),
('f989cc6f-fd0d-486d-9350-102327995664','諸公約會縣中觀燈不克赴既又見趣座中賦一章','徐鹿卿','宋','宋诗','song-poetry','','[]','上元花市明如晝，良會應知臭味同。',64,'全唐诗/poet.song.203000.json','["上元花市明如晝，良會應知臭味同。", "自笑無殽似坡老，豈能載酒過揚雄。", "寒盟如我顔生赤，燒燭輸君坐照紅。", "莫憶遶梁聲未斷，且將詩酒謝春風。"]'),
('40a16afb-d931-4340-9d2d-d84bd62ee7ec','即席次府判韻','徐鹿卿','宋','宋诗','song-poetry','','[]','梨園勝日問春光，細細飄來滿院香。',64,'全唐诗/poet.song.203000.json','["梨園勝日問春光，細細飄來滿院香。", "色縞半空天與潔，花翻六出雪呈祥。", "月華巧幻溶溶景，風韻偏宜淡淡粧。", "深夜霓裳欲飛舉，篝燈何惜共徜徉。"]'),
('535164db-bbf4-487d-8d88-170b7ab9e397','興教寺勸農呈史君','徐鹿卿','宋','宋诗','song-poetry','','[]','自從豳雅無傳後，漢有龔黄宋有羅。',64,'全唐诗/poet.song.203000.json','["自從豳雅無傳後，漢有龔黄宋有羅。", "夙駕朱轓勤勸相，奉宣黄紙放催科。", "一犂烟雨郊原曉，千里春風嶺嶠和。", "看取便民橋下水，滿江濃綠漲恩波。"]'),
('54b4a14d-2f00-4ba6-a38a-54832d65d7b0','挽安人陳氏','徐鹿卿','宋','宋诗','song-poetry','','[]','節義千年一緹縈，復因緩急見高情。',64,'全唐诗/poet.song.203000.json','["節義千年一緹縈，復因緩急見高情。", "風霜凜凜欺行役，天地昭昭監此誠。", "羞藻敬恭宗祀重，空花了悟世緣輕。", "歸時認得來時路，暗想蓬萊是故程。"]'),
('3ad420f1-8b0a-4692-b02c-4702bdb29eff','別倅車','徐鹿卿','宋','宋诗','song-poetry','','[]','聖朝疎網示寬平，鞫讞煩公六月行。',64,'全唐诗/poet.song.203000.json','["聖朝疎網示寬平，鞫讞煩公六月行。", "穿屋可嗟嚚訟險，持衡只在此心明。", "蘇冤去釋五原旱，了事歸看快閣晴。", "檢點舊遊章世美，甘棠蔽芾滿江城。"]'),
('85d26939-5b01-4fba-9ad6-7cf78e3a594d','餞羅史君二首  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','聖朝選表作公卿，如此才猷合要津。',64,'全唐诗/poet.song.203000.json','["聖朝選表作公卿，如此才猷合要津。", "上亦知公能體國，心乎濟物不謀身。", "梅花嶺下忽千里，荷橐班中添一人。", "民願借留留不得，多應留與十分春。"]'),
('30da5fc4-2035-447a-a32f-16b6d8ea9eaa','餞羅史君二首  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','西鄰有女出深閨，十二樓中奉盥匜。',64,'全唐诗/poet.song.203000.json','["西鄰有女出深閨，十二樓中奉盥匜。", "大德愛憐知有造，小心莊肅但無欺。", "請爲公祝千年壽，耻學人填半額眉。", "舊著衣裳今好在，芳心暗逐錦帆移。"]'),
('ba36d260-a551-4646-9f28-9d8a296f3734','令佐約登息梅嶺不克赴次來韻','徐鹿卿','宋','宋诗','song-poetry','','[]','撐空一嶺鎮東隅，未遂登臨且按圖。',64,'全唐诗/poet.song.203000.json','["撐空一嶺鎮東隅，未遂登臨且按圖。", "城雉崢嶸歸眼界，徑蛇盤屈透雲衢。", "句中風月天無盡，物外亭臺山不孤。", "令佐才高當辦此，稍容拙者自嬉娛。"]'),
('be1b8c3f-3a31-413d-88b7-11080b25d45b','喜雨上史使君馮宮講','徐鹿卿','宋','宋诗','song-poetry','','[]','平田秋水高潺湲，大府寬條俶布宣。',64,'全唐诗/poet.song.203000.json','["平田秋水高潺湲，大府寬條俶布宣。", "不旱猶應言有旱，省諐敢自謂無諐。", "倒翻雲外菩提水，幻出人間擺柳天。", "阡陌曉來傳好語，作霖人在嶺梅邊。"]'),
('e84c6c6e-16a1-4528-8a44-466760140fa3','湛泉酌餞黎有詩壁間遂次其韻','徐鹿卿','宋','宋诗','song-poetry','','[]','幾人林下賦歸休，公獨翩然汗漫遊。',64,'全唐诗/poet.song.203000.json','["幾人林下賦歸休，公獨翩然汗漫遊。", "味道不妨寒似水，入時須用曲如鉤。", "從來鄰父邀皆去，底事官曹挽不留。", "後夜相從那復得，月明千里故山秋。"]'),
('93e7f0fa-67d2-4ae2-b4c9-65540a9bc49c','壽馮宮教  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','子月陽從律管囘，剛明鍾聚濟時材。',64,'全唐诗/poet.song.203000.json','["子月陽從律管囘，剛明鍾聚濟時材。", "出當聖世千齡會，小爲橫江百姓來。", "生意無窮倉有粟，春工不擇地宜梅。", "從今拈出經綸手，吾道輝光壽域開。"]'),
('ac164f57-0047-46f3-af24-5545a227ad05','壽馮宮教  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','文星照耀大江濱，春色無邊上藻芹。',64,'全唐诗/poet.song.203000.json','["文星照耀大江濱，春色無邊上藻芹。", "千載魯宮覃美化，百年洛學嗣清芬。", "但同南國歌申伯，敢效東坡壽卯君。", "誰謂廣文官舍冷，眼前突兀厦連雲。"]'),
('ef73d407-0d5b-4ed0-bf26-7dcc0ad69a4a','壽馮宮教  其三','徐鹿卿','宋','宋诗','song-poetry','','[]','公占金華寶婺躔，我生劍氣斗牛邊。',64,'全唐诗/poet.song.203000.json','["公占金華寶婺躔，我生劍氣斗牛邊。", "雲山闊遠一千里，歲紀參差三十年。", "初度謾言同日月，榮枯相去異天淵。", "香山不鄙兼謩少，名節當參九老傳。"]'),
('8e3ce67e-d1d2-4169-b1f8-1e5514c535ef','送游同年赴增城征官  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','蹋雪南征靡憚勞，此公端不爲錐刀。',64,'全唐诗/poet.song.203000.json','["蹋雪南征靡憚勞，此公端不爲錐刀。", "能行所學官無小，苟利於民譽自高。", "鞭算何須窮孔穴，荆班且共說風騷。", "吏姦民蠹渾閑事，臨政先教立脚牢。"]'),
('40097a2a-5ee8-4ab2-a99f-3dfe65a05e1e','送游同年赴增城征官  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','君行嶺海獨賢勞，我念鄉關折大刀。',64,'全唐诗/poet.song.203000.json','["君行嶺海獨賢勞，我念鄉關折大刀。", "心事有如江水白，誼風端共庾山高。", "理財只合從周禮，飲酒何妨讀楚騷。", "客至無氈相諒得，請將詩句當共牢。"]'),
('ad73ffb2-bd9d-4315-8033-b6676f790103','次宮教六齋慶成韻  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','魯侯修泮幾千年，盛事相符易地然。',64,'全唐诗/poet.song.203000.json','["魯侯修泮幾千年，盛事相符易地然。", "夏屋渠渠高插斗，誨言歷歷暖於氈。", "簡編有味芸香細，風月無邊草色鮮。", "樂道簞瓢亦人耳，安居何憚士希賢。"]'),
('19521f08-30fe-4e33-af37-90ce907cfffa','次宮教六齋慶成韻  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','邪傾枝柱費三年，革故圖新有待然。',64,'全唐诗/poet.song.203000.json','["邪傾枝柱費三年，革故圖新有待然。", "凌雨千間駢紫佩，濂溪一派寶青氈。", "韶鳴已覺俱忘味，鼎養何妨更擊鮮。", "師帥作成真有道，詵詵弟子信皆賢。"]'),
('78bcfa30-f671-4d2a-b0e8-ef4d2bf98544','宮教再以詩來復次韻','徐鹿卿','宋','宋诗','song-poetry','','[]','蚤負才名四十年，胸中成室總天然。',64,'全唐诗/poet.song.203000.json','["蚤負才名四十年，胸中成室總天然。", "承流且建偏州學，談道終分廣厦氈。", "椽筆發揮春藻麗，鸞旂照映雪花鮮。", "幾人魚躍鳶飛下，黄卷生涯對聖賢。"]'),
('d3f2965c-f66a-44cd-93b4-063fc6769ce7','陳府判邀遊梅關','徐鹿卿','宋','宋诗','song-poetry','','[]','庾嶺蒼蒼古復今，公餘杖履愜幽尋。',64,'全唐诗/poet.song.203000.json','["庾嶺蒼蒼古復今，公餘杖履愜幽尋。", "兩崖峭壁風霜骨，一片清泉佛祖心。", "靜浣世緣揮酒椀，更添春色上梅林。", "冥搜翻覺詩情拙，滿眼皆詩祇用吟。"]'),
('ae875d92-f00d-44d0-92fa-0ddb9ae1c08b','勸農上宮教','徐鹿卿','宋','宋诗','song-poetry','','[]','竹馬兒童喜欲狂，循良太守似龔黄。',64,'全唐诗/poet.song.203000.json','["竹馬兒童喜欲狂，循良太守似龔黄。", "倉庚百囀蠶桑啟，布穀一聲稉稻香。", "耕饁盡陶豳國化，遊嬉已遍舜民鄉。", "文書便合登高閣，爲說東郊入務忙。"]'),
('35a609b1-8d64-4a7d-87b5-c59963bc27f7','中秋對月有懷','徐鹿卿','宋','宋诗','song-poetry','','[]','前年今日文闈裏，鏖戰紛紛酣萬蟻。',240,'全唐诗/poet.song.203000.json','["前年今日文闈裏，鏖戰紛紛酣萬蟻。", "去年歸去浙江頭，塵滿征衫未曾洗。", "今年又對梅花嶺，日味虀鹽翻故紙。", "乾坤一季兩中秋，兄弟三人各千里。", "伯兄恍作期年別，夏口武昌幾山水。", "季弟秋初辭母去，去日不堪重倒指。", "孔懷一念我既然，伯季念吾亦如此。", "天涯海角渺相望，蓬轉萍浮無定止。", "古言秋月只愁人，人自關心何預此。", "陰晴圓缺歲復歲，離合悲歡固其理。", "何時當有二頃田，歸卧雲山漱清泚。", "烹茶煨栗對秋輝，老穉團欒相爾汝。", "此心烱烱明月知，一醉狂吟聊復爾。", "詩成鄉夢透泉溪，人物山川亦良是。", "殷勤多謝桂花風，忽遣清香喚人起。"]'),
('70e06062-eab7-4eda-988e-3bfd8d76d127','溪泉命客','徐鹿卿','宋','宋诗','song-poetry','','[]','湛泉泉水鏡樣明，清溪溪水玉似清。',240,'全唐诗/poet.song.203000.json','["湛泉泉水鏡樣明，清溪溪水玉似清。", "是中風物俱可人，一塵不到世累輕。", "詩家者流修水裔，筆頭春工不擇地。", "川君水靈聖得知，爭遣酒兵互招致。", "泉聲似喜嘉客到，㶁㶁琴鳴徐弄操。", "兩榕傴僂巧逢迎，萬竹敲鏗當呵導。", "清溪忽走間使來，言傳號渙驅風雷。", "鼻祖校文遊覽舊，對壘者誰人姓柳。", "百年遺事儻可徵，今夕尋盟一盃酒。", "客聞斯言但唯唯，熊掌固奇魚亦美。", "賞心樂事古難并，到此如何决行止。", "憑欄會意夢非夢，止者靜兮流者動。", "嗟嗟此水真吾師，去流皆可隨所之。", "揮手謝泉歸路晚，風雨瀟瀟溪上館。", "明朝收拾入新詩，兩處溪泉皆意滿。"]'),
('e44a2903-ac66-4600-90fb-8bbd3f3e6148','獨坐','徐鹿卿','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江釀碧山滴藍，書堂枕北戶啟南。',128,'全唐诗/poet.song.203000.json','["長江釀碧山滴藍，書堂枕北戶啟南。", "無人與言略爲二，邀月對影聊成三。", "澄清萬慮了無攄，魚獵百氏幾如貪。", "觀蘭玩石亦何好，平生嗜好有所耽。", "沉烟紛郁醒宿醉，松風清越供幽談。", "反觀靜照默有契，森然衆理俱包涵。", "覊窮紛紛歎荼苦，真味往往如飴甘。", "客來問訊主人處，春風軒下榻睡酣。"]'),
('3991fa4d-382a-42cd-ad29-827cbee71dc4','春補揭榜史君爲詩以農諭學次韻爲謝','徐鹿卿','宋','宋诗','song-poetry','','[]','東郊前日勸農民，泮宮今日勸諸生。',240,'全唐诗/poet.song.203000.json','["東郊前日勸農民，泮宮今日勸諸生。", "勸農直欲使家給，勸士詎止隆鼎烹。", "新詩隨寓有規益，筆勢滾滾今長庚。", "芹藻生春鵠袍肅，聽說筆耕同鐵耕。", "情田鋤治付編簡，儒藻溉灌須陶泓。", "善根深培恐未固，惡念痛絕猶潛萌。", "因農諭學良切至，一理通貫昭然明。", "下民蚩蚩每難悟，不勸安得千倉盈。", "讀書爲士豈待勸，勸且弗勉真眩名。", "本然之天我固有，踐履須蹋實地行。", "要知爲仁在乎熟，本無內外無將迎。", "歲猶有歉道常富，士實爲重農爲輕。", "賢侯之文菽粟味，雖出遊戲皆真情。", "居窮勿但作魚蠹，官達還戒專蠅營。", "信能行此乃有獲，不負魯泮鳴鸞聲。"]'),
('496229e4-0614-4f54-87bf-1341662fdd1b','莫悲秋','戴昺','宋','宋诗','song-poetry','','[]','傷春非貞女，悲秋非烈士。',72,'全唐诗/poet.song.203000.json','["傷春非貞女，悲秋非烈士。", "時運自循環，我心如止水。", "剝固復之機，榮乃悴之始。", "未識天地妙，胡爲浪悲喜。", "鷃蓬或數仞，鵬海或萬里。", "大小何必齊，蒙莊未窮理。"]'),
('9a835102-67d0-44ea-bbad-aee07a2c1071','次黄叔粲茶隠倡酬之什','戴昺','宋','宋诗','song-poetry','','[]','美人隠於茶，性與茶不異。',144,'全唐诗/poet.song.203000.json','["美人隠於茶，性與茶不異。", "苦澀知餘甘，淡薄見真嗜。", "肯隨世俱昏，寧墮衆所棄。", "靈雨滋山腴，迅雷起龍睡。", "野草未敢花，春芽早呈瑞。", "鬭水須占一，焙火不落二。", "趣深同誰參，雋永時自試。", "葱薑勿容溷，瓜蘆定非類。", "標名寓玄思，微吟寫清致。", "成我君子交，從彼俗客恚。", "嚼芳憩泉石，包貢免郵置。", "遼遼玉川翁，千載共風味。"]'),
('1850d380-7538-4e22-aec6-db0529e3234e','夏肯甫曉山亭','戴昺','宋','宋诗','song-poetry','','[]','開櫺納晨光，隠几挹寒翠。',84,'全唐诗/poet.song.203000.json','["開櫺納晨光，隠几挹寒翠。", "以我胸中真，會彼景外意。", "孰因夜息存，孰使晝梏累。", "念慮方清明，體認貴切至。", "峨峨成九仞，進進基一簣。", "朂哉亭中人，涵養玉其粹。", "卷舒意何如，顔回坐忘地。"]'),
('157fdbce-3851-43fc-9c37-44f1c5100ed0','春日偕兄弟侍屏翁遊晉原分得外字因集句而成','戴昺','宋','宋诗','song-poetry','','[]','既雨晴亦佳，適與賞心會。',96,'全唐诗/poet.song.203000.json','["既雨晴亦佳，適與賞心會。", "初日照高林，幽泥化輕壒。", "步屧隨春風，始覺天宇大。", "牽懷到空山，逍遥白雲外。", "青松夾路生，童童狀車蓋。", "清川带華薄，陰壑生虛籟。", "性達形迹忘，傲然脫冠带。", "薄暮方來歸，月光摇淺瀨。"]'),
('8debc169-eb34-46a8-9c20-7801ba326373','唐李涉有山中五無可奈何詩戲用其體作秋日四章  其一','戴昺','宋','宋诗','song-poetry','','[]','無奈秋風何，怒號震林木。',36,'全唐诗/poet.song.203000.json','["無奈秋風何，怒號震林木。", "着我井上桐，一夜失寒綠。", "莫作摇落悲，妙理在觀復。"]'),
('6af02804-4721-4ceb-9b1f-cff123826675','唐李涉有山中五無可奈何詩戲用其體作秋日四章  其二','戴昺','宋','宋诗','song-poetry','','[]','無奈秋月何，鍊魄金氣精。',36,'全唐诗/poet.song.203000.json','["無奈秋月何，鍊魄金氣精。", "炯炯一輪滿，天地冰壺清。", "照我方寸景，表裏同光明。"]'),
('31fa1089-68ea-491c-b76e-a40c94ac32c6','唐李涉有山中五無可奈何詩戲用其體作秋日四章  其三','戴昺','宋','宋诗','song-poetry','','[]','無奈秋山何，萬疊淺深碧。',36,'全唐诗/poet.song.203000.json','["無奈秋山何，萬疊淺深碧。", "起來樓上看，朝爽浮几席。", "稜稜政自高，更養靜壽德。"]'),
('e3007a86-2e57-44ae-bd1e-c191024963f0','唐李涉有山中五無可奈何詩戲用其體作秋日四章  其四','戴昺','宋','宋诗','song-poetry','','[]','無奈秋水何，悠悠盪輕槳。',36,'全唐诗/poet.song.203000.json','["無奈秋水何，悠悠盪輕槳。", "上下天一碧，顛倒涵萬象。", "願從雙白鷗，生涯寄浩蕩。"]'),
('5f59cffd-62bb-454e-a9d7-5e6858d51428','青陽梅仙舒伯虞爲其尊人索靜閒軒詩','戴昺','宋','宋诗','song-poetry','','[]','人心元至虛，天下本無事。',96,'全唐诗/poet.song.203000.json','["人心元至虛，天下本無事。", "舉世役於形，擾擾誰暫置。", "先生自超俗，涵養老逾粹。", "妙契無名翁，深造靜閒味。", "壺中貯日月，胸次納天地。", "婆娑閲四序，物物見春意。", "林花高下紅，庭草淺深翠。", "一笑扶瘦筇，行吟散微醉。"]'),
('b04882b2-8f1f-443b-81ab-408628174d52','壬子立夏日同郡博士黄次夔游江祖太白釣臺因成古詩並呈偕行諸丈','戴昺','宋','宋诗','song-poetry','','[]','翰林天酒星，謫墮人間世。',204,'全唐诗/poet.song.203000.json','["翰林天酒星，謫墮人間世。", "豪氣眇乾坤，浪迹寄湖海。", "峨峨江祖山，片石峙西澨。", "醉狂御風來，踞坐高傲睨。", "一絲聊戲垂，意得在魚外。", "青天畫屏句，妙越無塵界。", "至今五百年，春虹絢晴彩。", "我來訪遺蹤，躡屐捫薜荔。", "錦苔剝冰霜，髣髴題字在。", "屬時春夏交，微雨弄輕霽。", "同遊俱嘉朋，笑語洽傾蓋。", "雲木團晝陰，松風奏天籟。", "勝踐心已愜，酣歌意彌快。", "欲招臺上魂，舉爵酹清泚。", "今昔自殊時，欣感諒一契。", "詩成寫蒼壁，存否非所計。", "長嘯下歸舟，驚湍送飛栧。"]'),
('90e67967-9fc1-4b9d-bb8d-31e8c3c9c2c3','梳頭自嘆','戴昺','宋','宋诗','song-poetry','','[]','短髮如冬霜，一朝白一朝。',132,'全唐诗/poet.song.203000.json','["短髮如冬霜，一朝白一朝。", "又如深秋柳，槁葉迎風凋。", "白者不再黑，白者不復牢。", "羲娥疾馳驥，乾坤虛懸瓢。", "人生寄其間，泛泛波上藻。", "百歲一大夢，倏忽已隔宵。", "胡不適所適，而乃隨滔滔。", "富貴撇眼電，榮華過耳飈。", "木散故得壽，龜靈徒取焦。", "甘拙自安吉，役智滋勞忉。", "所以柴桑人，不肯折此腰。"]'),
('d63c4fc6-496e-4e52-a2d2-fddfea13dffe','上立齋先生十首以有官居鼎鼐無宅起樓臺爲韻  其一','戴昺','宋','宋诗','song-poetry','','[]','形弱能使强，脈病能使壽。',48,'全唐诗/poet.song.203000.json','["形弱能使强，脈病能使壽。", "醫和肘後方，袖手若無有。", "綠野歸晉公，洛社閑迂叟。", "此意誰得知，可以久則久。"]'),
('7ac44d3b-7482-4737-b14c-a6b5052fa6bc','上立齋先生十首以有官居鼎鼐無宅起樓臺爲韻  其二','戴昺','宋','宋诗','song-poetry','','[]','羸牛指爲驥，鳴梟認爲鸞。',48,'全唐诗/poet.song.203000.json','["羸牛指爲驥，鳴梟認爲鸞。", "彼欲欺一世，自亂耳目官。", "吾直不能枉，吾方竟誰刓。", "何妨寄楚澤，餐菊紉秋蘭。"]'),
('d1aff3f6-73a8-4e3b-a686-b0f0131ad717','上立齋先生十首以有官居鼎鼐無宅起樓臺爲韻  其三','戴昺','宋','宋诗','song-poetry','','[]','蔚蔚空明山，古號仙人居。',48,'全唐诗/poet.song.203000.json','["蔚蔚空明山，古號仙人居。", "神秀發虹氣，瑞孕真璠璵。", "潔白外難染，堅剛中不枯。", "勿逐鼠璞價，韞匵姑藏諸。"]'),
('76031c5f-91f5-4eaa-9882-65b76d17a9dc','上立齋先生十首以有官居鼎鼐無宅起樓臺爲韻  其四','戴昺','宋','宋诗','song-poetry','','[]','支厦資寸莛，涉江寄孤艇。',48,'全唐诗/poet.song.203000.json','["支厦資寸莛，涉江寄孤艇。", "弗顧勝弗勝，乃諉幸不幸。", "舜華朝暮期，蒼松歲年迥。", "從渠寶康瓠，我自有岑鼎。"]'),
('c898a37b-be57-40fe-8ce9-95753e831d7b','上立齋先生十首以有官居鼎鼐無宅起樓臺爲韻  其五','戴昺','宋','宋诗','song-poetry','','[]','君子如真金，真金剛不改。',48,'全唐诗/poet.song.203000.json','["君子如真金，真金剛不改。", "小人如浮雲，瞬目多變態。", "隨世良獨難，殉道乃無悔。", "近日崔菊坡，堅卧辭鼎鼐。"]'),
('c4952c8e-f17f-44d5-a224-2036111188ef','上立齋先生十首以有官居鼎鼐無宅起樓臺爲韻  其六','戴昺','宋','宋诗','song-poetry','','[]','薰蕕不同性，涇渭不同趨。',48,'全唐诗/poet.song.203000.json','["薰蕕不同性，涇渭不同趨。", "由來區以別，那使强合汙。", "老聃守道德，韓非事刑誅。", "二人共一傳，能信千古無。"]'),
('480c75ac-1f13-496c-bf34-8be52d817e2c','上立齋先生十首以有官居鼎鼐無宅起樓臺爲韻  其七','戴昺','宋','宋诗','song-poetry','','[]','多金建華屋，一堂容百客。',48,'全唐诗/poet.song.203000.json','["多金建華屋，一堂容百客。", "立齋有廳事，不覺旋馬窄。", "僻於蕭相居，隘甚晏子宅。", "鬼神瞰高明，吉祥止虛白。"]'),
('e00d3e84-6025-44d1-8535-06b8c042a3de','上立齋先生十首以有官居鼎鼐無宅起樓臺爲韻  其八','戴昺','宋','宋诗','song-poetry','','[]','靈岩一片雲，曾爲作雨起。',48,'全唐诗/poet.song.203000.json','["靈岩一片雲，曾爲作雨起。", "風吹還故山，松筠澹相倚。", "秋高霜露寒，酒熱鱸魚美。", "少寬憂世懷，微醉有妙理。"]'),
('d985a7df-1e14-4655-89ed-edc9040ee37c','上立齋先生十首以有官居鼎鼐無宅起樓臺爲韻  其九','戴昺','宋','宋诗','song-poetry','','[]','否泰關世運，進退非人謀。',48,'全唐诗/poet.song.203000.json','["否泰關世運，進退非人謀。", "尼父雖皇皇，不爲無理留。", "用則巨川楫，舍則野渡舟。", "行藏兩付之，獨倚百尺樓。"]'),
('1678333f-fb07-42b4-825e-921ad65d7102','上立齋先生十首以有官居鼎鼐無宅起樓臺爲韻  其一○','戴昺','宋','宋诗','song-poetry','','[]','小草有遠志，埋沒同蒿萊。',48,'全唐诗/poet.song.203000.json','["小草有遠志，埋沒同蒿萊。", "風霜坐相欺，冉冉成枯荄。", "我公下白屋，意重黄金臺。", "儻借伯樂顧，未信終駑駘。"]'),
('738e54ff-71cf-40a8-9558-2bde24763189','雜言  其一','戴昺','宋','宋诗','song-poetry','','[]','衆芳以春榮，萬葉以秋肅。',48,'全唐诗/poet.song.203000.json','["衆芳以春榮，萬葉以秋肅。", "造物持其權，兒戲恣翻覆。", "亭亭山上松，蕭蕭澗邊竹。", "超然榮肅中，正色閲寒燠。"]'),
('831b8a0b-4f16-44d1-a72f-fae1d7442e6b','雜言  其二','戴昺','宋','宋诗','song-poetry','','[]','提壺勸我飲，布穀催我耕。',48,'全唐诗/poet.song.203000.json','["提壺勸我飲，布穀催我耕。", "我酒瓶已罄，我田草正生。", "荷鋤理荒穢，及時新雨晴。", "秋來刈吾秫，庶得兩遂情。"]'),
('038a8e19-5ada-4f8c-b766-4ec82b40f8a6','雜言  其三','戴昺','宋','宋诗','song-poetry','','[]','逸翮凌丹霄，潛鱗縱深壑。',48,'全唐诗/poet.song.203000.json','["逸翮凌丹霄，潛鱗縱深壑。", "天分安所適，翔泳同一樂。", "短吟五七字，薄酒三四酌。", "浩氣與春風，相從滿寥廓。"]'),
('29d08ed2-2a3c-4632-ae02-21d7bc7f7424','侍屏翁遊屏山分得水字','戴昺','宋','宋诗','song-poetry','','[]','携琴入空山，脩竹翠相倚。',48,'全唐诗/poet.song.203000.json','["携琴入空山，脩竹翠相倚。", "一曲千古心，泠泠寄流水。", "拂雲卧白石，冥搜契玄理。", "有時採薪人，歌聲隔林起。"]'),
('f241d267-0ef3-4989-a032-f5cf29a1d65c','秋日過屏山庵  其一','戴昺','宋','宋诗','song-poetry','','[]','凄切抱葉蟬，間關栖樹禽。',48,'全唐诗/poet.song.203000.json','["凄切抱葉蟬，間關栖樹禽。", "入山本避喧，復愛聆此音。", "微颸動夕爽，薄雲散秋陰。", "衆籟閴以靜，片月生東林。"]'),
('23f9649a-3f1f-4100-8075-546c95c427bf','秋日過屏山庵  其二','戴昺','宋','宋诗','song-poetry','','[]','山泉清且甘，漱之冷侵骨。',48,'全唐诗/poet.song.203000.json','["山泉清且甘，漱之冷侵骨。", "拂苔坐石上，松風更蕭瑟。", "悠悠行空雲，何心自出沒。", "六鑿忽玲瓏，吾計良未失。"]'),
('469d04ae-4ce3-4467-b6ad-4a00958f841c','孤桐行','戴昺','宋','宋诗','song-poetry','','[]','孤桐結根倚崖石，俯瞰清溪照虛碧。',96,'全唐诗/poet.song.203000.json','["孤桐結根倚崖石，俯瞰清溪照虛碧。", "枝葉扶疎朱夏寒，上有翔鸞舊栖迹。", "風霜冉冉歲月深，老柯半朽蒼皮蝕。", "其中素抱金玉聲，以暗投人人不識。", "人不識，多苦心，樵夫斤斧莫相尋。", "寧教枯死倒澗壑，不從爨下求知音。"]'),
('28878cdb-f5ae-4198-bbb3-4ae2ff9ce0f1','逐瘧鬼','戴昺','宋','宋诗','song-poetry','','[]','咄哉瘧鬼何冥愚，沉魄猶滯江流居。',301,'全唐诗/poet.song.203000.json','["咄哉瘧鬼何冥愚，沉魄猶滯江流居。", "孰云胄出高陽氏，而乃不肖如此歟。", "爲妖常闖秋令動，作威又竊炎官餘。", "今年恣睢逞暴虐，十戶九室聞嗟吁。", "人生一歲一寒暑，自有大瘧纏其軀。", "翻手爲凉覆手暖，笑爾禍福纔須臾。", "癡兒騃女或汝怖，那能嚇我烈丈夫。", "汝不記少陵詩句有神語，子璋髑髏血模糊。", "昌黎遣逐更多術，灌毒炷艾揮靈符。", "今來古往共憎疾，奈何長惡終不渝。", "胡不學鮫人細織冰綃製雲裾，胡不從湘君緩移桂櫂搴芙蕖。", "乃甘卑渫賈衆怨，厭禳唾駡無時無。", "爾來經旬瞰吾室，再三謝遣猶踟躕。", "吾詩吾酒既不廢，汝窮汝技將何如。", "大江秋色正瀟灑，明月皎皎風疎疎。", "便須悟悔速歸去，嘯儔呼侶相嬉娛。", "夜闌吟徹欲就睡，燈花照眼團如珠。", "夢回病思砉然散，颯颯風籟生庭梧。"]'),
('c66d35aa-6345-497f-a9f3-d9a9ac19c222','五禽言  其一','戴昺','宋','宋诗','song-poetry','','[]','提葫蘆，沽美酒，人世光陰春電走。',48,'全唐诗/poet.song.203000.json','["提葫蘆，沽美酒，人世光陰春電走。", "一日得醉一日閑，綠鬢幾曾俱白首。", "沽酒沽酒有酒沽，生前不飲真愚夫。"]'),
('8380b4b1-6d95-47b0-b023-92e574ea73b6','五禽言  其二','戴昺','宋','宋诗','song-poetry','','[]','不如歸去，不如歸去，千山萬水家鄉路。',50,'全唐诗/poet.song.203000.json','["不如歸去，不如歸去，千山萬水家鄉路。", "今年又負故園花，來歲花開定歸否。", "歸去歸去須早歸，近日江湖非舊時。"]'),
('6f626fcb-cf08-4b89-b633-e13592752146','五禽言  其三','戴昺','宋','宋诗','song-poetry','','[]','泥滑滑，泥滑滑，客路迢迢雨不歇。',51,'全唐诗/poet.song.203000.json','["泥滑滑，泥滑滑，客路迢迢雨不歇。", "我僕十步九步蹶，我馬{馬鼠}𩥑如跛鼈。", "泥滑泥滑君莫愁，秧爛麥損尤堪憂。"]'),
('94b8ba36-1b3c-4e41-b55a-8d2100b7577a','五禽言  其四','戴昺','宋','宋诗','song-poetry','','[]','脫却破袴，脫却破袴，蠶熟繅成霜雪縷。',50,'全唐诗/poet.song.203000.json','["脫却破袴，脫却破袴，蠶熟繅成霜雪縷。", "小姑織絹未落機，縣家火急催官賦。", "輸了官賦無零落，破袴破袴還更着。"]'),
('d6953c58-38a4-4164-b767-d1027a49b2a7','五禽言  其五','戴昺','宋','宋诗','song-poetry','','[]','麥熟鍛磨，麥熟鍛磨，村南村北聲相和。',50,'全唐诗/poet.song.203000.json','["麥熟鍛磨，麥熟鍛磨，村南村北聲相和。", "大男小女總欣欣，煮餠蒸糜任渠做。", "鍛磨鍛磨莫等閒，去年糠粃無得餐。"]'),
('94e3e8b3-ee78-4988-920e-fb5ff5feba86','書初考','戴昺','宋','宋诗','song-poetry','','[]','得考雖多幸，無功祇自嫌。',48,'全唐诗/poet.song.203000.json','["得考雖多幸，無功祇自嫌。", "但求官速滿，不道老同添。", "卑拙翱蓬鷃，艱辛上竹鮎。", "黄花寒更好，三嗅憶陶潛。"]'),
('f36c1090-2f16-4a75-8011-0a13197539ef','辛亥九日被檄視澇遂爽同官飲菊之約夜宿荒驛風雨達曙','戴昺','宋','宋诗','song-poetry','','[]','孤負重陽菊，愁懷不肯寬。',48,'全唐诗/poet.song.203000.json','["孤負重陽菊，愁懷不肯寬。", "郵亭一夜雨，客枕五更寒。", "脚健從渠老，心低到處安。", "獨行誰可語，時把古詩看。"]'),
('503c5b0d-9ac3-4707-b7ce-aafbe6e0cdec','納凉即事','戴昺','宋','宋诗','song-poetry','','[]','炎蒸欣傍晚，掃地坐寬凉。',48,'全唐诗/poet.song.203000.json','["炎蒸欣傍晚，掃地坐寬凉。", "入竹風逾冷，生荷水亦香。", "蟻行緣食几，螢照落書牀。", "聽得農人語，今年稻穗長。"]'),
('c22bda82-6d56-4b61-bbf7-2dadb432a08d','侍屏翁領客遊雪山分得生字','戴昺','宋','宋诗','song-poetry','','[]','雪峰峰頂寺，來此定詩盟。',48,'全唐诗/poet.song.203000.json','["雪峰峰頂寺，來此定詩盟。", "山瀑分雲影，松風亂雨聲。", "眼明春樹綠，心醒曉鐘清。", "未好言歸去，塵中事又生。"]'),
('6996655d-bfd5-4513-9f12-792717bf5289','偕兄侍屏翁探梅屏山分得空字','戴昺','宋','宋诗','song-poetry','','[]','踏破登山屐，來尋傍水叢。',48,'全唐诗/poet.song.203000.json','["踏破登山屐，來尋傍水叢。", "眼明千樹底，春入數花中。", "格瘦詩難寫，香寒酒易空。", "狂歌歸秉燭，驚怪走兒童。"]'),
('9edaf813-d79e-4ef4-94c1-5bef4cdcddf9','豈潛弟平遠圖','戴昺','宋','宋诗','song-poetry','','[]','卜築占寬閒，修篁老樹間。',48,'全唐诗/poet.song.203000.json','["卜築占寬閒，修篁老樹間。", "八窗開宇宙，一室貯雲山。", "野曠行人少，天遥去鳥還。", "悠然會心處，妙語徹玄關。"]'),
('9476ac30-6613-4e15-b28b-7e42cf828eb9','謝趙山臺見訪','戴昺','宋','宋诗','song-poetry','','[]','寂寞海東頭，殷勤貴客舟。',48,'全唐诗/poet.song.203000.json','["寂寞海東頭，殷勤貴客舟。", "如何經歲約，祇作數宵留。", "清玩分行篋，高吟壓小樓。", "更須謀再會，同醉菊花秋。"]'),
('46e354f6-cbde-4d1f-8ad9-e4f1a32f9e08','臘前見蘭花','戴昺','宋','宋诗','song-poetry','','[]','蘭叢纔一幹，獨向臘前開。',48,'全唐诗/poet.song.203000.json','["蘭叢纔一幹，獨向臘前開。", "托蔭偏宜竹，先春不讓梅。", "韵從幽處見，香自靜中來。", "便欲紉芳佩，靈均喚不回。"]'),
('bedbe22a-c70d-4cd5-b68e-699cd8f7d976','安居','戴昺','宋','宋诗','song-poetry','','[]','安居元自好，春晝更遲遲。',48,'全唐诗/poet.song.203000.json','["安居元自好，春晝更遲遲。", "雪涌煎茶鼎，雲生浴硯池。", "栽荷填廢沼，移竹補疎籬。", "猶有閑光景，欹眠續舊詩。"]'),
('e1b5615d-1185-4ed0-8b6d-7d57583716a0','次韻屏翁詠梅','戴昺','宋','宋诗','song-poetry','','[]','芳信基花事，東君思亦奇。',48,'全唐诗/poet.song.203000.json','["芳信基花事，東君思亦奇。", "橫枝疎蓓蕾，半樹老丰姿。", "心共寒霜苦，香惟夜月知。", "最憐清夢覺，疎影竹窗時。"]'),
('f704c656-aa70-408b-b0e2-da47a33e487e','次韻屏翁觀梅','戴昺','宋','宋诗','song-poetry','','[]','曉寒籬落外，一見一番新。',48,'全唐诗/poet.song.203000.json','["曉寒籬落外，一見一番新。", "喚覺羣芳夢，先鍾萬古春。", "冷香宜醉寢，真色任烟隣。", "更喜連朝雪，飛花爲辟塵。"]'),
('cd60274e-39a5-4be5-9393-be30544eb6d8','項宜父涉趣園','戴昺','宋','宋诗','song-poetry','','[]','四面山迴合，中間百畝畦。',48,'全唐诗/poet.song.203000.json','["四面山迴合，中間百畝畦。", "入門惟見竹，遶屋半栽梅。", "果熟霜前樹，魚肥雨後溪。", "秋來饒景物，斟酌費詩材。"]'),
('38ea2b03-34c6-4f90-9672-4f33ecaff847','小酌會芳分得陰字','戴昺','宋','宋诗','song-poetry','','[]','暇日頻相顧，清風舊竹林。',48,'全唐诗/poet.song.203000.json','["暇日頻相顧，清風舊竹林。", "功名春後夢，吟咏老來心。", "世事隨流水，年芳付綠陰。", "悠然千古意，閑理斷紋琴。"]'),
('b6266c97-fcf7-4d71-8274-cb1c8743ea37','玉峰登眺得初字','戴昺','宋','宋诗','song-poetry','','[]','玉峰奇絕處，短策步崎嶇。',48,'全唐诗/poet.song.203000.json','["玉峰奇絕處，短策步崎嶇。", "海近潮聲壯，山空樹影疎。", "吟情危眺外，飲興薄寒初。", "數點新來雁，高飛不羨渠。"]'),
('9c260a29-4456-49dc-a6bb-8654c969092c','小樓扁山海圖鄭安道酒邊有詩因次韻','戴昺','宋','宋诗','song-poetry','','[]','等閒成小集，危眺豁幽情。',48,'全唐诗/poet.song.203000.json','["等閒成小集，危眺豁幽情。", "四面畫圖出，一襟天地清。", "晚雲山晻靄，夜月海空明。", "自有茲樓景，輸君第一評。"]'),
('a20e52c2-5185-45d3-b4b7-a1c9b45924b6','次韻屏翁新秋','戴昺','宋','宋诗','song-poetry','','[]','檢點新秋事，天公賜已豐。',48,'全唐诗/poet.song.203000.json','["檢點新秋事，天公賜已豐。", "秋床梧葉雨，曉袂竹林風。", "閲世心先老，傷時酒易中。", "誰將和戰議，細與問元戎。"]'),
('630f7c59-cd50-4bbd-98e0-f390646e32e5','己亥十月晦大雷雨','戴昺','宋','宋诗','song-poetry','','[]','舛運頻年見，憂時百慮灰。',48,'全唐诗/poet.song.203000.json','["舛運頻年見，憂時百慮灰。", "入冬常苦雨，昨夜又轟雷。", "土爛麥難種，蟲傷菜失栽。", "兒童不解事，喜報海棠開。"]'),
('6e0b8ae3-5b16-47b1-a685-a57064995af7','次屏翁冬日韻','戴昺','宋','宋诗','song-poetry','','[]','曉起衝寒出，霜明日未晞。',48,'全唐诗/poet.song.203000.json','["曉起衝寒出，霜明日未晞。", "麥豐來歲本，梅漏早春機。", "水涸魚深隠，蜜成蜂倦飛。", "靜中參物理，一一見精微。"]'),
('790b5819-bf00-4c4d-b160-fdd285347aa7','自武林還家道由剡中','戴昺','宋','宋诗','song-poetry','','[]','一筇雙不借，役役又東還。',48,'全唐诗/poet.song.203000.json','["一筇雙不借，役役又東還。", "野渡淺深水，夕陽高下山。", "光陰虛我老，造物靳人閒。", "高躅思吾祖，鳴琴獨閉關。"]'),
('51b9d6eb-c21a-4a0a-895f-7a056771b13a','次韻屏翁新元聚拜','戴昺','宋','宋诗','song-poetry','','[]','履端來聚拜，和氣洽昌辰。',48,'全唐诗/poet.song.203000.json','["履端來聚拜，和氣洽昌辰。", "蕃衍如今日，栽培豈一人。", "詩書延澤潤，忠厚續長春。", "相祝無多語，年新德又新。"]'),
('e05d3de4-ea39-47c3-af7a-087c486427c0','次韻君玉弟春事','戴昺','宋','宋诗','song-poetry','','[]','海棠紅未了，又近牡丹時。',48,'全唐诗/poet.song.203000.json','["海棠紅未了，又近牡丹時。", "送日多忙事，酬春欠好詩。", "暖風催麥早，晴晷轉花遲。", "不盡清遊興，重爲上巳期。"]'),
('ed274899-a804-47f6-9d6f-e5a517d6d920','次韻晚春二首  其一','戴昺','宋','宋诗','song-poetry','','[]','一襟塵欲滿，刮眼得新詩。',48,'全唐诗/poet.song.203000.json','["一襟塵欲滿，刮眼得新詩。", "風絮遺春恨，烟花隔歲期。", "筍抽蟲半蝕，櫻熟鳥先窺。", "光景渾如此，心閑即好時。"]'),
('1aa3b412-b790-4195-931d-f94f112add84','次韻晚春二首  其二','戴昺','宋','宋诗','song-poetry','','[]','田園深有趣，已分隠柴扃。',48,'全唐诗/poet.song.203000.json','["田園深有趣，已分隠柴扃。", "老去情多感，春來夢少靈。", "游絲捲晴日，飛絮入空庭。", "預識今年好，啼鵑枕上聽。"]'),
('dcba5719-70bb-4a3d-bb7c-e7f019a30f5f','春晚即事','戴昺','宋','宋诗','song-poetry','','[]','春郊農務急，野岸水痕高。',48,'全唐诗/poet.song.203000.json','["春郊農務急，野岸水痕高。", "蒲渚鳴姑惡，桑林囀伯勞。", "整欄扶芍藥，搴網護櫻桃。", "不改窮居樂，何妨見二毛。"]'),
('d9c68602-8563-4c29-9062-398d5458070d','次韻屏翁初夏會芳小集','戴昺','宋','宋诗','song-poetry','','[]','一觴還一詠，竟日醉難成。',48,'全唐诗/poet.song.203000.json','["一觴還一詠，竟日醉難成。", "坐石驚雲濕，臨池愛水平。", "密林宜午蔭，啼鳥尚春聲。", "更有櫻桃約，明朝且願晴。"]'),
('9fa94447-d49e-4a4a-9b55-7ae0185b5271','夏初郊行','戴昺','宋','宋诗','song-poetry','','[]','晴雨天難測，寒暄氣未齊。',48,'全唐诗/poet.song.203000.json','["晴雨天難測，寒暄氣未齊。", "連村多綠樹，終日囀黄鸝。", "田水衝塍斷，山雲着地低。", "偶隨農叟語，不覺過橋西。"]'),
('b8d4b0ff-26c7-4784-a20c-4358238bad3c','僻居','戴昺','宋','宋诗','song-poetry','','[]','地僻塵囂遠，身閑趣味深。',48,'全唐诗/poet.song.203000.json','["地僻塵囂遠，身閑趣味深。", "清池涵竹色，老樹带藤陰。", "引鶴隨閒步，招蟬伴醉吟。", "有時燃古鼎，隠几自觀心。"]'),
('e9dec79b-31f5-45c3-80e7-211a20b143ed','亦龍弟覆簣累石作亭其陰屏翁名曰野亭索詩謾賦二首  其一','戴昺','宋','宋诗','song-poetry','','[]','幽棲得真趣，隙地巧經營。',48,'全唐诗/poet.song.203000.json','["幽棲得真趣，隙地巧經營。", "花竹有和氣，林園無俗情。", "带經休樹影，抱甕俯池清。", "我亦甘肥遯，相從樂此生。"]'),
('c9eef8e6-6042-418f-b42c-cfb3c6b7749e','亦龍弟覆簣累石作亭其陰屏翁名曰野亭索詩謾賦二首  其二','戴昺','宋','宋诗','song-poetry','','[]','高懷抗塵外，林杪着三間。',48,'全唐诗/poet.song.203000.json','["高懷抗塵外，林杪着三間。", "綠遶村邊樹，青浮海上山。", "目窮天變化，心靜地寬閑。", "鷗鳥知人樂，忘機亦往還。"]'),
('b7023826-6977-4dbf-b087-62b3a262c598','秋晚','戴昺','宋','宋诗','song-poetry','','[]','西風澄曉氣，凝觀愜幽情。',48,'全唐诗/poet.song.203000.json','["西風澄曉氣，凝觀愜幽情。", "草潤蛩聲滑，松凉鶴夢清。", "吟懷依水靜，病思得秋輕。", "忽憶登高近，循籬看菊英。"]'),
('ff77f323-5d76-49e5-9cc4-736b079c0f45','屏翁領諸孫小集亦龍弟野亭君玉即席有詩次韻','戴昺','宋','宋诗','song-poetry','','[]','結屋新亭好，登臨雅興長。',48,'全唐诗/poet.song.203000.json','["結屋新亭好，登臨雅興長。", "心融八窗白，塵隔九衢黄。", "泛菊金英碎，嘗粳玉顆香。", "更期梅着蕋，來賞小春光。"]'),
('cd47970a-bb60-4e15-8c17-694242af978b','鄭安道終歲相聚臨別以詩見貽次韻爲謝','戴昺','宋','宋诗','song-poetry','','[]','解把詩言別，那無計可留。',48,'全唐诗/poet.song.203000.json','["解把詩言別，那無計可留。", "梅花兩心事，寒鴈五更愁。", "我亦高懸榻，君須獨卧樓。", "後回相憶處，莫返雪中舟。"]'),
('501a05a1-6db2-41ef-b284-40b289855909','夏曼卿作新樓扁曰瀟湘片景來求拙畫且索詩','戴昺','宋','宋诗','song-poetry','','[]','有此一樓足，悠然萬慮忘。',48,'全唐诗/poet.song.203000.json','["有此一樓足，悠然萬慮忘。", "拓開風月地，壓斷水雲鄉。", "四野留春色，千峰明夕陽。", "眼前無限景，何處認瀟湘。"]'),
('c11f78cf-6e42-4c7c-b46e-44c47ab41e0d','江濱晚霽','戴昺','宋','宋诗','song-poetry','','[]','十里平沙路，人行晚霽間。',48,'全唐诗/poet.song.203000.json','["十里平沙路，人行晚霽間。", "水光涵遠樹，雲影度空山。", "吹浪江豚怒，摩霄野鶴閑。", "漁翁醉吹笛，小艇泊前灣。"]'),
('cd87feb2-79a9-4319-89a9-c0bb493a6264','十日取野菊泛酒','戴昺','宋','宋诗','song-poetry','','[]','野徑菊仍好，村壚酒亦嘉。',48,'全唐诗/poet.song.203000.json','["野徑菊仍好，村壚酒亦嘉。", "未應今日蕋，便是背時花。", "心在家千里，身猶客九華。", "官程難久駐，風雨暮山斜。"]'),
('156f458b-1d4a-4eb1-8c15-aa2ee2a392e4','山家小憩即景效藥名體','戴昺','宋','宋诗','song-poetry','','[]','柴門通草徑，茅屋桂枝間。',48,'全唐诗/poet.song.203000.json','["柴門通草徑，茅屋桂枝間。", "修竹連翹木，高松續斷山。", "仰空青蔭密，掃石綠花斑。", "傍澗牽牛飲，白頭翁自閑。"]'),
('d50425af-ea1b-4d99-9377-9df31647b59d','從板橋買舟上青陽','戴昺','宋','宋诗','song-poetry','','[]','卸馬板橋西，扁舟逆上溪。',48,'全唐诗/poet.song.203000.json','["卸馬板橋西，扁舟逆上溪。", "水鎪岩骨斷，烟截樹頭齊。", "野鴨驚人起，村鷄上樹啼。", "老農頭雪白，猶自把鉏犁。"]'),
('142280de-7988-4cf5-9c65-38db127a9da6','池州','戴昺','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','一城方九里，宛在水中坻。',48,'全唐诗/poet.song.203000.json','["一城方九里，宛在水中坻。", "額揭顔公字，碑傳杜牧詩。", "昔年稱上郡，今日逼邊陲。", "莫望長江北，天寒風正悲。"]'),
('4554a594-b9c5-40c6-aeba-676ffaffa398','有永嘉薛君自號雲屋來池陽以詩見貽用韵答之','戴昺','宋','宋诗','song-poetry','','[]','清晨聞剝啄，喜得薛能詩。',48,'全唐诗/poet.song.203000.json','["清晨聞剝啄，喜得薛能詩。", "風月一囊錦，江湖兩鬢絲。", "寒城吹角夜，孤館擁衾時。", "誰會吟心苦，梅花是舊知。"]'),
('0bd3a5da-bfc7-4d78-bc20-5c6a04abcb0f','有方叔材用余和薛雲屋歌見貽次韻奉酬','戴昺','宋','宋诗','song-poetry','','[]','江湖前輩盡，何敢易言詩。',48,'全唐诗/poet.song.203000.json','["江湖前輩盡，何敢易言詩。", "鼠璞元非玉，蛛羅不是絲。", "池塘生草處，風雪跨馿時。", "此是真吟境，從來幾箇知。"]'),
('c43e2345-9c56-4f7d-b891-b8e36f6f8fcd','立春前五日得雪','戴昺','宋','宋诗','song-poetry','','[]','雪作春前瑞，銀城擁萬家。',48,'全唐诗/poet.song.203000.json','["雪作春前瑞，銀城擁萬家。", "太婆頭欲白，九子頂先華。", "壓麥嘉培本，封梅惜損花。", "家童解人意，燒鼎問烹茶。"]'),
('51b21388-5014-4ef0-811b-2a4e1dc2f605','小畦','戴昺','宋','宋诗','song-poetry','','[]','小畦尋丈許，鑿壁置柴扉。',48,'全唐诗/poet.song.203000.json','["小畦尋丈許，鑿壁置柴扉。", "雨後菜蟲死，秋來花蝶稀。", "插籬新種菊，抱甕已忘機。", "俗客忽相訪，妨人洗布衣。"]'),
('0232f261-e226-450b-85d0-865b4ed90d42','有感','戴昺','宋','宋诗','song-poetry','','[]','浩浩海風勁，滔滔河水渾。',48,'全唐诗/poet.song.203000.json','["浩浩海風勁，滔滔河水渾。", "古人皆去世，喬木自當門。", "族黨諸孫盛，吾宗一綫存。", "興衰知有數，心事與誰論。"]'),
('f2185cb1-d609-47af-b3e0-552b3297ddeb','金陵懷古','戴昺','宋','宋诗','song-poetry','','[]','尚聞深巷語烏衣，無復高堂彩鳳儀。',64,'全唐诗/poet.song.203000.json','["尚聞深巷語烏衣，無復高堂彩鳳儀。", "棟宇半欹元帝廟，香烟爭奉誌公祠。", "六朝興廢千年夢，獨客登臨萬古悲。", "莫上鍾山望淮北，西風禾黍更離離。"]'),
('2a982c7e-1f50-4473-ad25-00114f352326','幽棲','戴昺','宋','宋诗','song-poetry','','[]','幽棲頗喜隔囂喧，無客柴門盡日關。',64,'全唐诗/poet.song.203000.json','["幽棲頗喜隔囂喧，無客柴門盡日關。", "汲水灌花私雨露，臨池疊石幻溪山。", "四時有景常能好，一世無人放得閑。", "清坐小亭觀衆妙，數聲黄鳥綠陰間。"]'),
('97802eea-b1ef-4a46-8287-eb67b6c1a193','此生','戴昺','宋','宋诗','song-poetry','','[]','此生畢竟已蹉跎，有酒何妨醉且歌。',64,'全唐诗/poet.song.203000.json','["此生畢竟已蹉跎，有酒何妨醉且歌。", "人世盡緣愁得老，春花偏被雨相魔。", "草欺蘭瘦能香否，杏笑梅殘奈俗何。", "試上東樓看春景，海山無數列青螺。"]'),
('91f9339e-0f37-4ec3-ad3d-872d710b155d','自况','戴昺','宋','宋诗','song-poetry','','[]','多貲徒作守錢奴，伏臘無憂便有餘。',64,'全唐诗/poet.song.203000.json','["多貲徒作守錢奴，伏臘無憂便有餘。", "世路本夷休自險，人情太密反成疎。", "非圖報施方爲善，豈爲功名始讀書。", "門外良田堪種秫，自牽黄犢試犂鉏。"]'),
('55bc5e0a-c83a-4aa6-b030-8877d8d3a6f7','書房','戴昺','宋','宋诗','song-poetry','','[]','書房清曉焚香坐，轉覺幽棲趣味真。',64,'全唐诗/poet.song.203000.json','["書房清曉焚香坐，轉覺幽棲趣味真。", "怪石一根雲態度，早梅半樹雪精神。", "池魚自樂誰知我，林鳥相忘不避人。", "得喪由來天自定，莫將閑慮惱閑身。"]'),
('4ed91c19-1fd0-4b06-a46d-731feccfbfff','移古梅植於貯清之側已有生意喜而賦之','戴昺','宋','宋诗','song-poetry','','[]','剝盡皮毛真實在，幾年孤立小溪潯。',64,'全唐诗/poet.song.203000.json','["剝盡皮毛真實在，幾年孤立小溪潯。", "人來人去誰青眼，花落花開自苦心。", "不是野夫同臭味，難教君子出山林。", "巡簷日日窺生意，一朵先春直萬金。"]'),
('909e5bb5-4cdc-4135-b319-68ae55a2845a','再得古梅小而益怪首蒙屏翁品題因次韻','戴昺','宋','宋诗','song-poetry','','[]','愛渠怪怪復奇奇，冒雪遥憑健步移。',64,'全唐诗/poet.song.203000.json','["愛渠怪怪復奇奇，冒雪遥憑健步移。", "竹外池邊栽恰好，山巔水際夢多時。", "百年死質餘生意，一片孤槎带好枝。", "寄語花神勤守護，品題莫負老僊詩。"]'),
('287c4e19-43d9-42e5-aa20-fb61571a274e','初遊方巖山','戴昺','宋','宋诗','song-poetry','','[]','圖志舊嘗看紀載，杖藜今得徧經行。',64,'全唐诗/poet.song.203000.json','["圖志舊嘗看紀載，杖藜今得徧經行。", "漁翁化石幾年釣，仙客有田何世耕。", "千尺枯崖蛻龍骨，一簾飛瀑撼雷聲。", "相傳逸少曾來此，惜不鎸巖記姓名。"]'),
('43056884-3116-44bf-8bad-07fe6b78d425','觀敗棋者戲作','戴昺','宋','宋诗','song-poetry','','[]','看人出着笑人低，及至當枰却自迷。',64,'全唐诗/poet.song.203000.json','["看人出着笑人低，及至當枰却自迷。", "角上僅全輸了腹，東邊纔活喪於西。", "欲裝劫去多難補，待算征來恰又提。", "天下未應無妙手，勸君莫愛墨狻猊。"]'),
('af502338-f53e-4438-843f-4213763d3511','牡丹','戴昺','宋','宋诗','song-poetry','','[]','萬巧千奇費剪裁，瓊瑶錦繡簇成堆。',64,'全唐诗/poet.song.203000.json','["萬巧千奇費剪裁，瓊瑶錦繡簇成堆。", "世間妖女輪回魄，天上仙姬降謫胎。", "笑臉倚風嬌欲語，醉顔酣日困難擡。", "東君若使先春放，羞殺羣花不敢開。"]'),
('ebd4c651-975b-4b17-b6c5-9b1e6675cc53','喜有秋','戴昺','宋','宋诗','song-poetry','','[]','去年已作填溝計，誰料今年見有秋。',64,'全唐诗/poet.song.203000.json','["去年已作填溝計，誰料今年見有秋。", "天意乘除元自定，人生伏臘謾多憂。", "滿盆淅玉休論價，成斛量金不計籌。", "最是野夫懽喜處，春風百甕遶床頭。"]'),
('fb4d103d-8b36-472c-b90c-8c0f48ea4af7','次君玉弟聞新雁','戴昺','宋','宋诗','song-poetry','','[]','霜風颯颯荻花洲，避北趨南巧自謀。',64,'全唐诗/poet.song.203000.json','["霜風颯颯荻花洲，避北趨南巧自謀。", "僊翮飛殘千里月，寒聲催老一天秋。", "乍教騷客驚詩夢，莫爲征夫寄別愁。", "汝度塞垣應未久，新來烟燧已沉不。"]'),
('9fbbd6af-2cb4-4b47-977f-c9321be9a667','次韻東渠兄觀梅','戴昺','宋','宋诗','song-poetry','','[]','詩眼非梅不可遮，三葩五蕋便堪嘉。',64,'全唐诗/poet.song.203000.json','["詩眼非梅不可遮，三葩五蕋便堪嘉。", "瘦如飯顆逢工部，老似磻溪卧子牙。", "水影月香參衆妙，弟酬兄倡自成家。", "快篘新醖同清賞，莫待枝頭爛縵花。"]'),
('0304704f-3701-40c0-8710-6ffb763f5ce7','閑居幽事','戴昺','宋','宋诗','song-poetry','','[]','閒居幽事屬田園，何必山林始避喧。',64,'全唐诗/poet.song.203000.json','["閒居幽事屬田園，何必山林始避喧。", "足水早禾分母子，多年修竹見翁孫。", "欣然勝敗無心弈，兀爾醉醒隨意樽。", "昨夜一番雷雨過，綠波微漲曲池痕。"]'),
('e1781d74-61b5-4fc9-883a-b90ffe0786ff','甘窮','戴昺','宋','宋诗','song-poetry','','[]','自甘窮處更何疑，坎止流行信所之。',64,'全唐诗/poet.song.203000.json','["自甘窮處更何疑，坎止流行信所之。", "不學昌黎驅五鬼，肯隨子厚駡三尸。", "堂堂白髮欺人出，耿耿青燈獨己知。", "細嚼黄花香滿齒，清風千古一東籬。"]'),
('61aa9ab8-2a3f-49ba-b0d0-864529420078','送彭希聖姊夫赴三山民曹','戴昺','宋','宋诗','song-poetry','','[]','槐笏綠衫初作吏，要須立脚自廉勤。',64,'全唐诗/poet.song.203000.json','["槐笏綠衫初作吏，要須立脚自廉勤。", "閭閻疾苦宜加意，廒廥奇贏莫與聞。", "少啖荔枝防美疢，多栽茉莉挹清芬。", "公餘覽徧佳山水，倘有詩篇寄海雲。"]'),
('beae607b-6124-4df7-b1d7-4b8ef971d2ce','己亥九日屏翁約諸孫登高西嶼阻風舟行不前遂會於吾家山海圖之上酒邊翁有詩留題因次韻','戴昺','宋','宋诗','song-poetry','','[]','良辰樂事兩相關，喜我樓臺便往還。',64,'全唐诗/poet.song.203000.json','["良辰樂事兩相關，喜我樓臺便往還。", "不用移舟過西嶼，只消把酒對南山。", "風於破帽如相約，菊爲新篘欲笑顔。", "留作千年佳話處，詩翁醉墨照楣間。"]'),
('8d966610-d971-4631-aa38-5fdb1b5093f9','如京至西興阻風雨','戴昺','宋','宋诗','song-poetry','','[]','月將圓夜出鄉關，纔到西興月又殘。',64,'全唐诗/poet.song.203000.json','["月將圓夜出鄉關，纔到西興月又殘。", "老去問名先已懶，近來行路覺尤難。", "雲烟漠漠吳山暗，風雨瀟瀟浙水寒。", "識破人生真逆旅，此身何處不堪安。"]'),
('f6438dde-9467-427c-a8b7-2a2b895231d9','七夕感興二首  其一','戴昺','宋','宋诗','song-poetry','','[]','家家懽笑迓星期，我輩相邀只酒巵。',64,'全唐诗/poet.song.203000.json','["家家懽笑迓星期，我輩相邀只酒巵。", "矯俗何須標犢鼻，甘愚不解候蛛絲。", "新秋光彩月來處，半夜清凉風起時。", "一曲玉簫塵外意，此音除是鶴仙知。"]'),
('c570d014-505c-414d-9e58-8581af7435f1','七夕感興二首  其二','戴昺','宋','宋诗','song-poetry','','[]','相傳牛女起何時，無柰人間事轉癡。',64,'全唐诗/poet.song.203000.json','["相傳牛女起何時，無柰人間事轉癡。", "青鳥蟠桃方士信，金釵鈿合逆胡基。", "一杯記節圖成醉，萬感因秋却易悲。", "遺恨古今流不盡，銀潢耿耿接天池。"]'),
('77e0cc1a-7b75-481e-a2d2-68d791ee801f','抵池陽未入關泊于齊山數日因窮岩壑之勝','戴昺','宋','宋诗','song-poetry','','[]','瘦策相扶上翠微，眼驚奇怪足忘疲。',64,'全唐诗/poet.song.203000.json','["瘦策相扶上翠微，眼驚奇怪足忘疲。", "三十六洞猶昔者，四百餘年無牧之。", "漲水淼瀰春雨後，遠山重疊夕陽時。", "幾多江北江南恨，問着沙鷗總不知。"]'),
('16afa71c-6026-442e-a46b-4b79bbd1d7a8','次劉叔子總幹夜坐感秋韻','戴昺','宋','宋诗','song-poetry','','[]','秋風遠客歎飄零，滿鏡吳霜故故明。',64,'全唐诗/poet.song.203000.json','["秋風遠客歎飄零，滿鏡吳霜故故明。", "酒盞論心疎舊約，詩筒到眼快新評。", "短檠伴我夜深靜，長笛何人月下橫。", "步繞空庭吟未竟，隔林鸜鵒又傳更。"]'),
('114982ea-3c1a-4b36-a669-d1e878bd4458','代簡約諸同官探梅','戴昺','宋','宋诗','song-poetry','','[]','信是摶沙放手開，渴心空想細論杯。',64,'全唐诗/poet.song.203000.json','["信是摶沙放手開，渴心空想細論杯。", "等閒不見便逾月，如此相從能幾回。", "舊雨已孤重九菊，新詩宜探小春梅。", "騎馿索句真顔面，要向清溪洗出來。"]'),
('ed898121-c75d-422c-9382-7ab080540846','燒燈夕宋明府自置酒見招席上復賦詩因次韻定詩盟併致別意','戴昺','宋','宋诗','song-poetry','','[]','苦用吟心續祖燈，得君印證愈分明。',64,'全唐诗/poet.song.203000.json','["苦用吟心續祖燈，得君印證愈分明。", "一聆此日鷄窗話，盡洗前時蚓竅聲。", "颺柳輕風寒忽暖，催花小雨濕還晴。", "眼前總是詩光景，可惜明朝又遠行。"]'),
('22794e70-41cb-4e0f-8d1e-b278f1171c68','秋暮出關即事','戴昺','宋','宋诗','song-poetry','','[]','俗塵汩汩負清遊，重出城來已暮秋。',64,'全唐诗/poet.song.203000.json','["俗塵汩汩負清遊，重出城來已暮秋。", "水洗柳根欹斷岸，霜摧蘆葉擁荒洲。", "鄉音不到愁來雁，野性無拘羨去鷗。", "可惜一堤明月好，隔關難作夜深留。"]'),
('22dc9e05-c56d-4884-bc53-cd165d692ee8','秋日獨倚東樓','戴昺','宋','宋诗','song-poetry','','[]','重陽過了秋逾爽，自豁樓窗眺晚西。',64,'全唐诗/poet.song.203000.json','["重陽過了秋逾爽，自豁樓窗眺晚西。", "野外倒涵天影動，海雲平壓雁行低。", "興來頻放深杯飲，吟到須還大字題。", "近喜書房添一寶，陶泓買得古端溪。"]'),
('915459ed-c013-4bce-b9a6-ed7f1717abcb','次韻屏翁壬寅九日再題小樓','戴昺','宋','宋诗','song-poetry','','[]','佳節相過共舉觴，爲萸菊醉亦何妨。',64,'全唐诗/poet.song.203000.json','["佳節相過共舉觴，爲萸菊醉亦何妨。", "須知我輩襟懷事，不是時人酒肉狂。", "落雁影邊寒水碧，歸鴉啼處夕陽黄。", "詩翁樽俎風流在，老氣橫吞年少場。"]'),
('bdf068b6-777e-4f45-b54f-261e67be70ff','初冬梅花偷放頗多','戴昺','宋','宋诗','song-poetry','','[]','清樽纔了黄花債，又被梅花惱殺人。',64,'全唐诗/poet.song.203000.json','["清樽纔了黄花債，又被梅花惱殺人。", "碎點南枝無數雪，探支東帝幾分春。", "精神全向疎中足，標格端於瘦處真。", "徹夜苦吟無好語，夢隨雙月步溪漘。"]'),
('dfefa3c8-8e63-4d32-8676-1f3735cc993d','石屏後集鋟梓敬呈屏翁','戴昺','宋','宋诗','song-poetry','','[]','新刊後藁又千首，近日江湖誰有之。',64,'全唐诗/poet.song.203000.json','["新刊後藁又千首，近日江湖誰有之。", "妙似豫章前集語，老於夔府後來詩。", "梅深歲月枝逾古，菊飽風霜色轉奇。", "要洗晚唐還大雅，願揚宗旨破羣癡。"]'),
('3c363415-96c8-4bf3-a8fa-d385db6143bd','四月節景','戴昺','宋','宋诗','song-poetry','','[]','茶歌纔了又田歌，節物真成一鳥過。',64,'全唐诗/poet.song.203000.json','["茶歌纔了又田歌，節物真成一鳥過。", "蒼竹招風凉意足，碧梧留雨夜聲多。", "瓜緣茅屋抽長蔓，藕過蔬畦出矮荷。", "最喜白鷗相狎久，對人自在浴清波。"]'),
('a472479e-8474-4324-8b26-ad7ec5272b61','次韻鄭安道懷君玉弟游東嘉','戴昺','宋','宋诗','song-poetry','','[]','好山好水東嘉郡，兩月清游樂可知。',64,'全唐诗/poet.song.203000.json','["好山好水東嘉郡，兩月清游樂可知。", "遠想池塘頻夢汝，還當風雨對眠誰。", "別時菊蕊方宜酒，幾日梅花已索詩。", "雁影參差霜正冷，寄言歸計莫遲遲。"]'),
('b371784d-fa07-46b3-b98f-12b04082d132','贈日者張異手','戴昺','宋','宋诗','song-poetry','','[]','漫浪江湖等泛萍，破囊惟有百中經。',64,'全唐诗/poet.song.203000.json','["漫浪江湖等泛萍，破囊惟有百中經。", "一吭辯處長三寸，兩手生來應七星。", "笑汝道途多坎壈，說人禍福太分明。", "我今已决爲農計，不解從君較五行。"]'),
('b5e8bf3e-8011-4ed7-9108-19fbb6af8156','代簡寄謝友人','戴昺','宋','宋诗','song-poetry','','[]','經年未復寄來書，索我形骸莫太疎。',64,'全唐诗/poet.song.203000.json','["經年未復寄來書，索我形骸莫太疎。", "鮑叔相知應似舊，嵇康習懶苦難除。", "白頭閲世梅花老，青眼看人柳色舒。", "春月正圓春水滑，何須雪夜扣吾廬。"]'),
('e58c1b0b-2b92-4c10-b920-d86b8f1d7bb3','春事','戴昺','宋','宋诗','song-poetry','','[]','春事關心常早起，愛看景物試憑欄。',64,'全唐诗/poet.song.203000.json','["春事關心常早起，愛看景物試憑欄。", "戲魚池面微添綠，啼鳥枝頭尚带寒。", "斬棘重樊新插柳，𣂏泉頻灌自栽蘭。", "年來賸有園林興，每恨廬邊地不寬。"]'),
('39a7e4a9-49e1-46e0-96f4-97d108ab5415','有妄論宋唐詩體者答之','戴昺','宋','宋诗','song-poetry','','[]','不用雕鎪嘔肺腸，辭能達意即文章。',64,'全唐诗/poet.song.203000.json','["不用雕鎪嘔肺腸，辭能達意即文章。", "性情元自無今古，格律何須辨宋唐。", "人道鳳簫諧律呂，誰知牛鐸有宮商。", "少陵甘作村夫子，不害光芒萬丈長。"]'),
('465a9ed5-e622-4e5a-99cd-9d8435a670cd','趙倅賦喜雪詩爲黄堂頌黄堂和韻傳示僚屬衆因續貂','戴昺','宋','宋诗','song-poetry','','[]','風衮瑶花撲面寒，沾泥點點鹿文斑。',64,'全唐诗/poet.song.203000.json','["風衮瑶花撲面寒，沾泥點點鹿文斑。", "要呈臘瑞鬭梅好，肯讓春容傍柳還。", "萬戶閙添沽酒市，兩山窮聳索詩肩。", "使君寬得憂民念，麥隴青青一望間。"]'),
('763a372f-c664-4c9d-9e13-ce922962b9cb','次韻黄次夔思家','戴昺','宋','宋诗','song-poetry','','[]','世態從渠炎更凉，蕙蘭元不爲人香。',64,'全唐诗/poet.song.203000.json','["世態從渠炎更凉，蕙蘭元不爲人香。", "時憑酒挹聖賢味，閑借茶搜文字腸。", "靴笏豈能拘野性，蓴鱸終是憶家鄉。", "小需歸作天台隠，長嘯松風卧石梁。"]'),
('8dd3e8f0-b55f-4dc2-86be-09ae35dec5e4','送陳竹屋提幹東歸','戴昺','宋','宋诗','song-poetry','','[]','生長由來接社枌，台山越水偶中分。',64,'全唐诗/poet.song.203000.json','["生長由來接社枌，台山越水偶中分。", "一朝傾蓋便知我，千里携家得傍君。", "風厚大鵬培怒翼，天寒征雁拆同羣。", "折梅相送齊山路，愁絕江東日暮雲。"]'),
('b2ea41a0-121e-4b78-881d-3c9a11702195','賞茶','戴昺','宋','宋诗','song-poetry','','[]','自汲香泉带落花，漫燒石鼎試新茶。',32,'全唐诗/poet.song.203000.json','["自汲香泉带落花，漫燒石鼎試新茶。", "綠陰天氣閑庭院，卧聽黄蜂報晚衙。"]'),
('d3d8f5fd-163b-49d3-8cbb-1b3d1e4331f7','夜過鑑湖','戴昺','宋','宋诗','song-poetry','','[]','推篷四望水連空，一片蒲帆正飽風。',32,'全唐诗/poet.song.203000.json','["推篷四望水連空，一片蒲帆正飽風。", "山際白雲雲際月，子規聲在白雲中。"]'),
('a48e3f3f-c6a7-440e-93e1-a9d6899ddee8','喜小兒學步','戴昺','宋','宋诗','song-poetry','','[]','對周尚有六十日，舉足已能三五移。',32,'全唐诗/poet.song.203000.json','["對周尚有六十日，舉足已能三五移。", "世路只今巇險甚，須教步步著平夷。"]'),
('b7069182-69ab-4c89-bee8-7e78dc3e4598','效宮詞體','戴昺','宋','宋诗','song-poetry','','[]','楊柳萬絲堆怨緒，丁香百結鎖愁腸。',32,'全唐诗/poet.song.203000.json','["楊柳萬絲堆怨緒，丁香百結鎖愁腸。", "小桃先得東皇寵，莫妬東風過海棠。"]'),
('0e3cbc6a-2d0a-4369-a3b0-3fbb34d8761d','讀陳元龍傳','戴昺','宋','宋诗','song-poetry','','[]','九州四海沸如湯，問舍求田策最良。',32,'全唐诗/poet.song.203000.json','["九州四海沸如湯，問舍求田策最良。", "豪氣到頭成底事，未容欺客卧高床。"]'),
('6809ee8a-ba5a-42a5-9951-80e7066e9c18','嚴子陵','戴昺','宋','宋诗','song-poetry','','[]','赤伏君王訪舊遊，富春男子只羊裘。',32,'全唐诗/poet.song.203000.json','["赤伏君王訪舊遊，富春男子只羊裘。", "一竿本爲逃名去，何意虛名上釣鈎。"]'),
('96d2a458-d93e-408f-949e-3a55485a085a','竹林避暑','戴昺','宋','宋诗','song-poetry','','[]','自抱桃笙過竹林，濃陰一片直千金。',32,'全唐诗/poet.song.203000.json','["自抱桃笙過竹林，濃陰一片直千金。", "清眠盡晚無人喚，時有風鳴石上琴。"]'),
('3204ad81-672f-4b6a-a4d8-af6bd18cb63d','夏晝小雨','戴昺','宋','宋诗','song-poetry','','[]','小牀蘄簟展琉璃，窗外新篁一尺圍。',32,'全唐诗/poet.song.203000.json','["小牀蘄簟展琉璃，窗外新篁一尺圍。", "正午雲橋疎雨過，冬青花上蜜蜂歸。"]'),
('9e893f74-561a-4a74-a609-ae8179228727','里中小漁舟被差防江有感而賦','戴昺','宋','宋诗','song-poetry','','[]','着身平地更多憂，一棹思爲泛宅謀。',32,'全唐诗/poet.song.203000.json','["着身平地更多憂，一棹思爲泛宅謀。", "昨夜西風邊報急，防江也要釣魚舟。"]'),
('b28dbd87-40f7-47c7-9071-16d373d327b9','天台道上早行','戴昺','宋','宋诗','song-poetry','','[]','箯輿軋軋過清溪，溪上梅花壓水低。',32,'全唐诗/poet.song.203000.json','["箯輿軋軋過清溪，溪上梅花壓水低。", "月影漸收天半曉，兩山相對竹雞啼。"]'),
