('878659dd-6bb1-469b-b209-73a6f957cd85','偈頌一百四十二首  其五','釋廣聞','宋','宋诗','song-poetry','','[]','思大一條脊梁硬似鐵，被草繩輕輕一絆絆倒，至今草窠裡頭出頭沒。',30,'全唐诗/poet.song.203000.json','["思大一條脊梁硬似鐵，被草繩輕輕一絆絆倒，至今草窠裡頭出頭沒。"]'),
('3a37099b-99bb-4f85-9da4-ca40946fe1c0','偈頌一百四十二首  其六','釋廣聞','宋','宋诗','song-poetry','','[]','釋迦不出世，秤尾無星。',38,'全唐诗/poet.song.203000.json','["釋迦不出世，秤尾無星。", "達磨不西來，尺頭有寸。", "峭巍巍處平坦垣，平坦坦處峭巍巍。"]'),
('525b5c75-22ef-4ea5-9fce-85373770851d','偈頌一百四十二首  其七','釋廣聞','宋','宋诗','song-poetry','','[]','楊岐眼裡睛，臨濟頂中髓。',30,'全唐诗/poet.song.203000.json','["楊岐眼裡睛，臨濟頂中髓。", "一不成，二不是。", "點著不來，白雲萬里。"]'),
('d6a0eef2-c91d-4bb5-a774-71f9e018b3ee','偈頌一百四十二首  其八','釋廣聞','宋','宋诗','song-poetry','','[]','森羅及萬象，一法之所印。',44,'全唐诗/poet.song.203000.json','["森羅及萬象，一法之所印。", "晝見日，夜見星。", "松本直，棘本曲，如何是一法。", "一冬二冬，叉手當胸。"]'),
('d7d8049b-d99a-4a6e-919f-0091292e6a13','偈頌一百四十二首  其九','釋廣聞','宋','宋诗','song-poetry','','[]','錯錯，六載草繩空自縛。',47,'全唐诗/poet.song.203000.json','["錯錯，六載草繩空自縛。", "了了，開得眼來天大曉。", "古今天地，古今日月，古今星辰。", "劍去久矣，切忌刻舟。"]'),
('2720845b-c5af-4809-a6ed-0a3f23a40ea0','偈頌一百四十二首  其一○','釋廣聞','宋','宋诗','song-poetry','','[]','馬腹馿胎輥過來，通身滿面是塵埃，謾將香水年年洗。',41,'全唐诗/poet.song.203000.json','["馬腹馿胎輥過來，通身滿面是塵埃，謾將香水年年洗。", "有人續得末後句，許你親見釋迦老子。"]'),
('871f846e-27e9-4356-b382-bbb58818f86c','偈頌一百四十二首  其一一','釋廣聞','宋','宋诗','song-poetry','','[]','大無外，小無內。',40,'全唐诗/poet.song.203000.json','["大無外，小無內。", "南來北來，東倒西擂。", "不著佛求，不著法求。", "山中九十日，雲外幾千年。"]'),
('1980a504-577e-402c-9ad5-007dd5cdd1f3','偈頌一百四十二首  其一二','釋廣聞','宋','宋诗','song-poetry','','[]','難難，幾何般。',38,'全唐诗/poet.song.203000.json','["難難，幾何般。", "易易，直下是。", "也不難，也不易。", "常憶江南二三月，鷓鴣啼在深花裡。"]'),
('bf8deae2-f62c-499d-8333-a4aa43f2124b','偈頌一百四十二首  其一三','釋廣聞','宋','宋诗','song-poetry','','[]','八月十五，月圓當戶。',36,'全唐诗/poet.song.203000.json','["八月十五，月圓當戶。", "撩起便行，掀翻露布。", "長空雲暗雨漫漫，一段光明無著處。"]'),
('301c7390-45c0-449b-a4af-af9a56a8fc10','偈頌一百四十二首  其一四','釋廣聞','宋','宋诗','song-poetry','','[]','捻聚也在我，放開也在我。',28,'全唐诗/poet.song.203000.json','["捻聚也在我，放開也在我。", "三九二十七，菩提涅槃，真如解脫。"]'),
('b4a02563-8c4d-478a-a9d4-740b725093a3','偈頌一百四十二首  其一五','釋廣聞','宋','宋诗','song-poetry','','[]','巢知風，穴知雨。',30,'全唐诗/poet.song.203000.json','["巢知風，穴知雨。", "衲僧未學先知，浄慈不敢相許。", "發機須是千鈞弩。"]'),
('5aea3f31-42b4-4cbf-9e80-4139d5c7aea4','偈頌一百四十二首  其一六','釋廣聞','宋','宋诗','song-poetry','','[]','說法不應機，總是非時語。',22,'全唐诗/poet.song.203000.json','["說法不應機，總是非時語。", "長至令辰，天清地寧。"]'),
('9f0e1e16-fd9e-43ca-8000-07bfbad119d4','偈頌一百四十二首  其一七','釋廣聞','宋','宋诗','song-poetry','','[]','說不到處，一句是一句。',44,'全唐诗/poet.song.203000.json','["說不到處，一句是一句。", "行不到處，一步是一步。", "行到說到，一狀領過。", "缺齒老臊胡，嵩山破竈墮。"]'),
('add3d8ba-aa79-458c-b70d-4627bfcc4627','偈頌一百四十二首  其一八','釋廣聞','宋','宋诗','song-poetry','','[]','若喚作拄杖子，埋沒己靈。',24,'全唐诗/poet.song.203000.json','["若喚作拄杖子，埋沒己靈。", "不喚作拄杖子，辜負先聖。"]'),
('20474418-5ef8-493a-b3e7-be3aed2bbf5a','偈頌一百四十二首  其一九','釋廣聞','宋','宋诗','song-poetry','','[]','元正新改旦，舉則舊公案。',24,'全唐诗/poet.song.203000.json','["元正新改旦，舉則舊公案。", "料掉沒交涉，閏年春色晚。"]'),
('ba7260bc-15d8-4a58-8ac1-2cf447730775','偈頌一百四十二首  其二○','釋廣聞','宋','宋诗','song-poetry','','[]','欲見太平，須撥亂乾坤。',42,'全唐诗/poet.song.203000.json','["欲見太平，須撥亂乾坤。", "欲求知己，須掀翻海嶽。", "浄慈沒者閑工夫，端坐受供養，施主長安樂。"]'),
('cc71b4d8-610c-4179-bec0-18118a93564e','偈頌一百四十二首  其二一','釋廣聞','宋','宋诗','song-poetry','','[]','大盡小盡，三年一閏。',38,'全唐诗/poet.song.203000.json','["大盡小盡，三年一閏。", "全提半提，眼上安眉。", "有誵訛，沒巴鼻。", "放過一著，落在第二。"]'),
('4bd71e2d-1c57-4efd-9f4c-1bc4121d5994','偈頌一百四十二首  其二二','釋廣聞','宋','宋诗','song-poetry','','[]','馬祖陞堂，百丈卷席。',20,'全唐诗/poet.song.203000.json','["馬祖陞堂，百丈卷席。", "浄慈看來，寸不如尺。"]'),
('5c6f6f7c-3cb1-47fb-b7a9-754133a80c96','偈頌一百四十二首  其二三','釋廣聞','宋','宋诗','song-poetry','','[]','群陰剝盡，一陽來復。',26,'全唐诗/poet.song.203000.json','["群陰剝盡，一陽來復。", "拄杖子隨鄉入俗，六六不成三十六。"]'),
('79a1aea4-507e-4a19-82eb-d3f0efe693b4','偈頌一百四十二首  其二四','釋廣聞','宋','宋诗','song-poetry','','[]','昨夜送殘年，今朝賀新歲。',28,'全唐诗/poet.song.203000.json','["昨夜送殘年，今朝賀新歲。", "無量法門，百千三昧，又是從頭起。"]'),
('12d99e90-3f98-48d0-8cd9-6234c649df34','偈頌一百四十二首  其二五','釋廣聞','宋','宋诗','song-poetry','','[]','果滿菩提圓，花開世界起。',42,'全唐诗/poet.song.203000.json','["果滿菩提圓，花開世界起。", "爲復神通妙用，爲復法爾如然。", "將謂春歸無覓處，不知移向此中來。"]'),
('6c6c9ad1-f3cf-437b-9932-2ede75be59ba','偈頌一百四十二首  其二六','釋廣聞','宋','宋诗','song-poetry','','[]','纔有所重，便成窠臼。',40,'全唐诗/poet.song.203000.json','["纔有所重，便成窠臼。", "山僧只管打開，諸人只管坐斷。", "暫時安在暗窗前，明日與君重計算。"]'),
('b60ea392-dc94-4cbb-810b-909c54a3b43a','偈頌一百四十二首  其二七','釋廣聞','宋','宋诗','song-poetry','','[]','新年佛法有，一舉四十九。',40,'全唐诗/poet.song.203000.json','["新年佛法有，一舉四十九。", "新年佛法無，東壁挂葫蘆。", "今日重關還巨闢，幾多春色滿江湖。"]'),
('4c873def-ce6f-4049-8f7f-1749574ae7db','偈頌一百四十二首  其二八','釋廣聞','宋','宋诗','song-poetry','','[]','四月八日生，二月半入滅。',34,'全唐诗/poet.song.203000.json','["四月八日生，二月半入滅。", "雖然生滅元空，正是全提時節，珊瑚枝枝撐著月。"]'),
('7102cbfe-9ef0-446a-9118-8c16d4d42dce','偈頌一百四十二首  其二九','釋廣聞','宋','宋诗','song-poetry','','[]','雲門行棒，不可放過。',30,'全唐诗/poet.song.203000.json','["雲門行棒，不可放過。", "香山禮拜，放過不可。", "從來獻佛，不在香多。"]'),
('b3d460ef-39fb-4568-aa9e-562f3b929fdf','偈頌一百四十二首  其三○','釋廣聞','宋','宋诗','song-poetry','','[]','叢林紀綱，衲僧巴鼻。',20,'全唐诗/poet.song.203000.json','["叢林紀綱，衲僧巴鼻。", "詞鋒若差，鄉關萬里。"]'),
('81c92784-e266-4fb5-83a7-ede6137cfae0','偈頌一百四十二首  其三一','釋廣聞','宋','宋诗','song-poetry','','[]','未舉步前踏著，未開口前道著。',29,'全唐诗/poet.song.203000.json','["未舉步前踏著，未開口前道著。", "道著踏著，四海浪平，百川潮落。"]'),
('8f8fb3d9-0a2f-443c-b622-f514fe366756','偈頌一百四十二首  其三二','釋廣聞','宋','宋诗','song-poetry','','[]','富貴却易，雪中斷却娘生臂。',41,'全唐诗/poet.song.203000.json','["富貴却易，雪中斷却娘生臂。", "貧窮却難，覓心無處更何安。", "難難，夜來風色緊，孤客已先寒。"]'),
('18b3d561-53c6-45ca-87ea-c626e80c6512','偈頌一百四十二首  其三三','釋廣聞','宋','宋诗','song-poetry','','[]','一法若有，山河大地平沈。',88,'全唐诗/poet.song.203000.json','["一法若有，山河大地平沈。", "萬法若無，森羅萬像顯煥。", "舊歲今宵去，去去實不去。", "新年明日來，來來實不來。", "一法萬法，新年舊年。", "大地全收，千差一舉。", "絕去來，沒回互。", "回時更相涉，不爾依位住。"]'),
('2f13e8d9-79cc-48a6-b1d0-ee56ae7e2166','偈頌一百四十二首  其三四','釋廣聞','宋','宋诗','song-poetry','','[]','雲從龍，風從虎，聖人作而萬物覩。',32,'全唐诗/poet.song.203000.json','["雲從龍，風從虎，聖人作而萬物覩。", "須彌槌，虛空鼓，而以音聲爲佛事。"]'),
('2422dc60-edda-4ff5-b283-2ab9ddee0abf','偈頌一百四十二首  其三五','釋廣聞','宋','宋诗','song-poetry','','[]','百燈千燈，從一燈起。',38,'全唐诗/poet.song.203000.json','["百燈千燈，從一燈起。", "有處動地放光，無處放光動地。", "問訊燈明如來，慣打者般行市。"]'),
('3ef1a997-aacc-48bc-b280-d92299798bbe','偈頌一百四十二首  其三六','釋廣聞','宋','宋诗','song-poetry','','[]','五日不陞堂，三八不入室。',24,'全唐诗/poet.song.203000.json','["五日不陞堂，三八不入室。", "供是衆人辦，飯是借米喫。"]'),
('be4b2c38-173b-4ca9-9810-eb3d84c8406f','偈頌一百四十二首  其三七','釋廣聞','宋','宋诗','song-poetry','','[]','炎炎普熱，紛紛下雪。',20,'全唐诗/poet.song.203000.json','["炎炎普熱，紛紛下雪。", "百丈耳聾，黄檗吐舌。"]'),
('3685f644-5dbc-48da-800b-5338c0f08197','偈頌一百四十二首  其三八','釋廣聞','宋','宋诗','song-poetry','','[]','新年頭，舊年尾。',37,'全唐诗/poet.song.203000.json','["新年頭，舊年尾。", "第一句下明宗旨，三世諸佛不知有。", "是第二句，貍奴白牯却知有。"]'),
('d3d47e54-1585-49ac-b6dd-569f0e4a65de','偈頌一百四十二首  其三九','釋廣聞','宋','宋诗','song-poetry','','[]','風瀟瀟，雨瀟瀟。',28,'全唐诗/poet.song.203000.json','["風瀟瀟，雨瀟瀟。", "黑漫漫，明皎皎。", "過去燈明佛，面皮厚多少。"]'),
('01bdb66e-dda0-4563-9ace-8b9a0e883cf0','偈頌一百四十二首  其四○','釋廣聞','宋','宋诗','song-poetry','','[]','向下轉去，誰不知有。',21,'全唐诗/poet.song.203000.json','["向下轉去，誰不知有。", "向上轉去，如十日並照。"]'),
('29e970ae-d242-4594-83f1-98336aa895cd','偈頌一百四十二首  其四一','釋廣聞','宋','宋诗','song-poetry','','[]','六祖不會，誰云卞璧無瑕纇。',44,'全唐诗/poet.song.203000.json','["六祖不會，誰云卞璧無瑕纇。", "達磨不識，生鐵蒺藜當面擲。", "碓搗磨磨，風吹日炙，無位真人汗滴滴。"]'),
('bf42c1d4-ca8b-4c30-b75c-995d9d571cea','偈頌一百四十二首  其四二','釋廣聞','宋','宋诗','song-poetry','','[]','唯一堅密身，一切塵中現。',38,'全唐诗/poet.song.203000.json','["唯一堅密身，一切塵中現。", "近見不如遠聞，千聞不如一見。", "西風一陣來，落葉兩三片。"]'),
('4d5fe705-9c9f-45d4-ab16-7b45cf868de1','偈頌一百四十二首  其四三','釋廣聞','宋','宋诗','song-poetry','','[]','青天白日，閙市人多。',38,'全唐诗/poet.song.203000.json','["青天白日，閙市人多。", "鳥道玄途，龍門客少。", "目前機，頂門竅，一語不來，三十年後。"]'),
('c6fbb197-bd9c-48e4-af30-d08ae666723c','偈頌一百四十二首  其四四','釋廣聞','宋','宋诗','song-poetry','','[]','用東山暗號，虎頭戴角出荒草。',44,'全唐诗/poet.song.203000.json','["用東山暗號，虎頭戴角出荒草。", "唱少林一曲，六六不成三十六。", "看不足，聽不足，斷絃須是鸞膠續。"]'),
('578e8d9c-f3e1-45fc-ac71-f91e09e4cba7','偈頌一百四十二首  其四五','釋廣聞','宋','宋诗','song-poetry','','[]','日南長至，第一義諦。',32,'全唐诗/poet.song.203000.json','["日南長至，第一義諦。", "未舉先行，討甚巴鼻。", "鮎魚上竹竿，一日一萬里。"]'),
('ab1259cf-8edb-456e-9254-744fe01082ec','偈頌一百四十二首  其四六','釋廣聞','宋','宋诗','song-poetry','','[]','十字街頭，大圓覺海。',34,'全唐诗/poet.song.203000.json','["十字街頭，大圓覺海。", "逐色隨聲，家風落頼。", "討甚西天樣子，一任東倒西擂。"]'),
('6e9f221b-6499-47e3-ba6f-cac4fd876721','偈頌一百四十二首  其四七','釋廣聞','宋','宋诗','song-poetry','','[]','九旬過半，見成公案。',44,'全唐诗/poet.song.203000.json','["九旬過半，見成公案。", "明眼衲僧，打疊不辦。", "萬壽棗子渾侖吞，打鼓普請諸人看。", "看看，睦州擔板。"]'),
('56b4bcd5-29db-4bd6-b220-9964282a4fdd','偈頌一百四十二首  其四八','釋廣聞','宋','宋诗','song-poetry','','[]','祖師不來，曹溪路上生深棘。',50,'全唐诗/poet.song.203000.json','["祖師不來，曹溪路上生深棘。", "善財別後，樓閣門前草自青。", "直下穿過髑髏，換却眼睛。", "欲入洪波裡，須是弄潮人。"]'),
('bed670de-8e3b-450f-bde9-fcf50e69072d','偈頌一百四十二首  其四九','釋廣聞','宋','宋诗','song-poetry','','[]','鐘聲纔動鼓聲催，看取如今是甚時。',32,'全唐诗/poet.song.203000.json','["鐘聲纔動鼓聲催，看取如今是甚時。", "閙浩浩中靜悄悄，須臾小立是便宜。"]'),
('d2270538-e1d8-49e5-9975-f4162b609a9e','偈頌一百四十二首  其五○','釋廣聞','宋','宋诗','song-poetry','','[]','善行無轍迹，善繫無繩縛。',47,'全唐诗/poet.song.203000.json','["善行無轍迹，善繫無繩縛。", "二大老突出本分鉗鎚，不勞餘刃。", "叢林後世，追風捕影。", "要見古人，遠之遠矣。"]'),
('8bf7a4a9-3800-451f-b926-2be5b785da39','偈頌一百四十二首  其五一','釋廣聞','宋','宋诗','song-poetry','','[]','識得一，萬事畢，上下四維無等匹。',63,'全唐诗/poet.song.203000.json','["識得一，萬事畢，上下四維無等匹。", "張公醉倒街頭，元是李公喫酒，置之莫問。", "拽占波國與新羅國鬭額，是何境界。", "舉頭天外看，誰是我般人。"]'),
('bd13761c-97ce-42df-b712-90d4c9e041d0','偈頌一百四十二首  其五二','釋廣聞','宋','宋诗','song-poetry','','[]','真正舉揚，人荒道絕。',44,'全唐诗/poet.song.203000.json','["真正舉揚，人荒道絕。", "隨家豐儉，尺短寸長。", "衲僧門下有價數，沒商量。", "一夜落花雨，滿城流水香。"]'),
('822d731e-36d0-451d-99af-690b63cf4001','偈頌一百四十二首  其五三','釋廣聞','宋','宋诗','song-poetry','','[]','盡山河大地，只作一句道却。',27,'全唐诗/poet.song.203000.json','["盡山河大地，只作一句道却。", "普使有情無情，同向句下明宗。"]'),
('c84fdcbe-6142-440f-a16f-9bfb4fd35ba0','偈頌一百四十二首  其五四','釋廣聞','宋','宋诗','song-poetry','','[]','從上以來，無不知有，因甚被渠一把把定。',33,'全唐诗/poet.song.203000.json','["從上以來，無不知有，因甚被渠一把把定。", "不把定，裂破重關，行摩竭令。"]'),
('cadb1631-e69c-4873-b381-b9a508fb7496','偈頌一百四十二首  其五五','釋廣聞','宋','宋诗','song-poetry','','[]','千聖頭邊，星移斗換。',22,'全唐诗/poet.song.203000.json','["千聖頭邊，星移斗換。", "八面絕遮攔，打鼓普請看。"]'),
('4c92cd8f-6e66-40a5-9718-43e4dab6b7ca','偈頌一百四十二首  其五六','釋廣聞','宋','宋诗','song-poetry','','[]','過去一年復一年，未來一日是一日。',30,'全唐诗/poet.song.203000.json','["過去一年復一年，未來一日是一日。", "拶到力盡神疲，依舊正好著力。"]'),
('6495e2b0-3242-4c43-b446-41e33d6886fe','偈頌一百四十二首  其五七','釋廣聞','宋','宋诗','song-poetry','','[]','默默，無上菩提從此得。',32,'全唐诗/poet.song.203000.json','["默默，無上菩提從此得。", "了了，金雞一拍扶桑曉。", "衲僧門下，二俱漏逗。"]'),
('328cd1fa-21ab-49e3-a4a9-02ff88acaae2','偈頌一百四十二首  其五八','釋廣聞','宋','宋诗','song-poetry','','[]','不用低頭，思量難得。',20,'全唐诗/poet.song.203000.json','["不用低頭，思量難得。", "物有定價，錢是足陌。"]'),
('f30e3468-425c-471c-abb0-8853a98fcf03','偈頌一百四十二首  其五九','釋廣聞','宋','宋诗','song-poetry','','[]','菊花開時是重陽，又言九日是重陽。',73,'全唐诗/poet.song.203000.json','["菊花開時是重陽，又言九日是重陽。", "西風無帽落，西風索索。", "南山何處是，南山蒼蒼。", "恁麽也得，不恁麽也得。", "仰面不見天，低頭不見地。", "誰知遠煙浪，別有好商量。"]'),
('d4c8796d-69b1-4ffe-a8db-ded8213c5a8c','偈頌一百四十二首  其六○','釋廣聞','宋','宋诗','song-poetry','','[]','適間從僧堂中來，人人如白衣拜相。',32,'全唐诗/poet.song.203000.json','["適間從僧堂中來，人人如白衣拜相。", "少間從法堂下去，箇箇如晝錦還鄉。"]'),
('39b6d355-edf2-4b30-90c0-67026ac5b2d5','偈頌一百四十二首  其六一','釋廣聞','宋','宋诗','song-poetry','','[]','天地與我同根，萬物與我一體。',42,'全唐诗/poet.song.203000.json','["天地與我同根，萬物與我一體。", "豎四橫三，橫三豎四。", "全無巴鼻，討甚巴鼻，陽氣發時無硬地。"]'),
('011b0521-dea1-4920-aed5-3d366b43c0cd','偈頌一百四十二首  其六二','釋廣聞','宋','宋诗','song-poetry','','[]','河清海晏，天平地成，佛手遮不得。',32,'全唐诗/poet.song.203000.json','["河清海晏，天平地成，佛手遮不得。", "鑿井而飲，耕田而食，帝力何有哉。"]'),
('787960a5-9d93-4b48-9660-51c635bd6c16','偈頌一百四十二首  其六三','釋廣聞','宋','宋诗','song-poetry','','[]','雪竇雪寒，雪山雪寒。',30,'全唐诗/poet.song.203000.json','["雪竇雪寒，雪山雪寒。", "悟與未悟時，大地鐵一團，不妨北斗面南看。"]'),
('1d1f4be8-cb4f-4ec3-9c8b-7be892aee2cc','偈頌一百四十二首  其六四','釋廣聞','宋','宋诗','song-poetry','','[]','含珠林上碧崔嵬，曾入仁皇夢裡來。',32,'全唐诗/poet.song.203000.json','["含珠林上碧崔嵬，曾入仁皇夢裡來。", "今日恩從九天下，無邊剎海走風雷。"]'),
('2a1fd499-b941-44a3-bdab-93ccceec32fb','偈頌一百四十二首  其六五','釋廣聞','宋','宋诗','song-poetry','','[]','達磨九年面壁，不敢正眼覷著。',45,'全唐诗/poet.song.203000.json','["達磨九年面壁，不敢正眼覷著。", "神光三拜而立，至竟何曾踏著。", "覷著踏著，彩石渡頭看，陳年斷貫索。"]'),
('4cda8910-449d-4fc9-892d-9691ec33f17b','偈頌一百四十二首  其六六','釋廣聞','宋','宋诗','song-poetry','','[]','說心說性，說玄說妙，雪竇者裡是小家惡口。',64,'全唐诗/poet.song.203000.json','["說心說性，說玄說妙，雪竇者裡是小家惡口。", "學佛學法，學禪學道，諸人分上是鶻突布衫。", "秦不收，漢不管。", "閒來石上從頭數，得到清平有幾人。"]'),
('ababa7f3-0edf-460b-9c57-ebc382aec68e','偈頌一百四十二首  其六七','釋廣聞','宋','宋诗','song-poetry','','[]','貞女不著嫁時衣，好兒不使分時財。',31,'全唐诗/poet.song.203000.json','["貞女不著嫁時衣，好兒不使分時財。", "只如一夏九十日，切忌坐在者裡。"]'),
('8105d68a-b1a1-4f18-822a-c6db94cc5395','偈頌一百四十二首  其六八','釋廣聞','宋','宋诗','song-poetry','','[]','一番兩番新雨過，前村後村年已熟。',32,'全唐诗/poet.song.203000.json','["一番兩番新雨過，前村後村年已熟。", "試問蒲團上打坐，何如催人打禾穀。"]'),
('e558ab03-f195-4088-ad28-b2e1418ba07a','偈頌一百四十二首  其六九','釋廣聞','宋','宋诗','song-poetry','','[]','難難，幾何般。',40,'全唐诗/poet.song.203000.json','["難難，幾何般。", "時節難，道路難。", "貧窮布施難，富貴學道難。", "難難，達磨不會，大難大難。"]'),
('be8a358d-9b6d-4f23-a150-1f084d7845cf','偈頌一百四十二首  其七○','釋廣聞','宋','宋诗','song-poetry','','[]','物理有代謝，時節不相饒。',26,'全唐诗/poet.song.203000.json','["物理有代謝，時節不相饒。", "西家君子道長，東家小人道消。"]'),
('eb74656e-3acc-4e86-869f-814e9596dd6a','偈頌一百四十二首  其七一','釋廣聞','宋','宋诗','song-poetry','','[]','了了了，家近扶桑最先照。',63,'全唐诗/poet.song.203000.json','["了了了，家近扶桑最先照。", "知知知，一雙紅杏換消梨。", "莫莫莫，金雞啄破瑠璃殻。", "住住住，鳳棲不在梧桐樹。", "過者四重關了，五里牌在郭門外。"]'),
('2e9353bb-e370-4fa7-b336-0ea8c91fc927','偈頌一百四十二首  其七二','釋廣聞','宋','宋诗','song-poetry','','[]','客從遠方來，遺我徑寸璧。',36,'全唐诗/poet.song.203000.json','["客從遠方來，遺我徑寸璧。", "中有四箇字，字字無人識。", "且道是甚麽字，天子萬年。"]'),
('68c5b827-d5cc-4418-b249-a69852c78678','偈頌一百四十二首  其七三','釋廣聞','宋','宋诗','song-poetry','','[]','放出焦尾大蟲，咬殺南山猛虎。',50,'全唐诗/poet.song.203000.json','["放出焦尾大蟲，咬殺南山猛虎。", "動地號悲風，白日無行路。", "笑中擺手出長安，拶得虛空筋骨露，流水落花攔不住。"]'),
('db1f6f6a-001b-41fb-9a89-b456aba300b1','偈頌一百四十二首  其七四','釋廣聞','宋','宋诗','song-poetry','','[]','天平地平，河滿井滿。',40,'全唐诗/poet.song.203000.json','["天平地平，河滿井滿。", "臨濟口門窄，德山棒頭短。", "鐵蒺藜，黄金彈。", "直下來也，急著眼看。"]'),
('807604c0-9cbc-4545-8975-37ea6846c144','偈頌一百四十二首  其七五','釋廣聞','宋','宋诗','song-poetry','','[]','二千年前舊公案，九十日夏過一半。',52,'全唐诗/poet.song.203000.json','["二千年前舊公案，九十日夏過一半。", "雪竇道得十成，猶虧一半。", "諸人全身擔荷，未搆一半。", "靈利漢不赴兩頭不住中間。"]'),
('56f48f00-5a71-4fea-b236-668b3949bd6f','偈頌一百四十二首  其七六','釋廣聞','宋','宋诗','song-poetry','','[]','咄咄咄，力□希。',28,'全唐诗/poet.song.203000.json','["咄咄咄，力□希。", "大慈知處，雪竇不知。", "雪竇知處，大慈不知。"]'),
('a7c1864b-389a-4a47-98f2-a16de1c3f6e3','偈頌一百四十二首  其七七','釋廣聞','宋','宋诗','song-poetry','','[]','極小同大，極大同小。',36,'全唐诗/poet.song.203000.json','["極小同大，極大同小。", "官路行人少，私酒醉人多。", "風前三三兩兩，不妨水雲自若。"]'),
('9e07583a-d188-4c98-9c49-ffaaeb4c82b6','偈頌一百四十二首  其七八','釋廣聞','宋','宋诗','song-poetry','','[]','飛雪亭前水，妙高聲頂雲。',24,'全唐诗/poet.song.203000.json','["飛雪亭前水，妙高聲頂雲。", "雲有出山勢，水無投澗聲。"]'),
('200c0962-4fbb-4867-aec5-a55a1b2b77fc','偈頌一百四十二首  其七九','釋廣聞','宋','宋诗','song-poetry','','[]','你若坐時我須立，我若立時你須坐。',28,'全唐诗/poet.song.203000.json','["你若坐時我須立，我若立時你須坐。", "黄面老瞿曇，透者些不過。"]'),
('e9c94786-045f-4bd2-8708-e8897cf2070a','偈頌一百四十二首  其八○','釋廣聞','宋','宋诗','song-poetry','','[]','用毗盧正印，揭仲尼日月。',24,'全唐诗/poet.song.203000.json','["用毗盧正印，揭仲尼日月。", "一字不著畫，八字無兩丿。"]'),
('757dde33-955e-47cb-af8f-17b305ae7f9f','偈頌一百四十二首  其八一','釋廣聞','宋','宋诗','song-poetry','','[]','善言言者，言所不能言。',32,'全唐诗/poet.song.203000.json','["善言言者，言所不能言。", "善迹迹者，迹所不能迹。", "明眼衲僧，撞牆撞壁。"]'),
('901cec2e-99f8-4f41-a03b-1ad57d83cae9','偈頌一百四十二首  其八二','釋廣聞','宋','宋诗','song-poetry','','[]','大機圓應，大用現前。',27,'全唐诗/poet.song.203000.json','["大機圓應，大用現前。", "斬新日月，特地乾坤，知恩方解報恩。"]'),
('463cee9c-92b9-413a-bb3b-b91d54a4dd3b','偈頌一百四十二首  其八三','釋廣聞','宋','宋诗','song-poetry','','[]','多子塔前，平分半座。',28,'全唐诗/poet.song.203000.json','["多子塔前，平分半座。", "險崖句裡，水泄不通，風從虎兮雲從龍。"]'),
('5a6a3b90-89b9-48f2-a33e-1a961fca96d9','偈頌一百四十二首  其八四','釋廣聞','宋','宋诗','song-poetry','','[]','五月五，天中節。',48,'全唐诗/poet.song.203000.json','["五月五，天中節。", "盡大地人，無不向門頭戶底呪土書符。", "育王門下，身心一如，身外無餘。", "四明山色開畫圖。"]'),
('dbfcbf54-2fc0-42c5-8ee2-25968a2cc80e','偈頌一百四十二首  其八五','釋廣聞','宋','宋诗','song-poetry','','[]','人間九月又九日，善財去後無消息。',54,'全唐诗/poet.song.203000.json','["人間九月又九日，善財去後無消息。", "何止門前草自青，黄花滿地成狼藉。", "六祖不會，達磨不識。", "大藏小藏，盡從者裡流出。"]'),
('f75b7d1e-7dae-4780-9a32-288f9c5aa319','偈頌一百四十二首  其八六','釋廣聞','宋','宋诗','song-poetry','','[]','入山還出山，鐵壁復鐵壁。',42,'全唐诗/poet.song.203000.json','["入山還出山，鐵壁復鐵壁。", "衲僧門下，不消一擊。", "黄面瞿曇，散宅亡家。", "盡大地人，眼橫鼻直。"]'),
('2853d47d-26c6-4135-9d79-507e4f4c5d1e','偈頌一百四十二首  其八七','釋廣聞','宋','宋诗','song-poetry','','[]','六殊勝地，無越此山極殊勝。',54,'全唐诗/poet.song.203000.json','["六殊勝地，無越此山極殊勝。", "八吉祥中，唯有今朝最吉祥。", "於殊勝中顯殊勝，於吉祥中顯吉祥。", "萬年千載壽，一瓣九天香。"]'),
('25168757-7141-4023-98b0-ea22d074e44f','偈頌一百四十二首  其八八','釋廣聞','宋','宋诗','song-poetry','','[]','控佛祖大機，廓人天正眼，便恁麽去。',50,'全唐诗/poet.song.203000.json','["控佛祖大機，廓人天正眼，便恁麽去。", "入得育王門，要見育王人，遠之又遠。", "試看海上明公秀，何似堂中首座簡。"]'),
('e8229836-464c-4dd1-996f-ff46588579d4','偈頌一百四十二首  其八九','釋廣聞','宋','宋诗','song-poetry','','[]','牛頭橫說豎說，不知有向上關棙。',48,'全唐诗/poet.song.203000.json','["牛頭橫說豎說，不知有向上關棙。", "興化在大覺棒下，見臨濟先師於黄檗處喫棒底道理。", "獅子咬人，韓獹遂塊。"]'),
('c2e8a316-a7be-443e-984d-7b879ebc3771','偈頌一百四十二首  其九○','釋廣聞','宋','宋诗','song-poetry','','[]','雪峰輥毬，祕魔擎杈。',46,'全唐诗/poet.song.203000.json','["雪峰輥毬，祕魔擎杈。", "德山行棒，臨濟下喝，諸大老何用許多氣力。", "山僧尋常只是因風吹火，今日失利。"]'),
('93cf7b59-7c35-4794-9acd-bcc4ee41429c','偈頌一百四十二首  其九一','釋廣聞','宋','宋诗','song-poetry','','[]','行羅漢慈，破劫賊故。',56,'全唐诗/poet.song.203000.json','["行羅漢慈，破劫賊故。", "行菩薩慈，安衆生故。", "行如來慈，續慧命故。", "行平等慈，又且如何。", "嶺雲海月俱耕徧，拽耙拕犁卒未休。"]'),
('18c6558c-ab87-4afa-9dc5-da3adc65dde7','偈頌一百四十二首  其九二','釋廣聞','宋','宋诗','song-poetry','','[]','達磨面壁，雲門念七。',20,'全唐诗/poet.song.203000.json','["達磨面壁，雲門念七。", "玉本無瑕，彫文喪德。"]'),
('8b1a83ed-7677-4a7d-88ae-54138d644ada','偈頌一百四十二首  其九三','釋廣聞','宋','宋诗','song-poetry','','[]','畫龍看頭，畫蛇看尾。',54,'全唐诗/poet.song.203000.json','["畫龍看頭，畫蛇看尾。", "雪山冷坐六年，此處無金二兩。", "少林面壁九年，俗人沽酒三升。", "向道莫行山下路，果然猿呌斷腸聲。"]'),
('e073597e-fcc1-402c-b843-902990b5e30b','偈頌一百四十二首  其九四','釋廣聞','宋','宋诗','song-poetry','','["\u897f\u6e56"]','南屏山高，西湖水急。',23,'全唐诗/poet.song.203000.json','["南屏山高，西湖水急。", "還聞偃溪水聲麽，從者裡入。"]'),
('be5a6a0c-9d38-4a5c-aa44-0b97665af630','偈頌一百四十二首  其九五','釋廣聞','宋','宋诗','song-poetry','','[]','坐斷天下人舌頭，諸佛不知。',36,'全唐诗/poet.song.203000.json','["坐斷天下人舌頭，諸佛不知。", "捩轉天下人鼻孔，達磨不識。", "人天儼臨，皇帝有勑。"]'),
('882eac1d-239b-404f-abdf-a93ed0381c5b','偈頌一百四十二首  其九六','釋廣聞','宋','宋诗','song-poetry','','[]','建立法幢，扶持法社。',36,'全唐诗/poet.song.203000.json','["建立法幢，扶持法社。", "左之右之，風流儒雅。", "全卷全舒珠走盤，正法眼藏增高價。"]'),
('98fed7e3-be67-493c-8d32-5bc589733d51','偈頌一百四十二首  其九七','釋廣聞','宋','宋诗','song-poetry','','[]','彩儀仙仗五雲間，只作先皇舊日看。',32,'全唐诗/poet.song.203000.json','["彩儀仙仗五雲間，只作先皇舊日看。", "莫道空餘弓劍在，威風凜凜逼人寒。"]'),
('887c30c3-9bc8-40da-b6c7-f8a4eb51f820','偈頌一百四十二首  其九八','釋廣聞','宋','宋诗','song-poetry','','[]','吾佛廣大華藏海，法隨法行隨建立。',224,'全唐诗/poet.song.203000.json','["吾佛廣大華藏海，法隨法行隨建立。", "此寶華王獅子座，上有寶蓋從天垂。", "古來寶積長者子，手持此蓋同供佛。", "佛以智慧威神力，一一寶蓋合爲一。", "南山去天尺五近，王城不異毗耶城。", "彼時心即此時心，以此莊嚴作佛事。", "綵幢寶旛雜金碧，間見層出生光輝。", "猶如微風吹萎花，而復更雨新好者。", "仰觀三千大千界，於此蓋中悉充徧。", "一一世界既亦爾，線蹊針孔無不然。", "豈止一佛與二佛，盡十方佛現其中。", "廣長舌相熾然說，萬法一法靡不周。", "皇上心與佛心通，皇上壽與南山齊。", "無負此恩與此蓋，臣心有如此山爾。"]'),
('76970c19-a8c9-4e73-a927-14424e845466','偈頌一百四十二首  其九九','釋廣聞','宋','宋诗','song-poetry','','[]','如來禪祖師意，一不成二不是。',45,'全唐诗/poet.song.203000.json','["如來禪祖師意，一不成二不是。", "直下拶得行，轉得身吐得氣。", "又何待鼇山店上，古佛廟前，方始瞥地。"]'),
('0e9a82c7-bf9d-420f-be41-0b34d7e48205','偈頌一百四十二首  其一○○','釋廣聞','宋','宋诗','song-poetry','','[]','十字街頭石幢子，無你遮護處。',61,'全唐诗/poet.song.203000.json','["十字街頭石幢子，無你遮護處。", "一聲江上侍郎來，無你回避處。", "衲僧家朝出暮入，脚前脚後也須子細。", "忽然築著磕著，浄慈拄杖別有分付。"]'),
('03855196-5e8d-4828-a014-3c2da37a8958','偈頌一百四十二首  其一○一','釋廣聞','宋','宋诗','song-poetry','','[]','六年冷坐，九年面壁。',20,'全唐诗/poet.song.203000.json','["六年冷坐，九年面壁。", "碓搗東南，磨推西北。"]'),
('9dd99c43-8325-4aae-b4dd-42c18f3375e6','偈頌一百四十二首  其一○二','釋廣聞','宋','宋诗','song-poetry','','[]','風不鳴條，雨不破塊。',32,'全唐诗/poet.song.203000.json','["風不鳴條，雨不破塊。", "塵塵剎剎全彰，總是大人境界。", "北極高照南山外。"]'),
('19953cac-bac6-46b1-93ed-e5fa7ee5f467','偈頌一百四十二首  其一○三','釋廣聞','宋','宋诗','song-poetry','','[]','稅闍黎用影身術，老曹山用縛虎機。',26,'全唐诗/poet.song.203000.json','["稅闍黎用影身術，老曹山用縛虎機。", "且道那裡是他喫酒處。"]'),
('ea95e550-4224-4014-97fe-173bbdc4f986','偈頌一百四十二首  其一○四','釋廣聞','宋','宋诗','song-poetry','','[]','人有南北，道無南北。',49,'全唐诗/poet.song.203000.json','["人有南北，道無南北。", "上中下座，虛空逼塞。", "其中有一人半人肯去，說甚開粥相待。", "南山別甑炊香，未爲分外。"]'),
('8d48a03a-b7c4-4981-9d13-a4742a52b2b1','偈頌一百四十二首  其一○五','釋廣聞','宋','宋诗','song-poetry','','[]','寫王公符，用商君令。',20,'全唐诗/poet.song.203000.json','["寫王公符，用商君令。", "師多鬼亂，藥多病甚。"]'),
('fa0ed5c9-c5b5-45fe-a80d-8ec0c03a0287','偈頌一百四十二首  其一○六','釋廣聞','宋','宋诗','song-poetry','','["\u897f\u6e56"]','閙市無人，龍門有客。',49,'全唐诗/poet.song.203000.json','["閙市無人，龍門有客。", "漆桶相揩，渾無軌則。", "一時輥入草窠中，盡西湖之西，北山之北。", "山上鯉魚，南山白額。"]'),
('eb10726c-4b3d-4a8b-93c3-f94064fabd5c','偈頌一百四十二首  其一○七','釋廣聞','宋','宋诗','song-poetry','','[]','一法若有，脫羅籠處萬象平沉。',56,'全唐诗/poet.song.203000.json','["一法若有，脫羅籠處萬象平沉。", "萬法若無，沒遮護時紅塵滿地。", "如孤雲行空，如寒月即水。", "擬從於此覓雲山，何啻白雲千萬里。"]'),
('fc812b30-e772-4638-85da-7c1be8116ad3','偈頌一百四十二首  其一○八','釋廣聞','宋','宋诗','song-poetry','','[]','水清月現，動隨影轉。',61,'全唐诗/poet.song.203000.json','["水清月現，動隨影轉。", "水清月不現，背手新羅箭。", "踏翻水碗便行，墮在解脫深坑。", "三大老，總似閉目中秋坐。", "只知第二月，如何是第一月。"]'),
('8055e691-cd55-4c7a-8475-02cfdc06178c','偈頌一百四十二首  其一○九','釋廣聞','宋','宋诗','song-poetry','','[]','相逢不拈出，猶是東山左邊底。',68,'全唐诗/poet.song.203000.json','["相逢不拈出，猶是東山左邊底。", "舉意便知有，又是方菴外邊事。", "南山快便難逢，聲東擊西。", "持方入圓，貴要諸人知有。", "一點成龍兩處全，何如兄弟添十字。"]'),
('a9b5f76f-5822-4172-95d9-67bf5f2eeabc','偈頌一百四十二首  其一一○','釋廣聞','宋','宋诗','song-poetry','','[]','九日已無黄栗糕，十日依然有黄菊。',48,'全唐诗/poet.song.203000.json','["九日已無黄栗糕，十日依然有黄菊。", "何須九日記重陽，黄花開時意自足。", "東籬若謂見南山，鷂子已過新羅國。"]'),
('63601270-7d2d-42ee-97ab-f0cede369212','偈頌一百四十二首  其一一一','釋廣聞','宋','宋诗','song-poetry','','[]','日南長至，吉無不利。',20,'全唐诗/poet.song.203000.json','["日南長至，吉無不利。", "凍破泥團，花開碓嘴。"]'),
('c526e3dc-3a8a-4e13-ab26-9cc69eb85550','偈頌一百四十二首  其一一二','釋廣聞','宋','宋诗','song-poetry','','[]','祖師意，百草頭。',34,'全唐诗/poet.song.203000.json','["祖師意，百草頭。", "衲僧眼，拄杖頭。", "得路塞路，看樓打樓，須知衆穴一毫收。"]'),
('0896534f-42db-4009-a3ad-6046f4e09c44','偈頌一百四十二首  其一一三','釋廣聞','宋','宋诗','song-poetry','','[]','大辯若訥，大巧若拙。',40,'全唐诗/poet.song.203000.json','["大辯若訥，大巧若拙。", "如說而行，如行而說。", "只如行說不到時如何，瀟灑谿山，一天風月。"]'),
('0b37e1e7-6a4b-4428-bd33-4c9cbb6a4008','偈頌一百四十二首  其一一四','釋廣聞','宋','宋诗','song-poetry','','[]','唱新豐曲，風清古格。',52,'全唐诗/poet.song.203000.json','["唱新豐曲，風清古格。", "聲前轉調入無生，恰應雲門臘月拍。", "無影樹下，古渡頭邊。", "要知東谷末後句子，須待洞水逆流。"]'),
('cccefeed-6fe5-4855-a969-c19b4fab69c1','偈頌一百四十二首  其一一五','釋廣聞','宋','宋诗','song-poetry','','[]','世事悠悠，不如山丘。',20,'全唐诗/poet.song.203000.json','["世事悠悠，不如山丘。", "卧藤蘿下，塊石枕頭。"]'),
('e3bd5f52-c90b-4ae8-a22e-91f58bfa0874','偈頌一百四十二首  其一一六','釋廣聞','宋','宋诗','song-poetry','','[]','忽地晴天霹靂聲，禹門三級浪滂澎。',32,'全唐诗/poet.song.203000.json','["忽地晴天霹靂聲，禹門三級浪滂澎。", "幾多頭角成龍去，鰕蟹徒勞努眼睛。"]'),
('62f5801e-00a0-4205-a385-56cf3b5833df','偈頌一百四十二首  其一一七','釋廣聞','宋','宋诗','song-poetry','','[]','一句語具三玄門，一玄門具三要路。',30,'全唐诗/poet.song.203000.json','["一句語具三玄門，一玄門具三要路。", "直下重重透徹，許你縱橫十字。"]'),
('0bc64d39-160f-4283-a278-b66ebe790e0a','偈頌一百四十二首  其一一八','釋廣聞','宋','宋诗','song-poetry','','[]','一升三合，拄杖頭邊。',60,'全唐诗/poet.song.203000.json','["一升三合，拄杖頭邊。", "萬水千山，草鞋跟底。", "未言先領，誰家竈裡無烟。", "撩起便行，是處井中有水。", "莫道空來又空去，許多途路不相辜。"]'),
('9fc9c32e-0a24-4dfb-9132-1d7d761c995a','偈頌一百四十二首  其一一九','釋廣聞','宋','宋诗','song-poetry','','[]','花添錦上幾重重，針劄將來不露鋒。',32,'全唐诗/poet.song.203000.json','["花添錦上幾重重，針劄將來不露鋒。", "佛手分明遮不得，蓋天蓋地顯吾宗。"]'),
('0e3f650b-d3b8-4549-8dbb-d6af3565c2f9','偈頌一百四十二首  其一二○','釋廣聞','宋','宋诗','song-poetry','','[]','朝看東南，暮看西北。',36,'全唐诗/poet.song.203000.json','["朝看東南，暮看西北。", "一見便見，一得永得。", "靈雲謾道見桃花，臨濟未是白拈賊。"]'),
('9b06e561-4def-43f7-9086-e702f40f4e4f','偈頌一百四十二首  其一二一','釋廣聞','宋','宋诗','song-poetry','','[]','祕魔擎杈，魯祖面壁。',30,'全唐诗/poet.song.203000.json','["祕魔擎杈，魯祖面壁。", "官路不行，拗曲作直。", "一日不作，一日不食。"]'),
('515b495a-8a4f-447c-a326-c03dcbb5a34c','偈頌一百四十二首  其一二二','釋廣聞','宋','宋诗','song-poetry','','[]','目前機，量外事。',32,'全唐诗/poet.song.203000.json','["目前機，量外事。", "巢知風，穴知雨。", "百鍊鋼，千鈞弩。", "擬不擬，箭後路。"]'),
('bdd8812f-173b-4aaf-b91a-aa73650c2b4f','偈頌一百四十二首  其一二三','釋廣聞','宋','宋诗','song-poetry','','[]','世界恁麽熱，今日何似昨日。',44,'全唐诗/poet.song.203000.json','["世界恁麽熱，今日何似昨日。", "庭柯一葉落，前秋不覺後秋。", "通方達士未舉先知，不是俊流徒勞啗啄。"]'),
('3813cab5-8054-4aba-90b5-e0976ab371b9','偈頌一百四十二首  其一二四','釋廣聞','宋','宋诗','song-poetry','','[]','撥開若耶谿上雲，高挂峨嵋峰頂月。',54,'全唐诗/poet.song.203000.json','["撥開若耶谿上雲，高挂峨嵋峰頂月。", "大用不存軌則，瞎人何止一城。", "無毫髮間，無前後際。", "只今吳越令行，惱亂春風未已。"]'),
('184c6d25-00e4-48fc-a01c-226e1be3a8e2','偈頌一百四十二首  其一二五','釋廣聞','宋','宋诗','song-poetry','','[]','有則水裡月，無則形名兆。',29,'全唐诗/poet.song.203000.json','["有則水裡月，無則形名兆。", "即此是達磨眼睛，亦謂之衲僧頂門竅。"]'),
('1da1e30b-2f47-49eb-a63d-327943388bc3','偈頌一百四十二首  其一二六','釋廣聞','宋','宋诗','song-poetry','','[]','東去西去，脚頭脚尾沒回互。',48,'全唐诗/poet.song.203000.json','["東去西去，脚頭脚尾沒回互。", "南來北來，鐵壁銀山盡豁開。", "擬即失，動即乖。", "試看楊岐跨馿，何似玄沙斫牌。"]'),
('08b861c1-2770-4c03-9870-57a3cc34b912','偈頌一百四十二首  其一二七','釋廣聞','宋','宋诗','song-poetry','','[]','吾佛舒廣長舌相，不即此座亦不離。',160,'全唐诗/poet.song.203000.json','["吾佛舒廣長舌相，不即此座亦不離。", "爾時寶積諸長者，持七寶蓋而獻佛。", "如菴道人道機熟，今亦即色以明心。", "攢花簇錦出新好，而以組綉作佛事。", "一一針孔一世界，一一花葉一如來。", "森羅萬象影重重，莫不一法之所印。", "此座非高亦非廣，此被非闊亦非狹。", "舒即大千悉彌滿，收入微塵不迫窄。", "譬如隨色摩尼珠，是被光明亦如是。", "晝夜常轉如是輪，須彌燈王爲作證。"]'),
('205d35ac-177b-4703-b454-dad7b5795475','偈頌一百四十二首  其一二八','釋廣聞','宋','宋诗','song-poetry','','[]','燃無盡燈，示無盡意。',26,'全唐诗/poet.song.203000.json','["燃無盡燈，示無盡意。", "藕絲竅裡逗須彌，蟭螟眼中放夜市。"]'),
('a47fd97b-0b57-4345-bfb4-8c486b659aaf','偈頌一百四十二首  其一二九','釋廣聞','宋','宋诗','song-poetry','','[]','一句絕離微，渾崙無縫罅。',57,'全唐诗/poet.song.203000.json','["一句絕離微，渾崙無縫罅。", "善財七日尋覓不得，趙州五年分疎不下。", "靈山今日，快便難逢，爲通一線。", "六月賣松風，人間恐無價。"]'),
('c582aab4-3916-496f-a3d7-19370ba7634f','偈頌一百四十二首  其一三○','釋廣聞','宋','宋诗','song-poetry','','[]','雲門以勢欺人，雪竇抑强扶弱。',26,'全唐诗/poet.song.203000.json','["雲門以勢欺人，雪竇抑强扶弱。", "撿點將來，總是外道見解。"]'),
('294aa52a-15ad-4607-b197-a1fbad3f6348','偈頌一百四十二首  其一三一','釋廣聞','宋','宋诗','song-poetry','','[]','靈山又見一夏，不說陳年舊話。',28,'全唐诗/poet.song.203000.json','["靈山又見一夏，不說陳年舊話。", "青州衫重七斤，廬陵米作麽價。"]'),
('ba37f855-cee9-4606-9b51-45e4c7246328','偈頌一百四十二首  其一三二','釋廣聞','宋','宋诗','song-poetry','','[]','海外同歸用亦同，靈山有此兩雲峰。',32,'全唐诗/poet.song.203000.json','["海外同歸用亦同，靈山有此兩雲峰。", "萬人叢裡高標上，只貴重論蓋代功。"]'),
('8af2ed6c-c518-49fb-956e-ec46fd712d96','偈頌一百四十二首  其一三三','釋廣聞','宋','宋诗','song-poetry','','[]','圓處圓還缺，缺處缺還圓。',57,'全唐诗/poet.song.203000.json','["圓處圓還缺，缺處缺還圓。", "人爭看今日，月只是常年。", "南泉拂袖便行，鼓山拂袖歸衆。", "說甚衲僧門下，直是重處偏墜，薄處先穿。"]'),
('d8d584ab-9a10-40d5-8fa4-479358d1433e','偈頌一百四十二首  其一三四','釋廣聞','宋','宋诗','song-poetry','','[]','一年復一年，一冬復一冬。',24,'全唐诗/poet.song.203000.json','["一年復一年，一冬復一冬。", "海水知天寒，枯桑知天風。"]'),
('47cd5d3f-56c7-4acf-8148-8f2511359db1','偈頌一百四十二首  其一三五','釋廣聞','宋','宋诗','song-poetry','','[]','智門蓮花，趙州庭柏。',20,'全唐诗/poet.song.203000.json','["智門蓮花，趙州庭柏。", "不用低頭，思量難得。"]'),
('a67e5a83-39bf-4ff5-a0bd-eb6e62cb360b','偈頌一百四十二首  其一三六','釋廣聞','宋','宋诗','song-poetry','','[]','吾本來茲土，傳法救迷情。',30,'全唐诗/poet.song.203000.json','["吾本來茲土，傳法救迷情。", "面皮厚多少，一花開五葉，結果自然成。"]'),
('fcb69aa1-b17b-4411-b78b-b9bd386ee27f','偈頌一百四十二首  其一三七','釋廣聞','宋','宋诗','song-poetry','','[]','文殊爲衆竭力，世尊滿口含霜。',30,'全唐诗/poet.song.203000.json','["文殊爲衆竭力，世尊滿口含霜。", "千言萬語無人會，又逐流鶑過短牆。"]'),
('0300b1d7-98ae-43fc-a6f2-5a658a58f0e5','偈頌一百四十二首  其一三八','釋廣聞','宋','宋诗','song-poetry','','[]','機輪活脫走珠盤，妙處都盧在筆端。',32,'全唐诗/poet.song.203000.json','["機輪活脫走珠盤，妙處都盧在筆端。", "豎起依然還放下，靈鋒寶劍倚天寒。"]'),
('594b1811-ed21-4a0f-9e89-db390ae2ea84','偈頌一百四十二首  其一三九','釋廣聞','宋','宋诗','song-poetry','','[]','四月十五，靈山直舉。',22,'全唐诗/poet.song.203000.json','["四月十五，靈山直舉。", "捻聚處放開，放開處捻聚。"]'),
('b4ddf42b-96a3-4d13-9003-a928f67fd858','偈頌一百四十二首  其一四○','釋廣聞','宋','宋诗','song-poetry','','[]','佛子住此地，踏著依前不相似。',56,'全唐诗/poet.song.203000.json','["佛子住此地，踏著依前不相似。", "即是佛受用，切忌喚鐘而作甕。", "經行及坐卧，常在於其中。", "鶴有九臯難翥翼，馬無千里謾追風。"]'),
('e231c858-4d36-4478-b307-d86d37af18a9','偈頌一百四十二首  其一四一','釋廣聞','宋','宋诗','song-poetry','','[]','天寒人寒，風動旛動。',32,'全唐诗/poet.song.203000.json','["天寒人寒，風動旛動。", "與麽與麽，大難大難。", "一二三四五，放待冷來看。"]'),
('e4b976d4-d325-4054-9de0-283c1b2bcd38','偈頌十八首  其一','釋廣聞','宋','宋诗','song-poetry','','[]','乘流而行，過徑即止，猶是時人升降處。',30,'全唐诗/poet.song.203000.json','["乘流而行，過徑即止，猶是時人升降處。", "只今脚後脚前，通汝活路。"]'),
('79a38f2c-fa65-4974-90ed-95fc65db04de','偈頌十八首  其二','釋廣聞','宋','宋诗','song-poetry','','[]','捻聚放開，放開捻聚。',20,'全唐诗/poet.song.203000.json','["捻聚放開，放開捻聚。", "黄面瞿曇，無回避處。"]'),
('aa45df41-585d-498b-ade2-1d55553abde2','偈頌十八首  其三','釋廣聞','宋','宋诗','song-poetry','','[]','一縷烟蓋天蓋地，一滴水爲雨爲霖，誰見龍王宮殿深。',24,'全唐诗/poet.song.203000.json','["一縷烟蓋天蓋地，一滴水爲雨爲霖，誰見龍王宮殿深。"]'),
('8a72c0ab-c5af-4e1c-b456-979f6e24f1ae','偈頌十八首  其四','釋廣聞','宋','宋诗','song-poetry','','[]','者裡是吾父翁券內事，縱橫殺活，妙在不傳。',28,'全唐诗/poet.song.203000.json','["者裡是吾父翁券內事，縱橫殺活，妙在不傳。", "趙州親見老南泉。"]'),
('51dd555a-8c14-49ab-8fe3-d7effa9445b5','偈頌十八首  其五','釋廣聞','宋','宋诗','song-poetry','','[]','挂域中日月，立方外乾坤。',40,'全唐诗/poet.song.203000.json','["挂域中日月，立方外乾坤。", "從至尊至貴中得來，向無欲無依中流出。", "雲行雨施，三草二木。"]'),
('f015f16e-b50d-4439-a107-85a81a0f1b61','偈頌十八首  其六','釋廣聞','宋','宋诗','song-poetry','','[]','法王法令，頭正尾正。',29,'全唐诗/poet.song.203000.json','["法王法令，頭正尾正。", "只如世尊便下座時如何，路入桃源深更深。"]'),
('744293bc-9a26-4ad4-8eb2-28441c6bc758','偈頌十八首  其七','釋廣聞','宋','宋诗','song-poetry','','[]','一有多種，二無兩般。',20,'全唐诗/poet.song.203000.json','["一有多種，二無兩般。", "花根本艷，虎體元斑。"]'),
('c981c7a5-f329-4b24-b31b-9c8a9ee2cc8f','偈頌十八首  其八','釋廣聞','宋','宋诗','song-poetry','','[]','天生有大福德人，與佛同時同現瑞。',96,'全唐诗/poet.song.203000.json','["天生有大福德人，與佛同時同現瑞。", "是知心與佛心同，母儀天下同化育。", "如春及物春無迹，如月印水月無痕。", "天人中來道機熟，應身摩耶顯慈力。", "與天同壽福元元，萬年密贊無爲治。", "山林演此無爲法，是亦名爲報恩者。"]'),
('f324718a-69ff-4310-9816-1a96efd8d35e','偈頌十八首  其九','釋廣聞','宋','宋诗','song-poetry','','[]','和氣祥光靄九垓，新陽端自日邊回。',32,'全唐诗/poet.song.203000.json','["和氣祥光靄九垓，新陽端自日邊回。", "龍峰高處君恩重，先放花從鐵樹開。"]'),
('ceeb9514-26d3-4b3c-8fcf-d620cf402039','偈頌十八首  其一○','釋廣聞','宋','宋诗','song-poetry','','[]','大小黄面瞿曇老，了了了時何曾了。',32,'全唐诗/poet.song.203000.json','["大小黄面瞿曇老，了了了時何曾了。", "因憶明星出現時，夜來霜重知多少。"]'),
('0320a6ef-6f55-4030-87ea-e38612e90153','偈頌十八首  其一一','釋廣聞','宋','宋诗','song-poetry','','[]','雪峰據令而行，者僧分疏不下。',31,'全唐诗/poet.song.203000.json','["雪峰據令而行，者僧分疏不下。", "雪竇不曾與人葛藤，徑山道得也得也。"]'),
('8eb0a9f5-b9d7-487d-9575-9c1848db934e','偈頌十八首  其一二','釋廣聞','宋','宋诗','song-poetry','','[]','德山但知草偃風行，不覺通身泥水。',46,'全唐诗/poet.song.203000.json','["德山但知草偃風行，不覺通身泥水。", "者僧只見谿回路轉，不知身在桃源。", "徑山與麽批判，一任諸方撿責。"]'),
('051877ec-c2b7-4512-b8f9-2a409d3f3424','偈頌十八首  其一三','釋廣聞','宋','宋诗','song-poetry','','[]','落頼家風，今日重舉。',20,'全唐诗/poet.song.203000.json','["落頼家風，今日重舉。", "草本多同，西天此土。"]'),
('d2fb4412-72ee-48cb-9d06-87803ea244b3','偈頌十八首  其一四','釋廣聞','宋','宋诗','song-poetry','','[]','分圓照燈，下炎天雪，活弄南山鼈鼻蛇。',52,'全唐诗/poet.song.203000.json','["分圓照燈，下炎天雪，活弄南山鼈鼻蛇。", "驗盡英靈，提得藕絲牽玉象，不存途轍。", "只麽橫身異類行，踏斷石橋成兩截。"]'),
('4f62e656-ada7-4327-8811-e18a6db10045','偈頌十八首  其一五','釋廣聞','宋','宋诗','song-poetry','','[]','看錮{酉喿}，著生鐵。',28,'全唐诗/poet.song.203000.json','["看錮{酉喿}，著生鐵。", "因甚雲門心肝五臟，被者僧一摟摟盡。"]'),
('867e1249-d4ae-4f77-b543-df51e3ac76ab','偈頌十八首  其一六','釋廣聞','宋','宋诗','song-poetry','','["\u897f\u6e56"]','人間八月二十五，洞山此日離查渡。',48,'全唐诗/poet.song.203000.json','["人間八月二十五，洞山此日離查渡。", "棒頭敲出玉麒麟，江西湖南便與麽。", "徑山閙裡颺碌磚，誰道今人不如古。"]'),
('34a0ebd3-b1ce-465b-bb0c-34e8d4081f87','偈頌十八首  其一七','釋廣聞','宋','宋诗','song-poetry','','[]','谿上烟波遠，壺中日月長。',24,'全唐诗/poet.song.203000.json','["谿上烟波遠，壺中日月長。", "誰知冷灰裏，九轉透瓶香。"]'),
('2a722b08-fcff-4a2c-a396-ff5e882a1661','偈頌十八首  其一八','釋廣聞','宋','宋诗','song-poetry','','[]','以蠟人爲驗，病翼棲蘆。',34,'全唐诗/poet.song.203000.json','["以蠟人爲驗，病翼棲蘆。", "以鐵彈子爲驗，困鱗止濼。", "徑山不然，一箭雙鵰落。"]'),
('28bcae65-80bc-445f-95e2-165cccaf2f88','種竹','釋廣聞','宋','宋诗','song-poetry','','[]','香嚴活葬在南陽，知是所知忘未忘。',32,'全唐诗/poet.song.203000.json','["香嚴活葬在南陽，知是所知忘未忘。", "猛虎不應餐伏肉，聽教風雨細商量。"]'),
('bb3e8337-7b17-44f7-95f6-d71be8fe2235','送僧歸蜀','釋廣聞','宋','宋诗','song-poetry','','[]','曾經巴峽聽啼猿，萬想千思舉不全。',32,'全唐诗/poet.song.203000.json','["曾經巴峽聽啼猿，萬想千思舉不全。", "一萬里風吹夢轉，月明人上錦江船。"]'),
('16507591-4c17-4f2b-8c24-14037f006af3','送昭書記歸徑山','釋廣聞','宋','宋诗','song-poetry','','[]','錯下凌霄恨不忘，百城烟水漫茫茫。',32,'全唐诗/poet.song.203000.json','["錯下凌霄恨不忘，百城烟水漫茫茫。", "思量六十蒿枝拂，鐵打心肝也斷腸。"]'),
('12ebbd72-a0a7-4ecf-b3b5-44e8ff8989be','看潮','釋廣聞','宋','宋诗','song-poetry','','[]','怒雷聲撼海門秋，知是幾家人上樓。',32,'全唐诗/poet.song.203000.json','["怒雷聲撼海門秋，知是幾家人上樓。", "眼眼盡隨波浪轉，全潮端的屬誰收。"]'),
('53f32af6-2cd6-47cf-8c77-dd66d04129fb','褙語錄','釋廣聞','宋','宋诗','song-poetry','','[]','路不賷糧笑復歌，三更月下入無何。',32,'全唐诗/poet.song.203000.json','["路不賷糧笑復歌，三更月下入無何。", "太平誰整閑戈甲，王庫初無如是刀。"]'),
('e1caef0f-ead6-49c9-8b29-da59d050c94b','送愚菴和尚赴資福','釋廣聞','宋','宋诗','song-poetry','','["\u897f\u6e56"]','十分消息在竿頭，片甲纖鱗未足收。',32,'全唐诗/poet.song.203000.json','["十分消息在竿頭，片甲纖鱗未足收。", "怪得一番浮子動，西湖明月上金鈎。"]'),
('43f4fb31-c4f6-4e2a-8185-79fe750d3915','古劍','釋廣聞','宋','宋诗','song-poetry','','[]','干戈罷却復何言，六國風清令不傳。',32,'全唐诗/poet.song.203000.json','["干戈罷却復何言，六國風清令不傳。", "猶有當時太平意，塵埋三尺髑髏前。"]'),
('15c98b2a-ff13-458d-b136-811559c2ad3b','花翁','釋廣聞','宋','宋诗','song-poetry','','[]','傳來五葉到渠儂，略露些兒便不同。',32,'全唐诗/poet.song.203000.json','["傳來五葉到渠儂，略露些兒便不同。", "自是普通年遠事，莫將一樣看春風。"]'),
('d031e074-e5ce-47e5-a82c-36f5467c142b','送祖上人歸蜀','釋廣聞','宋','宋诗','song-poetry','','[]','只因月下甕吞蛇，贏得南來兩眼花。',32,'全唐诗/poet.song.203000.json','["只因月下甕吞蛇，贏得南來兩眼花。", "換手槌胸應有日，知他死款屬誰家。"]'),
('ff126d16-aa12-49a5-8f1d-a90107f09cae','送布袋像與妙峰和尚','釋廣聞','宋','宋诗','song-poetry','','[]','百千諸佛豎降旗，大法猶懸一縷絲。',32,'全唐诗/poet.song.203000.json','["百千諸佛豎降旗，大法猶懸一縷絲。", "問訊率陀老慈氏，只是恰是下生時。"]'),
('fefb2328-829b-46b1-ae79-4d80353a665e','放牛','釋廣聞','宋','宋诗','song-poetry','','[]','嗚咿聲斷笛橫時，滿目春風不自知。',32,'全唐诗/poet.song.203000.json','["嗚咿聲斷笛橫時，滿目春風不自知。", "脚後脚前者些子，入渠群隊聽渠疑。"]'),
('dcd4702d-9a96-4d58-8cbc-f7d6596d7054','拜大梅常禪師塔','釋廣聞','宋','宋诗','song-poetry','','[]','聲前借路謾經過，望却梅林自倒戈。',32,'全唐诗/poet.song.203000.json','["聲前借路謾經過，望却梅林自倒戈。", "八十四人屙漉漉，阿師猶更带誵訛。"]'),
('aeec4932-3711-472c-b50a-534506a97817','上安晚鄭丞相爲免墳地','釋廣聞','宋','宋诗','song-poetry','','[]','黄檗山中話裴相，獨龍岡上憶舒王。',32,'全唐诗/poet.song.203000.json','["黄檗山中話裴相，獨龍岡上憶舒王。", "相公留得谿邊寺，千古佳名在鄭鄉。"]'),
('07c80cce-8749-4b2d-9408-4112529a56a8','送僧歸蜀','釋廣聞','宋','宋诗','song-poetry','','[]','脫得南方馿馬群，相逢無法可呈君。',32,'全唐诗/poet.song.203000.json','["脫得南方馿馬群，相逢無法可呈君。", "看儂百衲袈裟上，半是吳雲半楚雲。"]'),
('10c184d5-d654-481d-90d8-1c4fbf0c6663','贈蜀相士蓑衣道人','釋廣聞','宋','宋诗','song-poetry','','[]','夢入東南萬里餘，閲人多處定何如。',32,'全唐诗/poet.song.203000.json','["夢入東南萬里餘，閲人多處定何如。", "綠蓑又裹春風去，未必黄金換得渠。"]'),
('065c7a79-0cc9-4b9c-81cb-20005ee07ff7','送蘭與樗寮張寺丞','釋廣聞','宋','宋诗','song-poetry','','[]','綠葉叢叢間紫莖，芳心細細爲誰傾。',32,'全唐诗/poet.song.203000.json','["綠葉叢叢間紫莖，芳心細細爲誰傾。", "不如去入芝蘭室，湊得仙家一段清。"]'),
('3dca430b-b2b2-46c8-bdcc-8ecc921528c2','無夢','釋廣聞','宋','宋诗','song-poetry','','[]','爲人徹困有誰知，眨得眼來話已遲。',32,'全唐诗/poet.song.203000.json','["爲人徹困有誰知，眨得眼來話已遲。", "滿地如今正閙在，聽渠寐語住何時。"]'),
('60e8b621-f893-417a-8aec-0aeeb2ad4576','宿天衣偶成','釋廣聞','宋','宋诗','song-poetry','','[]','過雁曾無影可留，不妨寒水向東流。',32,'全唐诗/poet.song.203000.json','["過雁曾無影可留，不妨寒水向東流。", "千峰一夜撐空立，舊事驚翻盡底休。"]'),
('cd2f606c-5aaa-446b-80e5-c4f19cc1fe5d','覺海諸善友整經','釋廣聞','宋','宋诗','song-poetry','','[]','好風晴日滿谿山，又到桃源盡處還。',32,'全唐诗/poet.song.203000.json','["好風晴日滿谿山，又到桃源盡處還。", "流水落花攔不住，幾多春色在人間。"]'),
('7eee2157-a747-40c4-84fa-21ce20fdb406','劍關','釋廣聞','宋','宋诗','song-poetry','','[]','吹毛不動定誵訛，徧地茫茫盡倒戈。',32,'全唐诗/poet.song.203000.json','["吹毛不動定誵訛，徧地茫茫盡倒戈。", "但見清風生閫外，知恩終少負恩多。"]'),
('2200f6e3-117c-4793-8e1e-b69deadcbc59','無聞','釋廣聞','宋','宋诗','song-poetry','','[]','老胡密語已乖張，迦葉何曾解覆藏。',32,'全唐诗/poet.song.203000.json','["老胡密語已乖張，迦葉何曾解覆藏。", "口耳到君俱喪盡，又還家醜外邊揚。"]'),
('27303ad0-9e37-4309-abf1-62de7ceb049b','虛舟','釋廣聞','宋','宋诗','song-poetry','','[]','一從橈下失關津，寂寞空橫斷岸濱。',32,'全唐诗/poet.song.203000.json','["一從橈下失關津，寂寞空橫斷岸濱。", "夜夜蘆花照明月，可憐不見謝家人。"]'),
('eb611f63-99b4-4ac8-96e3-fe26fe85b5df','送林上人歸湖南','釋廣聞','宋','宋诗','song-poetry','','[]','無端活業盡平沉，只爲當時錯用心。',32,'全唐诗/poet.song.203000.json','["無端活業盡平沉，只爲當時錯用心。", "歸路又從湖畔過，水深不似恨深深。"]'),
('4a3b605a-bc7f-4b0e-9129-83c08ff3cf8a','送無言和尚赴楓林','釋廣聞','宋','宋诗','song-poetry','','[]','禍兮不入慎家門，除是知恩解報恩。',32,'全唐诗/poet.song.203000.json','["禍兮不入慎家門，除是知恩解報恩。", "只用五峰曾中底，要人吐了要人吞。"]'),
('4b7ccfb5-868c-43d8-ba3f-ad703a7a97e9','月巖','釋廣聞','宋','宋诗','song-poetry','','[]','光非照境境非存，恁麽曾來二十年。',32,'全唐诗/poet.song.203000.json','["光非照境境非存，恁麽曾來二十年。", "話到乖崖峭壁處，令人特地憶南泉。"]'),
('0fb3debf-8418-42e5-8eee-d70c9f68f7bc','示頭陀過靈隠','釋廣聞','宋','宋诗','song-poetry','','[]','頭顱如雪困風波，未到靈山未倒戈。',32,'全唐诗/poet.song.203000.json','["頭顱如雪困風波，未到靈山未倒戈。", "百萬人中笑花眼，元來猶有此頭陀。"]'),
('ed83130d-bf64-4a8d-9348-22c5b7f60ec7','贈書華嚴','釋廣聞','宋','宋诗','song-poetry','','[]','南詢曾不涉途程，寫盡山雲海月情。',32,'全唐诗/poet.song.203000.json','["南詢曾不涉途程，寫盡山雲海月情。", "放筆看來親到處，一場特地又愁生。"]'),
('e21bb0e9-ef70-4cd2-9dfc-30d2cf03f9b9','上履齋吳丞相  其一','釋廣聞','宋','宋诗','song-poetry','','[]','合從龍首便黄扉，盡謂登庸十載遲。',32,'全唐诗/poet.song.203000.json','["合從龍首便黄扉，盡謂登庸十載遲。", "自是袖中霖雨手，肯令勳業頌臯夔。"]'),
('87159b3b-405d-4b2d-b5bd-1712c3813315','上履齋吳丞相  其二','釋廣聞','宋','宋诗','song-poetry','','[]','一新更化改絃初，人語驩聲藹道途。',32,'全唐诗/poet.song.203000.json','["一新更化改絃初，人語驩聲藹道途。", "僧自深禪湖上寺，不知身世在唐虞。"]'),
('a9dbb0c0-dfd4-4ada-ad17-bad431edf3eb','答日本國丞相令公','釋廣聞','宋','宋诗','song-poetry','','[]','人言千里本同風，何似如今一信通。',32,'全唐诗/poet.song.203000.json','["人言千里本同風，何似如今一信通。", "萬浪千波渾不涉，新羅元在海門東。"]'),
('137c3deb-8188-4318-885a-d9a939dd215d','壞菴','釋廣聞','宋','宋诗','song-poetry','','[]','壁倒籬坍第二籌，扶持不起轉風流。',32,'全唐诗/poet.song.203000.json','["壁倒籬坍第二籌，扶持不起轉風流。", "只因一句隨他語，未到吾宗掃土休。"]'),
('cd2188f7-5583-4405-b892-cc0e7205ebdc','上秋壑賈丞相  其一','釋廣聞','宋','宋诗','song-poetry','','[]','宇宙全歸掌握中，玄機制勝不言功。',32,'全唐诗/poet.song.203000.json','["宇宙全歸掌握中，玄機制勝不言功。", "人將富范張韓比，何異丹青繪太空。"]'),
('97e18e26-e97f-425f-9e79-0a5629dae4ef','上秋壑賈丞相  其二','釋廣聞','宋','宋诗','song-poetry','','[]','力挽天河洗甲兵，爭如談笑凈胡塵。',32,'全唐诗/poet.song.203000.json','["力挽天河洗甲兵，爭如談笑凈胡塵。", "山東名竝山西重，歷數從來有幾人。"]'),
('a8fbe2c0-dccf-4aea-8ea5-754ce2d47eb1','趙居士施丹結萬人緣','釋廣聞','宋','宋诗','song-poetry','','[]','透瓶九轉有餘香，閲世情忘有未忘。',32,'全唐诗/poet.song.203000.json','["透瓶九轉有餘香，閲世情忘有未忘。", "一萬人緣何日了，明朝烟水又茫茫。"]'),
('2271b83d-e36e-45f0-920f-7b1748dd831d','送一徹二公再參無際和尚','釋廣聞','宋','宋诗','song-poetry','','[]','兩公未見無際前，謂從本有成話墮。',144,'全唐诗/poet.song.203000.json','["兩公未見無際前，謂從本有成話墮。", "兩公既見無際後，謂是不同成兩箇。", "明知見與未見時，蒼龍終不澄潭卧。", "雲巖晚歸玲瓏巖，老兒家有彌天禍。", "口皮邊禪慣賣弄，動輒引人入荒草。", "不知兩公竟何意，春風又問東南道。", "貧思舊債濟北馿，再欲一頓憨作麽。", "當時失却一隻眼，賦過關門夾山老。", "後三十年有話在，珍重此行休放過。"]'),
('7b83243e-d2ed-415d-8226-9bb7b8b18a47','送東山源和尚歸閩','釋廣聞','宋','宋诗','song-poetry','','[]','尋思六十蒿枝拂，如何再得一頓喫。',128,'全唐诗/poet.song.203000.json','["尋思六十蒿枝拂，如何再得一頓喫。", "此是臨濟住後時，黄檗棒頭痛的的。", "尋思昔日曾行脚，未離南方已先錯。", "此是天平住後時，西院清風頓銷鑠。", "此時人是彼時人，去時路是來時路。", "老源胸中只自知，却道古人恰相似。", "二月江湖春水生，拈得烏藤先我行。", "得大愚力黄檗力，且聽住後真消息。"]'),
('03eb4f77-ec2e-4368-bec9-b5022488a449','釋迦佛贊','釋廣聞','宋','宋诗','song-poetry','','[]','不即此座，成等正覺。',86,'全唐诗/poet.song.203000.json','["不即此座，成等正覺。", "不離此座，成等正覺。", "入雪山，悟明星，知之者必謂以慈示人。", "開空花，結空果，不知者將謂實有此作。", "皇天無親，惟德是輔，此亦名言不及處。", "借水獻花，不可當面諱却。"]'),
('ff6ef412-b113-4733-87c2-26556e0168f7','出山相贊','釋廣聞','宋','宋诗','song-poetry','','[]','逾重城爲何事，悟明星自欺謾。',34,'全唐诗/poet.song.203000.json','["逾重城爲何事，悟明星自欺謾。", "試問出山，何似入山。", "含元殿裏，猶覓長安。"]'),
('a64775b8-bb7d-48c9-b6e5-6c79174700e9','維摩贊','釋廣聞','宋','宋诗','song-poetry','','[]','機不可觸，病不可醫。',28,'全唐诗/poet.song.203000.json','["機不可觸，病不可醫。", "說黄道黑，引蔓牽枝。", "要見衆生不病時。"]'),
('6cc08445-7f54-456f-ad7b-253be1029a16','觀音贊','釋廣聞','宋','宋诗','song-poetry','','[]','大士真慈念群生，有如慈母憶其子。',96,'全唐诗/poet.song.204000.json','["大士真慈念群生，有如慈母憶其子。", "盡塵毛剎世界海，一一具此一念中。", "惟此一念不退轉，如子得母亦復然。", "眼聲耳色互三昧，情與無情同證入。", "有能不作實證想，當知此相亦非實。", "忽若子母不相知，大士實相常現前。"]'),
('b577633d-b1a3-4379-b8a9-75d8c43ff747','血書心經爲圓相贊','釋廣聞','宋','宋诗','song-poetry','','[]','色何從眼，聲不到耳。',36,'全唐诗/poet.song.204000.json','["色何從眼，聲不到耳。", "耳色眼聲，血滴滴地。", "出乎爾，反乎爾，全身不在圈裏。"]'),
('c857b21b-aba6-4afa-a8ad-77b1a096ce43','師子國相贊','釋廣聞','宋','宋诗','song-poetry','','[]','十方國土中，應身何彼此。',36,'全唐诗/poet.song.204000.json','["十方國土中，應身何彼此。", "春在花，月在水。", "要令當處不留情，好看翻身獅子子。"]'),
('bb95169d-ea62-4781-bbea-438db374b872','水石上相贊  其一','釋廣聞','宋','宋诗','song-poetry','','[]','明月下，磐石上。',34,'全唐诗/poet.song.204000.json','["明月下，磐石上。", "以心中眼，觀身外相。", "六根互用示慈門，無風平地生波浪。"]'),
('76d68310-a2b8-4bcd-bfae-95b546bb4908','水石上相贊  其二','釋廣聞','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','月印長江，風號萬籟。',36,'全唐诗/poet.song.204000.json','["月印長江，風號萬籟。", "隨流入流，無在不在。", "百千三昧一毫頭，貴價精神賤價賣。"]'),
('d4dfdda6-2cc1-4812-9dd8-4c27ed0caf44','魚籃相贊','釋廣聞','宋','宋诗','song-poetry','','[]','風吹兩鬢蕭蕭起，全身已是拖泥水。',32,'全唐诗/poet.song.204000.json','["風吹兩鬢蕭蕭起，全身已是拖泥水。", "何人領取鉤頭意，明明不在魚籃裏。"]'),
('503310c3-e501-4d71-b8e3-3e2fbea82ec7','布袋像贊','釋廣聞','宋','宋诗','song-poetry','','[]','牙關咬定，行又行不上。',45,'全唐诗/poet.song.204000.json','["牙關咬定，行又行不上。", "布袋緊靠，放又放不下。", "知他裏許，有甚兜率內院底。", "十字街頭，遼天索價。"]'),
('57560504-2642-4f3a-a104-2789e2b66ff6','四睡圖贊','釋廣聞','宋','宋诗','song-poetry','','[]','睡時遞相枕藉，醒後互相熱謾。',34,'全唐诗/poet.song.204000.json','["睡時遞相枕藉，醒後互相熱謾。", "笑中有刃，用處多姦。", "看來人斑，寧可虎斑。"]'),
('2c869d1f-ce47-4727-b50c-ed2c83a70a37','韋馱天變相贊','釋廣聞','宋','宋诗','song-poetry','','[]','橫兩腕中杵，現堆雲裏身。',24,'全唐诗/poet.song.204000.json','["橫兩腕中杵，現堆雲裏身。", "權中示權處，依舊是天人。"]'),
('584115e5-e6a5-47bc-80a2-396c5b3504f7','達磨贊  其一','釋廣聞','宋','宋诗','song-poetry','','[]','趁得江頭航折葦，聽教後面風波起。',32,'全唐诗/poet.song.204000.json','["趁得江頭航折葦，聽教後面風波起。", "不負梁王所問來，只有此心如此水。"]'),
('d9a25fac-1c26-40b3-a371-5fad8192ebef','達磨贊  其二','釋廣聞','宋','宋诗','song-poetry','','[]','對梁王突出全機，賺神光錯禮三拜。',32,'全唐诗/poet.song.204000.json','["對梁王突出全機，賺神光錯禮三拜。", "熊耳月照嵩山雲，填溝塞壑無人會。"]'),
('bc596132-34c0-46fa-bf7d-48c25dd16c68','達磨贊  其三','釋廣聞','宋','宋诗','song-poetry','','[]','天寒京洛雪依然，三拜當時有底傳。',32,'全唐诗/poet.song.204000.json','["天寒京洛雪依然，三拜當時有底傳。", "皇道無私太平日，行人猶說普通年。"]'),
('6b55f89d-9bca-441a-b996-797e7b5f421f','五祖荷鋤贊','釋廣聞','宋','宋诗','song-poetry','','[]','江上青山未老，钁頭邊事猶在。',28,'全唐诗/poet.song.204000.json','["江上青山未老，钁頭邊事猶在。", "若能慎初護末，未到兩重納敗。"]'),
('4c2ab9dd-5828-44f8-8022-88a6c0602769','六祖挾擔贊','釋廣聞','宋','宋诗','song-poetry','','[]','柴已落在誰家，此行不空來去。',28,'全唐诗/poet.song.204000.json','["柴已落在誰家，此行不空來去。", "手中擔子相隨，心知應無所在。"]'),
('e0948fd7-b4b4-445e-a334-d90f96f47d67','郁山主贊','釋廣聞','宋','宋诗','song-poetry','','[]','野水小橋外，諸峰凜寒色。',24,'全唐诗/poet.song.204000.json','["野水小橋外，諸峰凜寒色。", "被馿子一交，至今翻不得。"]'),
('6ee5013a-8f13-4605-b60c-7376001fc734','政黄牛贊','釋廣聞','宋','宋诗','song-poetry','','[]','人牛兩相忘，又向橋邊去。',24,'全唐诗/poet.song.204000.json','["人牛兩相忘，又向橋邊去。", "眼明雙鷺鷀，無非是熟處。"]'),
('6db71e0a-193c-4ad5-ad25-79b592034b25','豬頭和尚贊','釋廣聞','宋','宋诗','song-poetry','','[]','目前機，背後底。',37,'全唐诗/poet.song.204000.json','["目前機，背後底。", "爲復神通，爲復游戲。", "直令換盡人眼睛，亦與懸羊賣狗而併案耳。"]'),
('762571e4-ab69-44a4-8578-e96b88979dda','蜆子和尚贊','釋廣聞','宋','宋诗','song-poetry','','[]','酒臺盤上，和聲突出。',37,'全唐诗/poet.song.204000.json','["酒臺盤上，和聲突出。", "釣螺江畔，撈摝得底。", "是則是以鰕爲目，不妨用活底祖師意。"]'),
('f8e1fa4f-eb50-40b9-9ce3-8ad48d823bc9','懶殘和尚贊','釋廣聞','宋','宋诗','song-poetry','','[]','寒涕無暇收，高風自然足。',24,'全唐诗/poet.song.204000.json','["寒涕無暇收，高風自然足。", "客來知不知，吾芋恰新熟。"]'),
('86a51911-12f8-4a82-a6b5-cc5eb29f74e6','船子和尚贊','釋廣聞','宋','宋诗','song-poetry','','[]','一橈復一橈，打著打不著。',24,'全唐诗/poet.song.204000.json','["一橈復一橈，打著打不著。", "至今華亭上，猶更風波惡。"]'),
('0a85a312-8739-4483-b93f-1b3f14985324','朝陽贊','釋廣聞','宋','宋诗','song-poetry','','[]','摘不斷，穿不透。',32,'全唐诗/poet.song.204000.json','["摘不斷，穿不透。", "寬作程，急著手。", "要從破後覓渾崙，當陽拈出誰知有。"]'),
('183367f4-9422-4cad-aa18-589e57163612','對月贊','釋廣聞','宋','宋诗','song-poetry','','[]','本無文，未曾說。',32,'全唐诗/poet.song.204000.json','["本無文，未曾說。", "一字字，生鐵橛。", "欲了了時是了時，何須特地尋明月。"]'),
('542cde4a-3d0f-4ade-b49f-a69a53d6f617','李源訪圓澤贊','釋廣聞','宋','宋诗','song-poetry','','[]','相看已瞭然，安用頻頻舉。',24,'全唐诗/poet.song.204000.json','["相看已瞭然，安用頻頻舉。", "長笛不禁聞，又隨烟棹去。"]'),
('ce7626e5-190f-4145-949d-1da7f7f9f053','熊公見西山贊','釋廣聞','宋','宋诗','song-poetry','','[]','一見能全機，隠身定無路。',24,'全唐诗/poet.song.204000.json','["一見能全機，隠身定無路。", "遇猶不遇時，病在回頭處。"]'),
('da557c92-57cb-402a-93d9-0a439dcf32f8','大道浴湫圖贊','釋廣聞','宋','宋诗','song-poetry','','[]','腥風怒濤中，信手拏得起。',24,'全唐诗/poet.song.204000.json','["腥風怒濤中，信手拏得起。", "觸撥老慈明，攛出拄杖子。"]'),
('9bd1aac5-071c-49f0-a299-5a622bfc66ca','靈照賣笊籬贊','釋廣聞','宋','宋诗','song-poetry','','[]','手把長長竹摝籬，與爺同樂又同悲。',32,'全唐诗/poet.song.204000.json','["手把長長竹摝籬，與爺同樂又同悲。", "輕如毫末重山嶽，十字街頭賣與誰。"]'),
('8d6e0d5f-5f3e-4276-87dd-7ea05eecfca5','大慧佛日禪師贊','釋廣聞','宋','宋诗','song-poetry','','[]','聞薰風南來時，和贓捉獲。',116,'全唐诗/poet.song.204000.json','["聞薰風南來時，和贓捉獲。", "向樹倒藤枯處，覆水難收。", "勘破元禪，楪子飣底青蝦蟆。", "脫得圓悟，胸次用底活馬騮。", "橫三尺竹篦，氣索列祖。", "翻四河雄辯，貫通九流。", "薄四海內外，罔不中傷。", "曠百世上下，其誰與儔。", "區區作是說者，如一塵之微，又何能重輕乎山丘。"]'),
('b3d1ad2e-fc20-4e36-96dd-8ada71f1285c','妙峰和尚贊','釋廣聞','宋','宋诗','song-poetry','','[]','見之目明，氣和如春，猶據妙峰頂時平等示人。',102,'全唐诗/poet.song.204000.json','["見之目明，氣和如春，猶據妙峰頂時平等示人。", "望之心折，面冷如鐵，猶坐蓮峰堂時大默而說。", "奔走龍象，鞭斥風霆。", "不約而繩，不令而行。", "宜其談笑興起東菴正脈，廓清末流之轍。", "至於靈機絕唱，不墮常調，莫妙乎庚峰定穴者也。"]'),
('8246a378-3384-41ea-9102-308aecb154db','大川和尚贊','釋廣聞','宋','宋诗','song-poetry','','[]','握拳透爪，有臨濟體裁。',109,'全唐诗/poet.song.204000.json','["握拳透爪，有臨濟體裁。", "輪珠示人，類大顛風格。", "不欲露全身，慣無贓考賊。", "十地吞聲，二乘動色。", "聚一世精神，而用東山暗號。", "鼓大地波瀾，而疏東澗正脈。", "宜乎百川倒流，天下暴白。", "如是模寫，滄溟一滴。", "傳金襴，倒剎竿，須是迦葉師兄始得。"]'),
('2be45c90-f326-44e5-ae56-e3baf58c7a84','古雲法師贊','釋廣聞','宋','宋诗','song-poetry','','[]','獲旋陀羅尼，機輪轉處風雷疾。',114,'全唐诗/poet.song.204000.json','["獲旋陀羅尼，機輪轉處風雷疾。", "入薩婆若海，舌頭不動雲濤翻。", "肆虛空講，盡實頭禪。", "以栗棘蓬，裹金剛圈。", "陶冶有學之學，而披剝萬象。", "發揮不傳之傳，而朝宗百川。", "是爲北峰真子，無愧竹菴嫡孫。", "後二千年，是真精進。", "所謂靈山未散之旨，至今一會儼然。"]'),
('4175c0b7-5aa8-4a52-9803-31688fe82fe4','牧長老以其師立菴像請贊','釋廣聞','宋','宋诗','song-poetry','','[]','不稟釋迦文，踏翻華藏界。',68,'全唐诗/poet.song.204000.json','["不稟釋迦文，踏翻華藏界。", "由天台南覺城東，提蘇州有常州有。", "立委羽重關，劄洪塘硬寨。", "如是三十年，起妙喜正派。", "若言老子見青山，行人更在青山外。"]'),
('0c7c6e39-0e63-403a-ac29-fcf782122537','謝靈運贊','釋廣聞','宋','宋诗','song-poetry','','[]','平生幾緉屐，自覺山招我。',24,'全唐诗/poet.song.204000.json','["平生幾緉屐，自覺山招我。", "不知身入畫，只貪山色好。"]'),
('29cb9274-20c9-403c-9017-ff23ff883c83','陶淵明贊','釋廣聞','宋','宋诗','song-poetry','','[]','和露鋤豆苗，不覺日又夜。',24,'全唐诗/poet.song.204000.json','["和露鋤豆苗，不覺日又夜。", "飄然從何來，定在南山下。"]'),
('9daa36f3-9f30-4661-a00c-24b2c7cca6ab','許宣平贊','釋廣聞','宋','宋诗','song-poetry','','[]','全肩擔荷時，落日重回首。',24,'全唐诗/poet.song.204000.json','["全肩擔荷時，落日重回首。", "世無相逢人，先生不在酒。"]'),
('044bb83d-fee5-4809-b469-707e18aabacb','孟東野贊','釋廣聞','宋','宋诗','song-poetry','','[]','人知琴無絃，無琴無人知。',24,'全唐诗/poet.song.204000.json','["人知琴無絃，無琴無人知。", "獨立天地間，知音復是誰。"]'),
('f8899417-13ad-4f0f-8907-6cac9d72c9f1','人我擔贊','釋廣聞','宋','宋诗','song-poetry','','[]','先我後人，爲誰辛苦。',35,'全唐诗/poet.song.204000.json','["先我後人，爲誰辛苦。", "三百六十骨節，透頂透底全露。", "窮鬼子，妨不下擔將去。"]'),
('247dc6b5-131d-453c-882e-bb6c06060169','閬州許居士畫像請贊','釋廣聞','宋','宋诗','song-poetry','','[]','家在閬城南，閲浮生知其如寄。',82,'全唐诗/poet.song.204000.json','["家在閬城南，閲浮生知其如寄。", "脚踏長安市，了萬緣齊之一默。", "雅重甘贄風流，孤峻龐老標格。", "甘終身於澹泊，見古道之顔色。", "故其寓意於物，而不留意於物。", "胸中瞭然，一點謾渠不得。"]'),
('44f2e82c-56ba-447a-bef3-67a3ca80e023','行素長老請自贊','釋廣聞','宋','宋诗','song-poetry','','[]','無獅子教兒之訣，無老貓上樹之機。',69,'全唐诗/poet.song.204000.json','["無獅子教兒之訣，無老貓上樹之機。", "世無所容其拙，人或見謂之慈。", "知之已熟，畫出何爲。", "後三十年颺在𡏖𡒁堆頭，便令無光怪發現，未免起傍觀按劍之疑。"]'),
('6c090e71-00ec-401f-8ab4-05dfc7f36c66','端常副寺請自贊','釋廣聞','宋','宋诗','song-poetry','','[]','本分曾無買賣，動輒於人招怪。',42,'全唐诗/poet.song.204000.json','["本分曾無買賣，動輒於人招怪。", "豈知父子之間，描畫虛空著彩。", "端常與麽無端，直是克由叵耐。"]'),
('351c9765-28a5-4f2a-b138-254100c683f9','資壽牧長老請自贊','釋廣聞','宋','宋诗','song-poetry','','[]','鐵牛去住之機，獅子反擲之訣。',54,'全唐诗/poet.song.204000.json','["鐵牛去住之機，獅子反擲之訣。", "毫芒略露，崖崩石裂。", "無些子柔和，唯一味生滅。", "電光石火瞥轉玄關，千聖頂頭恣興妖孽。"]'),
('211a93c3-dddb-4f0d-9aaa-99ae80a24994','禪人請自贊  其一','釋廣聞','宋','宋诗','song-poetry','','[]','冷泉亭放閘，換盡時人眼睛。',159,'全唐诗/poet.song.204000.json','["冷泉亭放閘，換盡時人眼睛。", "見山堂看雲，甚處討他巴鼻。", "認得完全，是則未是。", "手中黑竹篦，不能打得儞。", "胡亂三十年，全無巴鼻。", "叨居六七剎，無補宗教。", "翻著梵志襪，疑之者多。", "倒用司農印，識之者少。", "出嶺既不能跂步玄沙，入嶺又何敢追蹤雪老。", "上人擔頭不堪泊蠅，也能带得。", "老僧去那逢人展，似即不無。", "若謂起楊岐正宗，疏東澗正派，且莫謗渠好。"]'),
('21e3c048-fa3b-481d-a375-ad21fb3c78e9','禪人請自贊  其二','釋廣聞','宋','宋诗','song-poetry','','["\u897f\u6e56"]','北山雲擁千巖秀，西子湖平萬壑流。',32,'全唐诗/poet.song.204000.json','["北山雲擁千巖秀，西子湖平萬壑流。", "水石光中閑送目，無邊剎海一毫收。"]'),
('3f9a954d-4a03-4798-b72f-5739e7ef49c4','印維那請自贊','釋廣聞','宋','宋诗','song-poetry','','[]','眼看東南，意在西北。',80,'全唐诗/poet.song.204000.json','["眼看東南，意在西北。", "毗盧印倒用，輥動古井蓬塵。", "興化棒不施，撒下青天雨雹。", "騰身一擲，而抹過萬仞龍門。", "掉臂徑去，而何有連雲棧閣。", "祖師心印誰是親傳，麟兮龍兮崢嶸頭角。"]'),
('dac1da66-b68a-4300-a132-2457e5f6c58b','雪牧','釋廣聞','宋','宋诗','song-poetry','','[]','整頓蓑衣禦苦寒，自家水牯自家看。',32,'全唐诗/poet.song.204000.json','["整頓蓑衣禦苦寒，自家水牯自家看。", "白漫漫處無香草，笛弄梅花過別山。"]'),
('da1ee183-6da8-4e21-94dd-eeee524e4235','針','釋廣聞','宋','宋诗','song-poetry','','[]','惡鉗鎚下現針鋒，正眼開時一線通。',32,'全唐诗/poet.song.204000.json','["惡鉗鎚下現針鋒，正眼開時一線通。", "百匝千重俱劄透，始知箇是夜深工。"]'),
('f11a0427-d09e-4362-bb71-6784f9d6533d','羲之故居','釋廣聞','宋','宋诗','song-poetry','','[]','亭前不改晉山河，亭下春風屈曲過。',32,'全唐诗/poet.song.204000.json','["亭前不改晉山河，亭下春風屈曲過。", "我自不知賢者事，細挼花片付流波。"]'),
('6cb1968a-1f41-4e4b-b90c-e6e03a62d391','蒸籠','釋廣聞','宋','宋诗','song-poetry','','[]','重重疊疊有來由，熱汗通身未肯休。',32,'全唐诗/poet.song.204000.json','["重重疊疊有來由，熱汗通身未肯休。", "直得變生爲熟去，方知胡餠是饅頭。"]'),
('5767003b-93b4-4420-964a-053e2440d493','函柜','釋廣聞','宋','宋诗','song-poetry','','[]','脫體分明類異常，自然函蓋却相當。',32,'全唐诗/poet.song.204000.json','["脫體分明類異常，自然函蓋却相當。", "衲僧骨董多狼藉，收拾都歸一處藏。"]'),
('27506b90-415b-4f40-98c1-9510a01b9f85','門鈎','釋廣聞','宋','宋诗','song-poetry','','[]','彎彎曲曲箇形骸，曾向紅爐煅煉來。',32,'全唐诗/poet.song.204000.json','["彎彎曲曲箇形骸，曾向紅爐煅煉來。", "觸著上頭關棙子，千門萬戶一時開。"]'),
('0c40a98a-8c1e-4590-adcc-cb1d17280fd8','化楞嚴會香燭  其一','釋廣聞','宋','宋诗','song-poetry','','[]','椽燭爐香夏九旬，二千年事向誰論。',32,'全唐诗/poet.song.204000.json','["椽燭爐香夏九旬，二千年事向誰論。", "人家十萬春風裡，盡是靈山會上人。"]'),
('5373f79a-d87c-4605-9729-5f91d3100363','化楞嚴會香燭  其二','釋廣聞','宋','宋诗','song-poetry','','[]','玉磬輕敲紫篆清，金蓮花綻燭熒熒。',32,'全唐诗/poet.song.204000.json','["玉磬輕敲紫篆清，金蓮花綻燭熒熒。", "從教一百二十日，散作滿天星斗明。"]'),
('169a2c54-2729-4874-aba1-7c7b5798d20d','題林司戶寒齋','劉克遜','宋','宋诗','song-poetry','','[]','高絕寒齋雖未到，但觀名扁定非虛。',64,'全唐诗/poet.song.204000.json','["高絕寒齋雖未到，但觀名扁定非虛。", "連床夜語爐無火，四壁秋聲案有書。", "要與西塘同苦淡，更容東野伴蕭疎。", "區區粗得歸閑趣，每見高風愧不如。"]'),
('7d9c31fd-5dbb-4433-8176-e2833dbd58d3','三賢堂','劉克遜','宋','宋诗','song-poetry','','[]','堂成土木極精華，壯觀先生處士家。',32,'全唐诗/poet.song.204000.json','["堂成土木極精華，壯觀先生處士家。", "只恐三賢還一笑，不留隙地種梅花。"]'),
('8423ccb8-27a0-4100-b9ee-1cf41767fac4','江城','劉克遜','宋','宋诗','song-poetry','','[]','過了元宵景自佳，東風輕拂酒旗斜。',32,'全唐诗/poet.song.204000.json','["過了元宵景自佳，東風輕拂酒旗斜。", "江城可是春先到，已有盈街賣杏花。"]'),
('66b9a743-59c1-45a3-80b7-4b72303d2d68','送楊帥','劉克遜','宋','宋诗','song-poetry','','[]','累詔登華省，當時已避蹤。',48,'全唐诗/poet.song.204000.json','["累詔登華省，當時已避蹤。", "身閑名轉重，道大世難容。", "南國因鋤薤，東山得倚筇。", "何當投劾去，短褐許相從。"]'),
('899ff893-d9bf-426c-b801-0bc8999fba4a','壽樞使','劉克遜','宋','宋诗','song-poetry','','[]','喧喧文價握靈蛇，凜凜詞鋒挺鏌鋣。',64,'全唐诗/poet.song.204000.json','["喧喧文價握靈蛇，凜凜詞鋒挺鏌鋣。", "出遇萬年天子聖，生從七葉侍中家。", "君臣相悅同魚藻，兄弟連榮比棣華。", "歲歲重三前六日，壽觴何惜泛流霞。"]'),
('ae34506e-97c1-40e5-8253-1bc5860e82a7','壽異憲','劉克遜','宋','宋诗','song-poetry','','[]','元氣鍾爲一代英，天休節後是公生。',64,'全唐诗/poet.song.204000.json','["元氣鍾爲一代英，天休節後是公生。", "撐腸何止五千卷，滿腹猶藏十萬兵。", "懶向仕途爲佞熊，肯將祠秩倦閑情。", "芹溪不是橫舟處，四海風波正要平。"]'),
('98307340-4040-4411-95df-9c5adaab97e6','壽泉使','劉克遜','宋','宋诗','song-poetry','','[]','新春三九左弧垂，惟有東皇造化知。',64,'全唐诗/poet.song.204000.json','["新春三九左弧垂，惟有東皇造化知。", "不爲等閑花柳計，獨應長養棟梁姿。", "擎天一柱寧論價，伴月孤根永不移。", "自昔中書貴多考，願公難老過□期。"]'),
('ba8ce70b-67f4-4ccf-b8f8-304f7d49ba1c','詠蘭','趙以夫','宋','宋诗','song-poetry','','[]','一朵俄生几案光，尚如逸士氣昂藏。',32,'全唐诗/poet.song.204000.json','["一朵俄生几案光，尚如逸士氣昂藏。", "秋風試與平章看，何似當時林下香。"]'),
('00549e6c-30ff-4960-b4fe-fa3f794fe9c3','句','趙以夫','宋','宋诗','song-poetry','','[]','片雲不隔梅花月。',8,'全唐诗/poet.song.204000.json','["片雲不隔梅花月。"]'),
('ca00833b-26d7-4ee1-8631-badc3364b7fc','黄陵廟','黄棐','宋','宋诗','song-poetry','','[]','瀟湘江頭三月春，柳條弄日摇黄金。',64,'全唐诗/poet.song.204000.json','["瀟湘江頭三月春，柳條弄日摇黄金。", "鷓鴣一聲在何許，黄陵廟前烟靄深。", "丹青欲畫無好手，穩提玉勒况今久。", "馬蹄不爲行客留，心掛長林屢回首。"]'),
('fc27f6d0-96a3-4d79-9417-44a612413f9a','覽友莊子文稿','趙時彌','宋','宋诗','song-poetry','','[]','信手拈來語不驚，縱橫漫與筆端呈。',64,'全唐诗/poet.song.204000.json','["信手拈來語不驚，縱橫漫與筆端呈。", "獨崇爾雅追先輩，肯競鉛華逐後生。", "至寶何曾營琢削，神工自是謝鋤耕。", "一篇三復還堪味，不覺今人解性靈。"]'),
('a779ebd2-dc95-4c32-9d9d-92f369d91feb','句','李翔高','宋','宋诗','song-poetry','','[]','春愁自是無重數，又被東風揭繡簾。',16,'全唐诗/poet.song.204000.json','["春愁自是無重數，又被東風揭繡簾。"]'),
('ee33e328-8e12-4eef-818e-d3d31cfb9baf','隠求齋  其一','林汝礪','宋','宋诗','song-poetry','','[]','蝸名蠅利處樊籠，世事其如轉眼空。',32,'全唐诗/poet.song.204000.json','["蝸名蠅利處樊籠，世事其如轉眼空。", "惟有高人林下隠，只求明月與清風。"]'),
('e6141aff-3bbe-4b0b-9ab2-5355bd58b923','隠求齋  其二','林汝礪','宋','宋诗','song-poetry','','[]','朝同猿鳥吟，暮與麋鹿游。',24,'全唐诗/poet.song.204000.json','["朝同猿鳥吟，暮與麋鹿游。", "吾生有良願，捨此當安求。"]'),
('f2354e06-9c2a-459b-a3b7-207b0a09da11','題武夷仙掌巖','林汝礪','宋','宋诗','song-poetry','','[]','漢武昇遐幾度春，金莖事迹總無聞。',32,'全唐诗/poet.song.204000.json','["漢武昇遐幾度春，金莖事迹總無聞。", "懸崖更不承朝露，空印纖纖十指紋。"]'),
('83e5139c-e148-4bf0-8026-63bb83ef4cb2','題錢明仲汲古堂','陳夢庚','宋','宋诗','song-poetry','','[]','自一而三散萬殊，學惟定力是功夫。',64,'全唐诗/poet.song.204000.json','["自一而三散萬殊，學惟定力是功夫。", "十分謹處持槃水，萬理紬來似轆轤。", "癡叔床空唯易在，濂溪閣冷有圖無。", "希天窮到淵淵地，子肯閑來擁地爐。"]'),
('663d625a-5fdf-41db-8d4f-729c54830192','初度客中有感','陳夢庚','宋','宋诗','song-poetry','','[]','越舄長吟有所思，生空照社老空癡。',64,'全唐诗/poet.song.204000.json','["越舄長吟有所思，生空照社老空癡。", "一千餘尺拔文筆，三十六灣深墨池。", "人物要當天地意，溪山不欠晉唐詩。", "淵明子美成何事，牢落生涯寄酒巵。"]'),
('3a3a6647-ab60-4299-8ba6-6a5a6b036b34','燈夕','陳夢庚','宋','宋诗','song-poetry','','[]','人生能看幾番燈，强倚燈花聽竹聲。',64,'全唐诗/poet.song.204000.json','["人生能看幾番燈，强倚燈花聽竹聲。", "玉管吹殘梅外雪，星毬撰出雨邊晴。", "人行香霧不知夜，兒傲饑雷看到明。", "夢破春風感留滯，老書移就短長檠。"]'),
('d30b896a-38cf-4cdf-b1bd-f1fb9a9eeacf','心恥奉檄','陳夢庚','宋','宋诗','song-poetry','','[]','日月孔兼孟，塵埃申與韓。',48,'全唐诗/poet.song.204000.json','["日月孔兼孟，塵埃申與韓。", "合於三尺法，行矣一分寬。", "火傘不遮熱，冰壺獨枕寒。", "平反了無幾，足跡略高安。"]'),
('fd85e40d-c1c2-4c47-a1cd-0bd2c59704b5','漢祀壇','陳夢庚','宋','宋诗','song-poetry','','[]','苔老壇荒掃不開，漢皇多慾豈仙才。',32,'全唐诗/poet.song.204000.json','["苔老壇荒掃不開，漢皇多慾豈仙才。", "乘龍人去真圖失，萬里空勞一使來。"]'),
('513dbc9b-6df3-4bf0-bf63-7939a53731eb','仙茶竈','陳夢庚','宋','宋诗','song-poetry','','[]','儘夸六椀便仙靈，得似仙山石乳清。',32,'全唐诗/poet.song.204000.json','["儘夸六椀便仙靈，得似仙山石乳清。", "此水此茶須是竈，無人肯說與端明。"]'),
('2d337948-644e-4f47-86b9-9a10dc4b8407','武夷山','陳夢庚','宋','宋诗','song-poetry','','[]','看了圖經看舊碑，怪奇多是說秦時。',32,'全唐诗/poet.song.204000.json','["看了圖經看舊碑，怪奇多是說秦時。", "當時人會秦王意，可是建山稱武夷。"]'),
('e4a984a7-fff5-4574-8265-70b634994293','唐刻石','陳夢庚','宋','宋诗','song-poetry','','[]','長憶唐從天寶初，開元氣象了無餘。',32,'全唐诗/poet.song.204000.json','["長憶唐從天寶初，開元氣象了無餘。", "宮中已製霓裳曲，刻石山靈失笑渠。"]'),
('17133aae-97d7-41be-8add-61b5914c0b8e','武夷大隠屏','陳夢庚','宋','宋诗','song-poetry','','[]','大隠屏前風月閑，何人手種萬琅玕。',32,'全唐诗/poet.song.204000.json','["大隠屏前風月閑，何人手種萬琅玕。", "深深五曲東流水，合作千年洙泗看。"]'),
('c69f2586-fb3d-4d75-97e8-928fff4f3dee','武夷仙浴堂','陳夢庚','宋','宋诗','song-poetry','','[]','神仙無垢骨猶香，底用山間開浴堂。',32,'全唐诗/poet.song.204000.json','["神仙無垢骨猶香，底用山間開浴堂。", "我欲從之三洗髓，騎鯨散髮水雲鄉。"]'),
('940fd614-633f-429d-a670-257fadbc22dd','武夷大小廩石','陳夢庚','宋','宋诗','song-poetry','','[]','白石青霞爲歲計，佳殽旨酒出仙壺。',32,'全唐诗/poet.song.204000.json','["白石青霞爲歲計，佳殽旨酒出仙壺。", "侵天有廩無支遣，歲惡還能賑貸無。"]'),
('dd226b30-bd33-48ec-b5db-e7d923448be7','自劉真人庵上登飛雲','陳夢庚','宋','宋诗','song-poetry','','[]','列仙壇上碧鷄鳴，布襪青鞵取次行。',64,'全唐诗/poet.song.204000.json','["列仙壇上碧鷄鳴，布襪青鞵取次行。", "上界煙霞疑可到，東方草木漸知名。", "一泓滄海杯浮景，萬點青山棋落枰。", "脚底雲飛寒带雨，此身知是在蓬瀛。"]'),
('7e503010-c883-4b4d-ac71-d0227b69fb19','仙船','陳夢庚','宋','宋诗','song-poetry','','[]','此船何事架巖隈，不遂浮槎八月來。',32,'全唐诗/poet.song.204000.json','["此船何事架巖隈，不遂浮槎八月來。", "莫是飛仙無所用，乘風有路到蓬萊。"]'),
('5a317898-c103-4b47-aa5e-392140ea1be2','幔亭峰','陳夢庚','宋','宋诗','song-poetry','','[]','山中別是一桃源，綵屋虹橋影不存。',32,'全唐诗/poet.song.204000.json','["山中別是一桃源，綵屋虹橋影不存。", "山下人癡猶自說，排簷元是武夷孫。"]'),
('edd88529-63fc-4b75-a64d-320190bc333b','仙鼓樓','陳夢庚','宋','宋诗','song-poetry','','[]','求仙曾誤幾英雄，祇爲沉迷利欲中。',32,'全唐诗/poet.song.204000.json','["求仙曾誤幾英雄，祇爲沉迷利欲中。", "安得樓頭一聲鼓，頓教凡世醒盲聾。"]'),
('f3db02c7-d093-4b54-8b3d-458ee523619d','西湖置酒短歌','尤焴','宋','宋诗','song-poetry','','["\u897f\u6e56"]','春雲薄，淡將落。',84,'全唐诗/poet.song.204000.json','["春雲薄，淡將落。", "我心良與然，浩蕩杳無著。", "黄鳥枝頭語太工，可能喚起東坡翁。", "眼前妙景供妙咏，鈞天吹下乘長風。", "醉而復醒醒復醉，香山居士今安在。", "濡首狂歌無限情，一齊付與雲山外。"]'),
('209881cb-de12-43c1-81b5-a772e21db73b','被命出鎮淮西至任','尤焴','宋','宋诗','song-poetry','','[]','萬籟無聲意轉豪，一揮出守敢云勞。',64,'全唐诗/poet.song.204000.json','["萬籟無聲意轉豪，一揮出守敢云勞。", "臣心耿耿依三殿，予髮垂垂有二毛。", "月黑星光懸帳幙，夜深霜氣滿弓刀。", "披衣秉燭終宵坐，待旦乘時演豹韜。"]'),
('1345db3e-a5e5-4361-b3ba-a6cc2146afae','早朝步葛元喆韻','吳淵','宋','宋诗','song-poetry','','[]','萬井蒼涼欲曙天，禁鐘聲斷佩聲聯。',64,'全唐诗/poet.song.204000.json','["萬井蒼涼欲曙天，禁鐘聲斷佩聲聯。", "雲浮玉輦霞裾降，風動金蓮寶炬然。", "四國龍飛清穆世，羣工虎拜太平年。", "吾王不倦宵衣念，國祚遥知永永傳。"]'),
('d9e7c603-27aa-49ed-9df5-064de858e8dc','九日','吳淵','宋','宋诗','song-poetry','','[]','百年王事謾勞形，客裏逢時跡類萍。',64,'全唐诗/poet.song.204000.json','["百年王事謾勞形，客裏逢時跡類萍。", "無酒可添元亮興，任人浪笑阮宣醒。", "荆湖城壁連鉦鼓，河朔黎元陷虜庭。", "久擁旌旄愧無補，敢將衰朽歎飄零。"]'),
('51eb2da5-ef4c-44fe-91a3-d85665af086f','登南城','吳淵','宋','宋诗','song-poetry','','[]','江城一眺思悠悠，平楚蒼然野水流。',64,'全唐诗/poet.song.204000.json','["江城一眺思悠悠，平楚蒼然野水流。", "衰草寒烟梅老墓，敗垣斜日謝公樓。", "江山有恨英雄老，天地無私草木秋。", "萬古興亡俱是夢，丈夫何者爲身謀。"]'),
('e83a7def-56c5-421c-a7c8-8c68ceb25a6e','遊青山  其一','吳淵','宋','宋诗','song-poetry','','[]','碧嶂千層鎮一州，十年前記作斯遊。',64,'全唐诗/poet.song.204000.json','["碧嶂千層鎮一州，十年前記作斯遊。", "因看紅杏行停轡，爲濯清泉坐解裘。", "怪石巉巖蹲虎豹，老松偃蹇卧龍虬。", "轉看轉有無窮景，杖履何妨絕頂頭。"]'),
('1d2f9d60-5083-4af8-bef0-845603cd0a43','遊青山  其二','吳淵','宋','宋诗','song-poetry','','[]','風流千載憶玄暉，此日登臨不覺疲。',64,'全唐诗/poet.song.204000.json','["風流千載憶玄暉，此日登臨不覺疲。", "看取眼前都是句，如何身後不留詩。", "須知小隠徜徉日，正是高吟寥泬時。", "可惜出山終不免，空留翠岫與清漪。"]'),
('2c734d9c-bbb5-4cf3-a564-3d40fb447256','橫碧堂','吳淵','宋','宋诗','song-poetry','','[]','十一年如一欠伸，今朝又得快登臨。',64,'全唐诗/poet.song.204000.json','["十一年如一欠伸，今朝又得快登臨。", "半城楊柳春風滿，四野桑麻雨露深。", "檻外翠峰重入眼，樽前白髮遂驚心。", "感今懷昔憑欄處，不覺崦嵫日已沈。"]'),
('bff5b4be-22cd-46e3-9e42-0e17a5fbf486','用前韻','吳淵','宋','宋诗','song-poetry','','[]','每來登眺便眉伸，高處蒼穹儼若臨。',64,'全唐诗/poet.song.204000.json','["每來登眺便眉伸，高處蒼穹儼若臨。", "投老光陰隨日晚，思歸情緒與秋深。", "鷺飛沙際迷人目，雁滿江頭動客心。", "北望淮淝何處是，晚來烟霧正沈沈。"]'),
('5ee2c904-8f83-4e63-bb0a-b44b6b790026','官梅亭','吳淵','宋','宋诗','song-poetry','','[]','疇昔花前屢舉觴，重來鬢髮已蒼蒼。',64,'全唐诗/poet.song.204000.json','["疇昔花前屢舉觴，重來鬢髮已蒼蒼。", "未容籬菊成歸隠，且向官梅作醉鄉。", "每約松篁堅歲晚，肯隨桃李競春芳。", "東風二月無人惜，片片霏霏雪自香。"]'),
('59aef3d6-d9f5-4aab-94da-db36d06b760f','霜蕤亭三首  其一','吳淵','宋','宋诗','song-poetry','','[]','正到春歸惱客腸，荼䕷架上發孤芳。',64,'全唐诗/poet.song.204000.json','["正到春歸惱客腸，荼䕷架上發孤芳。", "劉伶嗜酒名爲酒，薛女餐香肌亦香。", "人已今朝衰鬢髮，花猶昔日淡梳妝。", "十年陳迹渾如夢，徙倚闌干到夕陽。"]'),
('0c3f2f80-85a6-4cee-9c0f-c19b0937202d','霜蕤亭三首  其二','吳淵','宋','宋诗','song-poetry','','[]','東皇爲代是南薰，醖釀成花迥出塵。',64,'全唐诗/poet.song.204000.json','["東皇爲代是南薰，醖釀成花迥出塵。", "盡洗嬌紅春態度，獨呈雅素雪精神。", "牽衣弱蔓如留客，入枕清香更惱人。", "月下星前曾醉插，肯容煩暑到冠巾。"]'),
('c8df9c4d-791c-45bd-866c-f4288150d233','霜蕤亭三首  其三','吳淵','宋','宋诗','song-poetry','','[]','園丁編竹亦勤哉，老蔓纖條費剪裁。',64,'全唐诗/poet.song.204000.json','["園丁編竹亦勤哉，老蔓纖條費剪裁。", "杳杳翠雲深作洞，霏霏香雪簇成堆。", "玉虬飛下盤千尺，金爵携將飲百杯。", "說與此花狼籍後，園林杖履亦稀來。"]'),
('a7b2bf46-df04-4cde-b875-f3bf84420f3d','揮麈堂二首  其一','吳淵','宋','宋诗','song-poetry','','[]','老守重來何所爲，築成臺榭鑿成池。',64,'全唐诗/poet.song.204000.json','["老守重來何所爲，築成臺榭鑿成池。", "綠深夜雨龜魚遠，紅壓春風鶑燕遲。", "民樂軒墀偏少訟，官閒園圃自多詩。", "鳳團啜罷投衾枕，夢覺花間日影移。"]'),
('9e262b22-acb7-4e4d-89f1-fef10e19f830','揮麈堂二首  其二','吳淵','宋','宋诗','song-poetry','','[]','戀宿懷安物我齊，况兼兩世四持麾。',64,'全唐诗/poet.song.204000.json','["戀宿懷安物我齊，况兼兩世四持麾。", "可憐園內樂成日，却被官中捉去時。", "李郭詩篇懷舊迹，歐梅歌舞悵新知。", "多應日後清宵夢，頻到姑溪溪水湄。"]'),
('a0181a5b-4890-4641-a186-5af4fe004670','送杜尚書赴行在','吳淵','宋','宋诗','song-poetry','','[]','龍德剛中道學優，洛中夫子爾同流。',64,'全唐诗/poet.song.204000.json','["龍德剛中道學優，洛中夫子爾同流。", "暫辭天府安邊閫，又屬軺車返帝州。", "萬里長城唐李勣，百年勳業漢留侯。", "明朝回首秋江上，泰華巖巖天際頭。"]'),
('448d81c5-5871-4878-9712-4b78cd234bfa','冬雨','吳淵','宋','宋诗','song-poetry','','[]','坐來雜霰灑隆冬，痛飲那禁觱發風。',32,'全唐诗/poet.song.204000.json','["坐來雜霰灑隆冬，痛飲那禁觱發風。", "却憶西樞承旨日，冒寒猶立大明宮。"]'),
('41cefeee-5620-4778-8f8e-f5809d36524a','高氏小景','吳淵','宋','宋诗','song-poetry','','[]','地白天寒凍裂裘，何人乘艇下中流。',32,'全唐诗/poet.song.204000.json','["地白天寒凍裂裘，何人乘艇下中流。", "披圖孟浪不相識，疑是當年王子猷。"]'),
('2e398cb0-866c-4a12-9ce1-3d9dcd013afd','鳳凰臺二首  其一','吳淵','宋','宋诗','song-poetry','','[]','暫因休暇得遨游，感慨樽前歲月流。',64,'全唐诗/poet.song.204000.json','["暫因休暇得遨游，感慨樽前歲月流。", "長向此時憂徼塞，不知何日樂林丘。", "鳳凰寂寂空留寺，鴻雁嗷嗷尚滿洲。", "疇昔謫仙愁絕處，我來登眺更多愁。"]'),
('a8ac332e-c3af-433c-9557-5f55d711a591','鳳凰臺二首  其二','吳淵','宋','宋诗','song-poetry','','[]','六朝舊跡作新游，王謝千年風尚流。',64,'全唐诗/poet.song.204000.json','["六朝舊跡作新游，王謝千年風尚流。", "但使時能開晉宋，只緣道不本軻丘。", "昏昏赤縣神州地，渺渺白蘋紅蓼洲。", "誰道天分南北限，人分南北至今愁。"]'),
('faa316c6-03ba-471d-924f-266d602cd171','勸耕二首  其一','吳淵','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','細靄輕烟弄晚晴，聊驅小隊出城闉。',64,'全唐诗/poet.song.204000.json','["細靄輕烟弄晚晴，聊驅小隊出城闉。", "□將泉石膏肓療，爲識廬山面目真。", "古殿松篁無盛夏，齋厨筍蕨有餘春。", "道旁處處聞流水，一部笙篁更可人。"]'),
('1ac78b12-5940-44e8-ba29-f9d57796b369','勸耕二首  其二','吳淵','宋','宋诗','song-poetry','','[]','鈴齋日日簿書塵，不覺光陰暗裏侵。',64,'全唐诗/poet.song.204000.json','["鈴齋日日簿書塵，不覺光陰暗裏侵。", "忽見前山有花發，始知今歲已春深。", "邊風尚有寒吹面，臘雪全無早繫心。", "憂國憂民平日事，新來贏得白盈簪。"]'),
('797731f2-0b15-4e52-ac1a-1e20c03952a9','峨眉山','吳淵','宋','宋诗','song-poetry','','[]','一带天分南北限，兩眉烟鎖古今愁。',32,'全唐诗/poet.song.204000.json','["一带天分南北限，兩眉烟鎖古今愁。", "却思太白驚人句，影入平羌江水流。"]'),
('02921937-d011-45a9-86c0-f93cc6130e3d','江南麥','釋本真','宋','宋诗','song-poetry','','[]','江南麥似草離離，胡馬貪青隔岸嘶。',32,'全唐诗/poet.song.204000.json','["江南麥似草離離，胡馬貪青隔岸嘶。", "驚得村翁多計較，旋樵桑葦縛疏籬。"]'),
('81e0aab0-d8d9-42f8-afd8-839deaf6a331','賦吳門上元','釋本真','宋','宋诗','song-poetry','','[]','村翁看了上元歸，正是西樓月落時。',32,'全唐诗/poet.song.204000.json','["村翁看了上元歸，正是西樓月落時。", "誇道官衙好燈火，不知渾爾點膏脂。"]'),
('3b4ca8bb-a053-4a12-9394-897ea13265fc','題經略臺','張琮','宋','宋诗','song-poetry','','[]','維攀白玉龍，曾上黄金臺。',48,'全唐诗/poet.song.204000.json','["維攀白玉龍，曾上黄金臺。", "指揮十二州，意氣何快哉。", "江上只如舊，四面畫圖開。", "慨懷出奇略，何地不生才。"]'),
('88e24ab8-e148-4772-97e9-29cacb64d73c','逍遥樓','張琮','宋','宋诗','song-poetry','','[]','神遊八極表，乃是逍遥意。',72,'全唐诗/poet.song.204000.json','["神遊八極表，乃是逍遥意。", "因之以名命，何取漆園吏。", "扁榜誰其書，太師龍蛇字。", "彈壓南容筦，江山倍增氣。", "心畫如見人，像想用餘地。", "我來登斯樓，凜凜敬節義。"]'),
('4aacd7d6-14db-4526-a3a0-049b53cfe2c2','獨秀峰','張琮','宋','宋诗','song-poetry','','[]','原隰驅驅過一冬，好山何處不相逢。',64,'全唐诗/poet.song.204000.json','["原隰驅驅過一冬，好山何處不相逢。", "層巒疊嶂分高下，翠靄晴嵐暈淡濃。", "小至停車休作暇，遷來携酒款從容。", "千崖競秀吾鄉遠，只在南容獨秀峰。"]'),
('73577eea-627b-41a9-aa3c-b90643eb3842','光福寺  其一','朱士麟','宋','宋诗','song-poetry','','[]','不辭暑汗透冠裳，亟拜靈祠爲亢陽。',64,'全唐诗/poet.song.204000.json','["不辭暑汗透冠裳，亟拜靈祠爲亢陽。", "與佛有緣憑佛力，于心無愧爇心香。", "崇朝霶霈施霖雨，千里歡欣飽稻粱。", "老吏兩年蒙潤澤，詩成借筆記僧房。"]'),
('cbdf57fb-f9e4-4627-82a3-fe5fd2a2ebde','光福寺  其二','朱士麟','宋','宋诗','song-poetry','','[]','乍和便覺怯衣裳，且駐歸舟傍夕陽。',64,'全唐诗/poet.song.204000.json','["乍和便覺怯衣裳，且駐歸舟傍夕陽。", "連日雨花多聽雨，今年香積又炊香。", "幸憑佛力成因果，消得詩人詠稻粱。", "殽核已無尊有酒，就溪带水擘蓮房。"]'),
('cd12800a-09cc-42b5-bfd2-e19460134ac8','曹娥江','余晦','宋','宋诗','song-poetry','','[]','男兒儘有移忠事，何處芳名不此侔。',32,'全唐诗/poet.song.204000.json','["男兒儘有移忠事，何處芳名不此侔。", "今日扁舟賦歸去，心如秋月印江流。"]'),
('428cec0c-6f4e-432b-bf68-c352893d1f47','遊澹山巖','王子申','宋','宋诗','song-poetry','','[]','坤靈擘罅天幻奇，一到仙凡覺兩岐。',64,'全唐诗/poet.song.204000.json','["坤靈擘罅天幻奇，一到仙凡覺兩岐。", "處士清風存萬古，詩翁雅句見當時。", "洞深不礙烟雲逸，丹就那知日月遲。", "更上層臺瞻佛像，媿無法語勘狐疑。"]'),
('5d9a5d19-bb3e-4c6e-8264-8e48fff35980','梨花山','史宜之','宋','宋诗','song-poetry','','[]','梨花飛雪滿春山，錯認寒梅露玉顔。',32,'全唐诗/poet.song.204000.json','["梨花飛雪滿春山，錯認寒梅露玉顔。", "幾日登山尋樂境，香風滿袖放船還。"]'),
('64542947-e1d5-40d2-983a-0b2ad220a9c9','季子廟','史{隽乃=冏}之','宋','宋诗','song-poetry','','[]','千載江濱季子宮，聯鑣款謁驟西風。',64,'全唐诗/poet.song.204000.json','["千載江濱季子宮，聯鑣款謁驟西風。", "清名長逐秋潮壯，遺蹟應隨夕照空。", "管領物華輸酒聖，平章古意屬詩翁。", "想君岸幘風塵表，笑我埋頭雁鶩中。"]'),
('a266694e-e7eb-4c74-96fb-d57c6b8de2bb','君山','史{隽乃=冏}之','宋','宋诗','song-poetry','','[]','釃酒臨江望石灣，松風引上白雲關。',64,'全唐诗/poet.song.204000.json','["釃酒臨江望石灣，松風引上白雲關。", "潮吹海雨來無際，帆遂天風去不還。", "千仞振衣聊遣興，一江如带敢偷閑。", "老懷撫事偏多感，莫拮中原幾點山。"]'),
('805d38cf-7191-4c63-91e5-1abb6fa36990','大滌洞天留題','曾槱','宋','宋诗','song-poetry','','[]','夢想雲根久已哉，青鞋布襪喜重來。',64,'全唐诗/poet.song.204000.json','["夢想雲根久已哉，青鞋布襪喜重來。", "筍添簡寂春前盛，桃勝玄都觀裏栽。", "洞狹天寬多秀異，泉清石怪少塵埃。", "仙家日月長如許，我欲朝真屢往回。"]'),
('5fd338c1-ec12-4782-af69-e62d3674e0b7','送胡秀昭謫象州','謝鄆','宋','宋诗','song-poetry','','[]','燕雀群飛敞漢宮，驚聞伏馬忽嘶風。',64,'全唐诗/poet.song.204000.json','["燕雀群飛敞漢宮，驚聞伏馬忽嘶風。", "洪恩大度祈三宥，烏府何顔奏一通。", "勁節敢攀丹陛檻，忠言應夢白頭翁。", "象臺一貶端然直，所幸身窮道不窮。"]'),
('350d66ad-3b15-4082-979a-0c149b5225a4','穿巖','王爚','宋','宋诗','song-poetry','','[]','穿巖之峰高蒼蒼，峰巒十九摩天光。',384,'全唐诗/poet.song.204000.json','["穿巖之峰高蒼蒼，峰巒十九摩天光。", "晨曦烜赫晹出岫，下望滄海何茫茫。", "有峰俛伏如鵝鼻，世說任公釣魚地。", "纜舟鑿石宛然存，海變桑田幾千歲。", "泗洲儼然坐其中，右顧蒸餠香爐峰。", "普賢獅子出雲來，筆架磬峰應覆鐘。", "峰頭有石平如席，仙子下棋有仙跡。", "雲收帳暖見文殊，新婦蛾眉弄空碧。", "好似將軍戰勝歸，擺旗卓劍逞雄威。", "又若子卿持漢節，幞頭高聳立丹墀。", "或如驟馬朝天闕，鼻孔撩天通日月。", "中有神人來隠居，老墨題詩猶未滅。", "斷崖蒼碧一線懸，崎嶇有路如登天。", "松關竹塢雜秋色，稻田麥壠凝春烟。", "危樓傑閣建庵宇，石空神僧開山祖。", "八載跏趺不下山，冷眼死生猶旦暮。", "遊人到此若登瀛，徙倚闌干鬼神驚。", "當年瀉出天池水，猶是尋常瀑布聲。", "山猿夜啼明月薄，聽雪眠雲猶未覺。", "五百真人應共歸，天香桂子紛紛落。", "居民多在此山前，强寇陸梁宣和年。", "流毒數州民受苦，老稚登山獲保全。", "誰知草莽英雄起，管領鄉民皆效死。", "山上分爲西南界，十萬魔軍猶睥睨。"]'),
('1f4ab8ac-5515-4bac-be4e-cc7f79a14e73','薦癡絕禪師','徐敏','宋','宋诗','song-poetry','','[]','癡絕有菴不肯住，弄月挑雲徑山去。',192,'全唐诗/poet.song.204000.json','["癡絕有菴不肯住，弄月挑雲徑山去。", "地水火風分裂時，親書贈予黄葛布。", "蛻封讀罷咽無語，會得龍鬚能避暑。", "豈知玉骨本清凉，書則珍藏布不取。", "源老忽踏幽深路，道在隔山遥望處。", "巨帙已載爛葛藤，何堪又送閒家具。", "開眼一看笑呵呵，猶有這個可奈何。", "來而不往非世法，聊效芹忱愧不多。", "兩角茶，十袋麵，寶瓶飛錢五十萬。", "虔心獻此一瓣香，奉爲禪師作清薦。", "且問先師來不來，玉山菴頂白雲開。", "更煩大衆打圓相，撥取青蓮火裏灰。"]'),
('c6bebfd4-872c-418a-9806-86be06c24f24','梅花  其一','江朝宗','宋','宋诗','song-poetry','','[]','小小人家短短籬，冷香濕雪兩三枝。',32,'全唐诗/poet.song.204000.json','["小小人家短短籬，冷香濕雪兩三枝。", "寂寥竹外無窮思，正倚江天日暮時。"]'),
('5d8bd89b-a0d9-4c2f-89d8-57faff2cbb25','梅花  其二','江朝宗','宋','宋诗','song-poetry','','[]','月淡霜清驛路長，一枝春信到江鄉。',32,'全唐诗/poet.song.204000.json','["月淡霜清驛路長，一枝春信到江鄉。", "西山餓死魂猶瘦，洛浦仙遊佩亦香。"]'),
('599de7a5-7403-42ef-b12d-7a471386ba03','題式之詩卷後','李義山','宋','宋诗','song-poetry','','[]','老氣稜稜未易攀，誼襟凜凜可廉頑。',64,'全唐诗/poet.song.204000.json','["老氣稜稜未易攀，誼襟凜凜可廉頑。", "瘦筇只爲江湖上，詩卷傍行天地間。", "社風雨花春正好，酒壚山屐夢相關。", "夔州已浚花繩削，今度編成不要刪。"]'),
('1f2160b4-946c-4dfb-8ee9-f87f002842eb','題梅山雲悅樓','李義山','宋','宋诗','song-poetry','','[]','雲本無心悅者誰，華陽去後少人知。',32,'全唐诗/poet.song.204000.json','["雲本無心悅者誰，華陽去後少人知。", "欲分半席無因到，一片飛來是覓詩。"]'),
('f4b10121-8008-45be-8291-011903c96300','毛竹','李義山','宋','宋诗','song-poetry','','["\u5199\u5c71", "\u63cf\u5199\u5c71"]','只得流霞送一杯，空中簫鼓當時回。',32,'全唐诗/poet.song.204000.json','["只得流霞送一杯，空中簫鼓當時回。", "武夷洞裏生毛竹，老盡曾孫更不來。"]'),
('54fac57d-f320-43cf-8a75-03f3b3bc6f17','青雲峰','李義山','宋','宋诗','song-poetry','','[]','瀛洲擬峴屢憑欄，不得江山四面看。',32,'全唐诗/poet.song.204000.json','["瀛洲擬峴屢憑欄，不得江山四面看。", "欲識青雲奇絕處，碧天無際裹峰巒。"]'),
('80a8099b-b375-458b-994e-8d649f32469c','白龍寺','靳更生','宋','宋诗','song-poetry','','[]','不怯山寒風力尖，要登絕頂看龍潛。',64,'全唐诗/poet.song.204000.json','["不怯山寒風力尖，要登絕頂看龍潛。", "翬飛傑閣雲穿棟，靜鎮禪關月滿簾。", "踏破松蘿容極目，嘯驚巖壑快軒髯。", "我來默印無邊義，寄與孤鈴語夜簷。"]'),
('3f5bd532-5c3f-407d-9965-0a33abbb46fd','李鹹谷歌','黄師參','宋','宋诗','song-poetry','','[]','李鹹谷，真詩人，無枝可棲雲水身。',160,'全唐诗/poet.song.204000.json','["李鹹谷，真詩人，無枝可棲雲水身。", "去年縣官爲架屋，纔有數枝堪寄宿。", "朝厨無烟眠正高，癡兒叫怒吟轉豪。", "人間六月盡絺服，獨著春衫凉自足。", "黄雞白酒東家留，西家欲留還住休。", "鑿池養魚未盈掌，有客過門須舉網。", "網收魚盡鏡奩空，菜羹作供尤春風。", "谷之山，窈復深，誰其友之紫芝民。", "谷之水，清且泚，誰其似之巢父耳。", "再拜號君鹹谷子，白頭結交從此始。"]'),
('d7f14a93-44b6-4577-bfad-2b5871bd36dd','過廬陵','黄師參','宋','宋诗','song-poetry','','[]','昔年樓迹處，今訪不知門。',48,'全唐诗/poet.song.204000.json','["昔年樓迹處，今訪不知門。", "華屋半塵土，故人餘子孫。", "少留誰共語，欲去轉銷魂。", "落日江樓望，江山空復存。"]'),
('a3e0fe55-7403-4be0-97f8-52fca1cfc6a9','詠懷','黄師參','宋','宋诗','song-poetry','','[]','南國有佳人，不數陰麗華。',60,'全唐诗/poet.song.204000.json','["南國有佳人，不數陰麗華。", "長年事絺葛，無語吟柳花。", "平生父母心，豈不願有家。", "紛紛輕薄兒，媒氏空自譁。", "失身死堪羞，失時未須嗟。"]'),
('62248412-6e95-4a7b-ae6c-f8ba4b06641b','小樓即事','黄師參','宋','宋诗','song-poetry','','[]','病起懶拈酒盞，衣單頓怯春寒。',28,'全唐诗/poet.song.204000.json','["病起懶拈酒盞，衣單頓怯春寒。", "獨把東坡詩卷，立殘西日闌干。"]'),
('5011a764-2d7a-4057-abd1-db0c5b1aad25','玉巖有感','黄師參','宋','宋诗','song-poetry','','[]','遊山苦無侶，獨行亦自佳。',144,'全唐诗/poet.song.204000.json','["遊山苦無侶，獨行亦自佳。", "不羨籃輿穩，軟草供蒲鞋。", "小僧倚門問，客從何處來。", "長嘯不復答，露坐面山隈。", "往謁玉岩翁，縞衣絕纖埃。", "祠宮蔽風雨，碑碣荒莓苔。", "四山壯幽閒，百感攖我懷。", "先生竟何之，山猿朝夕哀。", "出處非有意，於道相縈迴。", "翁看嶺表人，白骨漫成堆。", "所見明且哲，屢表乞歸骸。", "佇立三太息，歸思落日催。"]'),
('709cd57f-6949-415d-bc52-9655257c6a12','坡南塘','黄漢章','宋','宋诗','song-poetry','','[]','吁嗟從古行路難，長亭短日天風寒。',64,'全唐诗/poet.song.204000.json','["吁嗟從古行路難，長亭短日天風寒。", "舟膠馬隤憂欲死，朱門歌舞誰辦此。", "一朝邂逅滎陽君，首倡開土囊俱傾。", "五丁未具飯能幾，羣毛不集裘安成。"]'),
('6634f8f3-d5bb-4f2c-9cfc-f33441e1698d','倒插花巖','黄漢章','宋','宋诗','song-poetry','','[]','怪石膽瓶窟，從天倒插花。',24,'全唐诗/poet.song.204000.json','["怪石膽瓶窟，從天倒插花。", "九陽一樣澤，生意爲何差。"]'),
('687a965d-6bbb-4dc3-ada8-0a6fdee3a120','照膽臺','葉味道','宋','宋诗','song-poetry','','[]','一水磨銅鏡面寒，人心蔽錮可誰觀。',32,'全唐诗/poet.song.204000.json','["一水磨銅鏡面寒，人心蔽錮可誰觀。", "諸君顧影清潭裏，私曲分明見肺肝。"]'),
('2ea5db0c-42e5-4fb3-b13a-14a27c402f47','清溪曉行','秦噩','宋','宋诗','song-poetry','','[]','瀰瀰一溪水，滔滔終古清。',48,'全唐诗/poet.song.204000.json','["瀰瀰一溪水，滔滔終古清。", "晃漾吸初日，風靜波不生。", "衝烟出孤棹，微聞欵乃聲。", "寄言彼漁父，吾欲濯吾纓。"]'),
('ae05825e-d19c-4fe9-8d4e-1c21e8e9d02e','憩南臺寺','劉子澄','宋','宋诗','song-poetry','','[]','居塵等出家，涉世類行脚。',48,'全唐诗/poet.song.204000.json','["居塵等出家，涉世類行脚。", "岳靈招我隠，雨止雲亦閣。", "乾坤錦囊收，風月麈柄握。", "衆鳥各自鳴，豈礙沖霄鶴。"]'),
('03499ef8-649a-4e70-bc11-0d463950a967','蒙泉行呈張敬父','劉子澄','宋','宋诗','song-poetry','','[]','玉龍蟠向荆山麓，噴起雙泉冰雪瀑。',224,'全唐诗/poet.song.204000.json','["玉龍蟠向荆山麓，噴起雙泉冰雪瀑。", "琮琤萬古作寒鳴，冷浸一山渾是玉。", "泉旁樹老亦如龍，泉根石濯瑪瑙紅。", "更有金蓮吐泉底，歷歷星在銀潢中。", "池光六月如霜洗，藍橋倒影壺天裏。", "流下人間灌稻畦，歲歲家家飯雲子。", "我行荆州見山少，忽對林泉如久要。", "張侯引我飛羽觴，勸我爲泉開一笑。", "我歌數語泉應聞，茲山古號荆州門。", "英雄過者心在鹿，安得泉聲到耳根。", "曹瞞疾馳玄德懼，潘璋設伏雲長怒。", "早知成敗等丘墟，悔不解鞍學巢父。", "英雄何在水長流，閲盡英雄過未休。", "今日爲侯泉上醉，明朝西指鹿門遊。"]'),
('5f991361-c7df-4f6d-93e7-a67eb2a82e19','樅陽出陸','劉子澄','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','浮家無定日，仕在水雲鄉。',48,'全唐诗/poet.song.204000.json','["浮家無定日，仕在水雲鄉。", "棹別洞庭月，帆迎赤壁霜。", "早寒裘代葛，多病藥充糧。", "明日樅陽客，征鞍去路長。"]'),
('f83b6187-bbee-4751-a09a-c723ecfee03f','過鴻宿洲','劉子澄','宋','宋诗','song-poetry','','[]','洲名號鴻宿，流徙合來居。',48,'全唐诗/poet.song.204000.json','["洲名號鴻宿，流徙合來居。", "淮郡侵江密，人烟罩水疎。", "無山供笛竹，有港便罾魚。", "壯士休營業，功成返故廬。"]'),
('0c3047df-454f-4782-9da3-2901680ffc3e','遊石門縣層山流杯亭觀卓錫泉','劉子澄','宋','宋诗','song-poetry','','[]','寺惟泉最古，有詠載州圖。',48,'全唐诗/poet.song.204000.json','["寺惟泉最古，有詠載州圖。", "幾度流觴了，長如卓錫初。", "楚山閩老住，隋柏宋朝枯。", "雨後人耕急，荒岡带月鋤。"]'),
('f2b05236-ed54-4b60-aa4b-b5fa173fbb6d','董宰見和用韻留別','劉子澄','宋','宋诗','song-poetry','','[]','謾辱君相送，我行非壯圖。',48,'全唐诗/poet.song.204000.json','["謾辱君相送，我行非壯圖。", "客程來又去，人事久如初。", "句淡僧能和，泉靈旱不枯。", "升高莫怨險，世路爾能鋤。"]'),
('eb42f943-6b1d-47a8-9e9c-ce2f17d6b10d','武陵別任年魁','劉子澄','宋','宋诗','song-poetry','','[]','詔書應在道，君但趣行裝。',48,'全唐诗/poet.song.204000.json','["詔書應在道，君但趣行裝。", "去棹乘桃漲，朝衣带芷香。", "歸齋尋舊話，上殿拜新皇。", "論事依經好，平遷是玉堂。"]'),
('3f054cd8-9833-4434-b393-87631ba0a0e3','壽星寺江湖偉觀','劉子澄','宋','宋诗','song-poetry','','[]','豈不近京都，紅塵此地無。',48,'全唐诗/poet.song.204000.json','["豈不近京都，紅塵此地無。", "吳山青似越，江水白於湖。", "天接帆邊海，烟生樹外晡。", "危欄僧共倚，莫恨旅懷孤。"]'),
('5e8f24b9-8b0c-4cdb-939e-90c0c8612ee0','會真觀水簾','劉子澄','宋','宋诗','song-poetry','','[]','觀近朱陵萃列真，烟霞雖僻境長春。',64,'全唐诗/poet.song.204000.json','["觀近朱陵萃列真，烟霞雖僻境長春。", "若非火府煉神處，安用水簾遮世塵。", "古像著靈多是石，補鍾留跡似非人。", "尋源亦有桃花澗，莫是山山可避秦。"]'),
('68eee6d1-35f5-4802-bdad-e76a0e2e66a4','厲漕飲別海棠下索詩  其一','劉子澄','宋','宋诗','song-poetry','','[]','天然翠袖隠豐肌，好是胭脂未透時。',64,'全唐诗/poet.song.204000.json','["天然翠袖隠豐肌，好是胭脂未透時。", "夜睡無香供蝶夢，晨粧有恨只鶑知。", "坡仙具眼猶燒燭，子美多情却欠詩。", "料得錦城花正好，怨公底事訪春遲。"]'),
('69bd4938-8b2a-48ce-bde9-fcaf16f99abc','厲漕飲別海棠下索詩  其二','劉子澄','宋','宋诗','song-poetry','','[]','著雨胭脂沁玉肌，絕疑妃子醉眠時。',64,'全唐诗/poet.song.204000.json','["著雨胭脂沁玉肌，絕疑妃子醉眠時。", "未邀佳客閒來賞，已怪遊蜂早得知。", "燒燭不妨循故事，卷紗何惜賦新詩。", "羨君立就花前句，我欲賡吟思苦遲。"]'),
('02aea9b1-96ae-4a12-ae38-c2c798bd2525','雲峰寺詩','劉子澄','宋','宋诗','song-poetry','','[]','治水神書在此祁，溪名猶似念胼胝。',64,'全唐诗/poet.song.204000.json','["治水神書在此祁，溪名猶似念胼胝。", "當時民墊頼誰力，今日地平惟佛祠。", "泉出玉牀疏作乳，火生丹窖結成芝。", "雲峰自有樵人徑，岣嶁尋碑誤退之。"]'),
('616d45b0-ad32-4897-aae6-ad6dcc2d9560','遊岳麓宮抱黄洞','劉子澄','宋','宋诗','song-poetry','','[]','連天七十二雲屏，真境先於翠麓呈。',64,'全唐诗/poet.song.204000.json','["連天七十二雲屏，真境先於翠麓呈。", "洞發金光丹氣結，泉疏乳白玉華生。", "江心雁影重臨字，谷口禽呼自答名。", "閒步不教方外覺，破烟雙鶴已來迎。"]'),
('fe143872-e5f6-4cea-9253-c489ad480982','雲中寺','劉子澄','宋','宋诗','song-poetry','','[]','地僻層雲巋古禪，我來訪古尚依然。',64,'全唐诗/poet.song.204000.json','["地僻層雲巋古禪，我來訪古尚依然。", "越人重見流觴水，隋剎猶存卓錫泉。", "石罅遺題思往蹟，巖隈紀事憶前賢。", "可人不爲時摩拂，朝暮青山一抹烟。"]'),
('d348941d-71db-4f64-8cb8-f9aa86a0cbbf','登祝融宿上封寺詩','劉子澄','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','祝融尊與岱宗齊，仙境今容佛屋依。',64,'全唐诗/poet.song.204000.json','["祝融尊與岱宗齊，仙境今容佛屋依。", "曉揖日輪知海窄，夜捫星軫覺天低。", "風高殿悉杉爲瓦，雲冷僧常綿作衣。", "莫剪光天壇下草，時巡要秣六龍嘶。"]'),
('e32b9b56-1fcb-4c70-bb4c-b5f8a3cdfd51','江陵逢黄虛舟','劉子澄','宋','宋诗','song-poetry','','[]','山谷機忘似白鷗，有孫今復號虛舟。',64,'全唐诗/poet.song.204000.json','["山谷機忘似白鷗，有孫今復號虛舟。", "信風爲棹先開浪，與月同艙不載愁。", "吟就自將歌欵乃，醉時寧逐境漂流。", "乾坤等是虛舟爾，只好和詩莫带休。"]'),
('a472ad85-e086-4889-801e-14d4c751cca5','和張功曹清明之什','劉子澄','宋','宋诗','song-poetry','','[]','蘭江無物可關情，春去春來感亦生。',64,'全唐诗/poet.song.204000.json','["蘭江無物可關情，春去春來感亦生。", "流水幾番供禊事，新烟兩度過清明。", "念鄉鵑淚和花滴，懷友鶑腸學柳縈。", "讀遍離騷詩自慰，世間無地不蠻荆。"]'),
('bff23aab-c605-4b3d-a4ce-59d3ad62af1b','和賈秋壑南樓韻','劉子澄','宋','宋诗','song-poetry','','[]','大別磯頭江漢合，烟波堪詠亦堪圖。',64,'全唐诗/poet.song.204000.json','["大別磯頭江漢合，烟波堪詠亦堪圖。", "山標禹貢他州有，水列周南到處無。", "鶴外聲來蘄笛遠，鴻邊影落楚帆孤。", "登臨此地陪秋壑，收拾乾坤寘玉壺。"]'),
('9aa2a1c4-8a5d-4ef5-adf3-46a832996576','過金陵總卿吳履齋以詩贈別用謝','劉子澄','宋','宋诗','song-poetry','','[]','六朝三百有餘期，不滿詩人一皺眉。',64,'全唐诗/poet.song.204000.json','["六朝三百有餘期，不滿詩人一皺眉。", "只有燕迷新巷陌，更無鳳集古臺基。", "兵於史傳多陳迹，酒與江山是己知。", "僕指長淮又西去，輿圖向後更誰披。"]'),
('2e016df3-383e-4415-b0e4-a9a3a306b5da','哭趙南仲','劉子澄','宋','宋诗','song-poetry','','[]','功名翻覆等南柯，雲掩新阡長薜蘿。',64,'全唐诗/poet.song.204000.json','["功名翻覆等南柯，雲掩新阡長薜蘿。", "千載只憑公論去，百年無奈世情何。", "高光時節經營易，晉宋人才隠逸多。", "入汴老賓猶坐謫，餘生只合理煙蓑。"]'),
('d93b651e-03ce-4f7c-8487-98d95e8f2842','過洞庭','劉子澄','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','波神有兆報平安，半日重湖度不難。',64,'全唐诗/poet.song.204000.json','["波神有兆報平安，半日重湖度不難。", "隻艇泝洄風浪息，單包就謫水雲寬。", "曉烟不隔漁歌過，秋月還同畫軸看。", "擺脫塵緣天借便，嶷雲深處養神丹。"]'),
('519d12d7-6252-442e-8e18-feb3ffa2e540','會飲西湖聞黄浦捷用余制幹韻','劉子澄','宋','宋诗','song-poetry','','["\u897f\u6e56"]','湖邊重度夏，風物恍如初。',48,'全唐诗/poet.song.204000.json','["湖邊重度夏，風物恍如初。", "竹喜兒孫密，花憐姊妹疎。", "小舟逢寺泊，淡句欠僧書。", "此樂何從得，淮堧報賊除。"]'),
('b1ccfd48-8026-41d3-a5a4-3bc8e96363a8','澧州群賢堂記並歌  其一','劉子澄','宋','宋诗','song-poetry','','[]','主辱兮忘家，國安兮親寧。',44,'全唐诗/poet.song.204000.json','["主辱兮忘家，國安兮親寧。", "奈何有軀兮而焉自形，寧隕絕兮無生。", "望蒼穹兮痛徹，君精誠兮爲列星。"]'),
('d14465b9-1048-46a7-8446-10b38f783f9b','澧州群賢堂記並歌  其二','劉子澄','宋','宋诗','song-poetry','','[]','蕙肴兮椒漿，歷芳蕪兮薦君堂。',44,'全唐诗/poet.song.204000.json','["蕙肴兮椒漿，歷芳蕪兮薦君堂。", "君不來兮予愁，渺貝宮兮誰留。", "高丘之人兮爲君妬，聊澧浦兮消遥。"]'),
('d8559da0-39d8-4bcf-8556-0903cb2869f2','澧州群賢堂記並歌  其三','劉子澄','宋','宋诗','song-poetry','','[]','熠耀兮高明，讀經兮漱芳。',42,'全唐诗/poet.song.204000.json','["熠耀兮高明，讀經兮漱芳。", "仕不辰兮經以不信，蹇道直兮難行。", "人心險兮劍戟，公歸來兮故鄉。"]'),
('64f4bf21-6f94-4303-9285-772c0d132546','澧州群賢堂記並歌  其四','劉子澄','宋','宋诗','song-poetry','','[]','陰凝陽兮血塗野，臣力微兮肝膽怒。',62,'全唐诗/poet.song.204000.json','["陰凝陽兮血塗野，臣力微兮肝膽怒。", "睨階庭兮激諸子，往間道兮戴盟主。", "陳志誠兮冠期舉，事危就兮天弗假。", "天高兮蒼蒼，君柰何兮歸來雙。"]'),
('8f8265cb-952a-4829-80a1-c4a69070313d','澧州群賢堂記並歌  其五','劉子澄','宋','宋诗','song-poetry','','[]','蘭之江兮有洲，環堵兮蘭幽。',39,'全唐诗/poet.song.204000.json','["蘭之江兮有洲，環堵兮蘭幽。", "胡獨微兮臺閣，留不歸兮焉求。", "詠歌兮卒歲，名與兮江流。"]'),
('fd710dcb-6a16-4e72-8317-2ebe615cdad3','澧州群賢堂記並歌  其六','劉子澄','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','酌水兮澧清，酹月兮洞庭。',41,'全唐诗/poet.song.204000.json','["酌水兮澧清，酹月兮洞庭。", "公讀書兮湖上堂，波濤卷兮胸中甲兵。", "浩然兮長在，烟水兮茫茫。"]'),
('679e7d3d-f8ff-4512-9481-de25c9339aca','澧州群賢堂記並歌  其七','劉子澄','宋','宋诗','song-poetry','','[]','鶴書賁兮林丘，假截徑兮予羞。',41,'全唐诗/poet.song.204000.json','["鶴書賁兮林丘，假截徑兮予羞。", "曳杖兮長歌，清風賓兮明月友。", "雲山兮未改，羌何日兮公遊。"]'),
('bfd14d55-520d-4cda-87e4-f4811480a57c','遊層巖','劉子澄','宋','宋诗','song-poetry','','[]','一層雲結一層巔，貫腹成溪異物潛。',64,'全唐诗/poet.song.204000.json','["一層雲結一層巔，貫腹成溪異物潛。", "仙樂萬懸鐘有乳，洞門百折水爲簾。", "崖碑蘚暗瑰辭缺，石棧苔闌羽衛嚴。", "我欲通天刳絕頂，倒飛明月浴寒蟾。"]'),
('30863818-2116-4632-97e1-434f45e84836','讀書臺','劉子澄','宋','宋诗','song-poetry','','[]','安鄉古下邑，公偶混迹居。',120,'全唐诗/poet.song.204000.json','["安鄉古下邑，公偶混迹居。", "編茅閲古今，清澄涔澧潴。", "波濤入胸中，萬甲時卷舒。", "坐吞八九澤，去作宋真儒。", "西師出緒餘，膽已寒氈廬。", "軍中但歌范，誰識舊陶朱。", "大賢方窮時，隠憂在江湖。", "功成等糟粕，况復堂上書。", "我來拜遺像，悲風生黄壚。", "公今倘無死，此地正堪娛。"]'),
('b7485b1b-22d4-42b8-8d37-07fea21c0199','句  其一','劉子澄','宋','宋诗','song-poetry','','[]','世間此物多爲馬，寶劍還宜出上方。',16,'全唐诗/poet.song.204000.json','["世間此物多爲馬，寶劍還宜出上方。"]'),
('99da0ee2-72ad-4f23-9374-462331772cbe','句  其二','劉子澄','宋','宋诗','song-poetry','','[]','自怪神仙騎白鳳，不教天地點青蠅。',16,'全唐诗/poet.song.204000.json','["自怪神仙騎白鳳，不教天地點青蠅。"]'),
('ccef46d8-7873-47d8-9d17-6c13aa0c9a1e','淳祐七年丁未十一月朔蔡久軒自江東提刑歸抵家時三館諸公以風霜隨氣節河漢下文章分韻賦詩送別得節字','陳協','宋','宋诗','song-poetry','','[]','賈生陳治安，難與絳灌列。',156,'全唐诗/poet.song.204000.json','["賈生陳治安，難與絳灌列。", "汲黯觸公卿，不得補遺闕。", "直道非身謀，古今同一轍。", "吾觀蔡子賢，木訥有志節。", "道山得良友，同舍顔色悅。", "家學傳考亭，議論接賢哲。", "塵汙具瞻地，兩疏憤激切。", "當宁垂寬容，在庭競稱說。", "屢章丐投閑，一節往司臬。", "獄情貴平反，人物宜區別。", "要令大江東，精彩與昔別。", "君誠給諫姿，上恩詎輕絕。", "即當宣室對，忠言合稷契。"]'),
('f898cfa5-b400-4761-b2e5-ceb03668c1dd','題湘湖','姜應龍','宋','宋诗','song-poetry','','[]','世路羊腸淹客遊，塵纓來此濯清流。',64,'全唐诗/poet.song.204000.json','["世路羊腸淹客遊，塵纓來此濯清流。", "半窗修竹翠含雨，一片澄湖冷浸秋。", "地僻莓苔侵石几，機忘鷗鷺近漁舟。", "夜凉酒醒未能睡，詩句欲成搔白頭。"]'),
('b429c662-e02c-4d6f-9edd-697327d1b7b1','清都臺','曾鎬','宋','宋诗','song-poetry','','[]','兀坐豈不佳，偶出亦良適。',96,'全唐诗/poet.song.204000.json','["兀坐豈不佳，偶出亦良適。", "高臺挹清曠，况此好風日。", "俯憐波面浄，仰愛松身直。", "灑落萬古秋，飛鳥度晴碧。", "徘徊足瞻眺，蕭散謝羈馽。", "浮生眇塵端，一醉不易得。", "古人豈其遠，千載猶宿昔。", "清風何寥寥，愧此臺上石。"]'),
('a36e8537-4746-4ce9-9a95-653e8da13d30','賞心亭','王埜','宋','宋诗','song-poetry','','[]','物華盡入錦囊收，留與江山做話頭。',64,'全唐诗/poet.song.204000.json','["物華盡入錦囊收，留與江山做話頭。", "桃葉數聲風力晚，蘆花萬頃月波秋。", "非尋鶴相當年畫，誰記坡仙舊日游。", "回首興亡多少事，漁舟獨不掛閑愁。"]'),
('7ffa1fda-199f-40a3-b1f5-ef670c79fa66','翠微亭','王埜','宋','宋诗','song-poetry','','[]','虛亭北眺大江臨，江外晴嵐出寸岑。',64,'全唐诗/poet.song.204000.json','["虛亭北眺大江臨，江外晴嵐出寸岑。", "景與齊山俱絕唱，量如滄海且頻斟。", "地高宇宙雙眸豁，人老風霜兩鬢侵。", "感慨石城勳業舊，侃居夏口嶠居深。"]'),
('feaab799-2388-41ce-8173-c47428d7b0d9','題凝神菴','王埜','宋','宋诗','song-poetry','','[]','拋却林泉趣，卓菴臨近村。',48,'全唐诗/poet.song.204000.json','["拋却林泉趣，卓菴臨近村。", "兩窗吞日月，一室養乾坤。", "菊露秋籬重，松風午枕喧。", "蒲團數胎息，不肯學傍門。"]'),
('886d9c54-f6ec-4ce1-8c80-d087a1292159','登靈鷲興聖寺','王埜','宋','宋诗','song-poetry','','[]','山從西域來，寺自東南有。',96,'全唐诗/poet.song.204000.json','["山從西域來，寺自東南有。", "林泉既奇秀，巖穴更深黝。", "世僧奮空弮，經始不已久。", "俄然幻傑閣，丹碧照林藪。", "相輝靈隠前，更勝天竺後。", "理公坐崖屋，千歲骨已朽。", "坡翁昔曾遊，遺句今在否。", "洞猿不待呼，清晝時一吼。"]'),
('883f270d-88ae-47b4-8511-6973c301c3c9','楊柳','王埜','宋','宋诗','song-poetry','','[]','雨重垂楊綠未乾，一渠流碧弄潺潺。',32,'全唐诗/poet.song.204000.json','["雨重垂楊綠未乾，一渠流碧弄潺潺。", "暝鴉過盡東風惡，獨倚衡門看遠山。"]'),
('260f4441-56a9-49e3-88ce-801b15c5b218','清明日游鶴林寺  其一','王埜','宋','宋诗','song-poetry','','[]','蒿目黄塵擾擾間，出門偶到鶴林山。',32,'全唐诗/poet.song.204000.json','["蒿目黄塵擾擾間，出門偶到鶴林山。", "仙花僧竹俱陳迹，白日青天祇自閑。"]'),
('11e2f885-0682-45da-84ea-7b637176f010','清明日游鶴林寺  其二','王埜','宋','宋诗','song-poetry','','[]','竹院閑來春正遲，籜龍猶自有孫枝。',32,'全唐诗/poet.song.204000.json','["竹院閑來春正遲，籜龍猶自有孫枝。", "野夫豈識尋芳意，爲愛光風面面吹。"]'),
('bc6f4ab9-fb73-4be4-89a6-7e8b4dc90fcc','寄趙章泉','王埜','宋','宋诗','song-poetry','','[]','冷笑申公老漢班，不成一事又空還。',64,'全唐诗/poet.song.204000.json','["冷笑申公老漢班，不成一事又空還。", "與其零雨難蘇物，孰若爲雲只在山。", "庭草靜涵春意足，野瓢休掛樹陰閑。", "多應糞土看榮貴，留得清風宇宙間。"]'),
('2bb162b0-8768-40e7-982e-4d9bb736affe','壽千億','王埜','宋','宋诗','song-poetry','','[]','三十六洞天下奇，三十六峰名武夷。',375,'全唐诗/poet.song.204000.json','["三十六洞天下奇，三十六峰名武夷。", "武夷山中溪九曲，曲曲瀉出清漣漪。", "溪南溪北山對立，拔地插天幾千尺。", "或如丹砂丹，或如碧玉碧。", "東望開樓臺，南顧儼城壁。", "廩庾積其西，車蓋列其北。", "磊磊落落不可名，怪怪奇奇神所刻。", "草木不移寒暑心，巖巒長带煙霞色。", "太玄姥，武夷君，幔亭虹橋凌紫雲。", "曾孫宴罷桑海變，長琴短鼓空紛紛。", "魏公子，張真人，嗜酒一謫八百春。", "功成白日生羽翼，巔崖靈蛻猶如新。", "我欲冥搜極幽遠，櫂船朝去暮忘返。", "峰迴嶂合忽復迷，安得飛梯宿雲巘。", "鸞鶴去兮猿猱啼，恍空中兮聞金鷄。", "石嚙足兮濺濺，風吹衣兮淒淒，洄洑縈折。", "谽谺崔嵬，石堂真館豁然而中開。", "壑舟不墜棧不朽，至今藥爐丹鼎髣髴千仞之層崖。", "目亦不能盡，心亦不能惻。", "桃源風景未復見，柯山日月難重得。", "鼓余枻兮潺湲，乘驚波兮下前灘。", "瞬息兮回首，失向來兮巑岏。", "嗚呼，列仙高拱兮宅玄都，二聖繼御兮恢炎圖。", "措斯世於平乂，應皇家兮瑶符。"]'),
('11bea82c-e2ae-4737-b1a1-0f84d0409a8a','上霄洞','王埜','宋','宋诗','song-poetry','','[]','吾聞北山陽，巖壑寶相竅。',288,'全唐诗/poet.song.204000.json','["吾聞北山陽，巖壑寶相竅。", "何年開鴻濛，隨地通窔奧。", "朝真高難攀，冰壺深莫料。", "詭怪者雙龍，崖室最蒼峭。", "上霄雖晚出，煙霞寄孤嶠。", "尋源陟空山，訪仙款遺廟。", "始探頗褊窄，稍入亦窈窕。", "上穴由梯升，傍穿須火照。", "青厂既鬰鬰，白乳仍皭皭。", "旁通多曲折，幽眇轉奇妙。", "窮探豈不欲，所畏自微爝。", "昏昏蝙蝠飛，悄悄鼪鼯叫。", "或疑洞靈出，或恐山鬼嘯。", "又聞村中氓，鑿石供灰燒。", "俄然得深竇，傾城盡登眺。", "何人不好事，窒塞迷其要。", "此雖幸獨存，荒僻委蓬藋。", "儻移傍京邑，車馬日號召。", "了知神仙事，茫昧不堪弔。", "豈無隠淪士，巖築像惟肖。", "畬田沃可耕，澗水清可釣。", "平生愛泉石，自謂饑可療。", "喜茲近吾隠，來往足談笑。", "此意復誰論，行行逢荷篠。"]'),
('202917e6-0521-4db0-a313-5a4683c869d0','句  其一','王埜','宋','宋诗','song-poetry','','[]','輕霜臨菊月，細雨似梅天。',12,'全唐诗/poet.song.204000.json','["輕霜臨菊月，細雨似梅天。"]'),
('cea243ac-e4d5-4122-955c-8d3d67bc36d5','句  其二','王埜','宋','宋诗','song-poetry','','[]','莫道春隨風雨過，化工昨夜到桑麻。',16,'全唐诗/poet.song.204000.json','["莫道春隨風雨過，化工昨夜到桑麻。"]'),
('af335ebc-a27d-4a9d-83a9-3e838ad16f6a','秦皇廟','常棠','宋','宋诗','song-poetry','','[]','古廟三間矮棘叢，帝魂枉自氣凌空。',32,'全唐诗/poet.song.204000.json','["古廟三間矮棘叢，帝魂枉自氣凌空。", "早知今日容身窄，前此阿房不作宮。"]'),
('7a7d6036-3c76-4133-be66-ea0d1026ff16','花婆井','常棠','宋','宋诗','song-poetry','','[]','一灣秋月浸香痕，滌盡山前萬古塵。',32,'全唐诗/poet.song.204000.json','["一灣秋月浸香痕，滌盡山前萬古塵。", "猶記當時老梳洗，淡粧明鏡照眉顰。"]'),
('3cc30263-2b2f-4888-927a-f69055095ca4','次王元吉詠梅','高鵬飛','宋','宋诗','song-poetry','','[]','約略陽和動琯灰，南枝已冠百花魁。',64,'全唐诗/poet.song.204000.json','["約略陽和動琯灰，南枝已冠百花魁。", "莫教隴驛携春去，且向羅浮喚夢回。", "玉骨風標自仙種，鐵腸賦詠謾多才。", "只應賸結青青子，調鼎功夫看後來。"]'),
('b6e0e365-7225-4b1d-818b-188c791775dc','窗軒','高鵬飛','宋','宋诗','song-poetry','','[]','一窗開永晝，萬象出天成。',48,'全唐诗/poet.song.204000.json','["一窗開永晝，萬象出天成。", "風力欺楊絮，雷聲喚笋萌。", "愁多春不願，病起眼猶明。", "最喜今朝雨，川原足暮耕。"]'),
('c33eafa2-47d2-42df-918d-ffb557dbd9bf','過王氏雲莊','高鵬飛','宋','宋诗','song-poetry','','[]','十里雲莊路，東風信杖藜。',48,'全唐诗/poet.song.204000.json','["十里雲莊路，東風信杖藜。", "好花連夜發，幽鳥傍人啼。", "香宇禪心冷，山容醉眼迷。", "老僧春睡處，明月印樓西。"]'),
('b9be73fb-b1b7-42f1-a63a-6b1640c0d673','孤吟','高鵬飛','宋','宋诗','song-poetry','','[]','世景雲來去，人情水淺深。',48,'全唐诗/poet.song.204000.json','["世景雲來去，人情水淺深。", "塵埃從滿眼，交友欲知心。", "山簡豈愛酒，陶潛元解琴。", "對人不敢語，仰面數歸禽。"]'),
('5f991fe8-9cc6-45b5-b2c8-b789a577c2f9','深夜風雨有懷故人','高鵬飛','宋','宋诗','song-poetry','','[]','心馳流水高山外，身在落花啼鳥中。',64,'全唐诗/poet.song.204000.json','["心馳流水高山外，身在落花啼鳥中。", "滴得愁濃青杏雨，吹教夢斷碧梧風。", "垂堂遠愧千金子，掃地空憐一畝宮。", "兩朵燈花伴孤獨，清懽那得玉人同。"]'),
('09e5b3ca-728b-41dd-a745-4f45006e9b4f','首夏','高鵬飛','宋','宋诗','song-poetry','','[]','千里辭家不作難，歸來春事總闌珊。',64,'全唐诗/poet.song.204000.json','["千里辭家不作難，歸來春事總闌珊。", "久留午夢梅黄雨，重索冬衣麥秀寒。", "百箔老蠶鋪雪乳，一庭新竹長琅玕。", "此時正喜民財阜，野草閒花任自殘。"]'),
('1773b168-7bae-4628-9193-33395592a00b','湖上','高鵬飛','宋','宋诗','song-poetry','','[]','舟載閒雲穩，湖光盪碧天。',24,'全唐诗/poet.song.204000.json','["舟載閒雲穩，湖光盪碧天。", "笑看沙上鳥，終日伴雛眠。"]'),
('ef1cd844-c705-4d5a-841e-01b7fa18cbd2','深夜獨步思兄南伯舉杯扣門則卧矣','高鵬飛','宋','宋诗','song-poetry','','[]','綠柳橋邊古道橫，乾坤寂寂夜三更。',64,'全唐诗/poet.song.204000.json','["綠柳橋邊古道橫，乾坤寂寂夜三更。", "月窺門處君高卧，露溼衣時夜獨行。", "杯酒孰同驅俗意，天風時下步虛聲。", "明朝世界塵依舊，試挽銀河一洗清。"]'),
('4ca7c814-7699-4956-af14-be7fd7962c96','丈亭渡阻風','高鵬飛','宋','宋诗','song-poetry','','[]','捲地西風翻巨浪，小舟仍泊夜來灣。',64,'全唐诗/poet.song.204000.json','["捲地西風翻巨浪，小舟仍泊夜來灣。", "行沽携榼雖無酒，卧看開篷幸有山。", "原草正肥黄犢飽，汀蘋未老白鷗閒。", "平生遇險須知止，眼對江神一解顔。"]'),
('392806d9-0230-4ab3-a133-b48bb725c9e9','湖上','高鵬飛','宋','宋诗','song-poetry','','[]','好景難逢奈老何，十年此地絕經過。',64,'全唐诗/poet.song.204000.json','["好景難逢奈老何，十年此地絕經過。", "山如得意晚猶碧，雨亦知愁秋更多。", "造化從渠旋磨蟻，功名笑汝撲燈蛾。", "湖邊直欲呼船去，更共漁人掛綠蓑。"]'),
('846e3541-0956-426c-9da9-a540930d7529','晚興','高鵬飛','宋','宋诗','song-poetry','','[]','風靜湖光一鑑浮，青山四顧淡舒秋。',32,'全唐诗/poet.song.204000.json','["風靜湖光一鑑浮，青山四顧淡舒秋。", "松陰滿逕歸來晚，醉看巖花笑白頭。"]'),
('265157cb-f11d-4955-bbae-b8d4c11aab89','夜渡鄞江','高鵬飛','宋','宋诗','song-poetry','','[]','睡起開篷月在沙，晚江山影動龍蛇。',64,'全唐诗/poet.song.204000.json','["睡起開篷月在沙，晚江山影動龍蛇。", "詩成索筆無人應，酒盡空囊何處賒。", "船去船來數聲櫓，江南江北幾人家。", "星娥定怪歸來晚，從此西風欲泛槎。"]'),
('96d64bed-d7f7-4903-b633-8ff1a39764a0','南溪','高鵬飛','宋','宋诗','song-poetry','','[]','聞說南溪好，肩車带雨來。',48,'全唐诗/poet.song.204000.json','["聞說南溪好，肩車带雨來。", "澗泉鳴細石，松木衣蒼苔。", "雲笑人情薄，山隨客語回。", "黄花幽意足，知復爲誰開。"]'),
('c5ca8ca4-2475-4f30-9e7b-0cce60eb66f3','次靜海令蓋晞之食蟹','高鵬飛','宋','宋诗','song-poetry','','[]','吳中郭索聲價高，草泥足上生青毛。',64,'全唐诗/poet.song.204000.json','["吳中郭索聲價高，草泥足上生青毛。", "越中海市喧兒曹，白蟹厭飫霜前螯。", "新豐逆旅酒濯足，齊國相君飯脫粟。", "當時珍味無所需，吳越土宜俱碌碌。"]'),
('e3dfb0b6-e576-4c99-9cb3-8d9f133f4b81','復遊鄞江','高鵬飛','宋','宋诗','song-poetry','','[]','欲扣山扉汲野泉，支筇眼駐柳陰邊。',64,'全唐诗/poet.song.204000.json','["欲扣山扉汲野泉，支筇眼駐柳陰邊。", "苦無平地休穿屐，待有輕風却放船。", "孤笛叫開雲裏月，一竿撐破水中天。", "舟人相戒低聲語，沙上恐驚鷗鷺眠。"]'),
('d78a935b-d5c3-495f-bb55-a53b3b67eba1','次孫燭湖秋夜有感','高鵬飛','宋','宋诗','song-poetry','','[]','忽作清宵夢，非關世累長。',48,'全唐诗/poet.song.204000.json','["忽作清宵夢，非關世累長。", "月隨花影轉，水照木陰凉。", "浴露千峰碧，梳風兩鬢蒼。", "明朝須洗耳，秋意過寒螿。"]'),
('5162c144-ec42-41ee-a43a-c5213d10f297','舟中  其一','高鵬飛','宋','宋诗','song-poetry','','[]','木落山高秋去後，犬驚人語夜深時。',32,'全唐诗/poet.song.204000.json','["木落山高秋去後，犬驚人語夜深時。", "小舟滿載離愁重，惟有孤鳴寒雁知。"]'),
('3ad9947f-0661-4783-aad6-12381778ced6','舟中  其二','高鵬飛','宋','宋诗','song-poetry','','[]','一水分流無限曲，兩山相對不知名。',32,'全唐诗/poet.song.204000.json','["一水分流無限曲，兩山相對不知名。", "漁翁夜半歸南陌，認作中流擊楫聲。"]'),
('8501c13c-749b-470c-a855-261f2a4315f9','秋晚','高鵬飛','宋','宋诗','song-poetry','','[]','斷雲送歸雁，斜陽明晚楓。',24,'全唐诗/poet.song.204000.json','["斷雲送歸雁，斜陽明晚楓。", "西風灑雙鬢，醉倚危闌東。"]'),
('1a9a5775-76a2-4e62-ae1f-b7c407ae4481','春閨怨','吳惟信','宋','宋诗','song-poetry','','[]','細柳輕煙鎖畫樓，樓中人去水長流。',32,'全唐诗/poet.song.204000.json','["細柳輕煙鎖畫樓，樓中人去水長流。", "琵琶聲斷梅花落，別是春風一種愁。"]'),
('91f2593c-b233-4f2a-b0dd-3ed51e06275d','蘇堤清明即事','吳惟信','宋','宋诗','song-poetry','','["\u6e05\u660e\u8282", "\u6e05\u660e", "\u5199\u666f", "\u6625\u6e38"]','梨花風起正清明，遊子尋春半出城。',32,'全唐诗/poet.song.204000.json','["梨花風起正清明，遊子尋春半出城。", "日暮笙歌收拾去，萬株楊柳屬流鶑。"]'),
('debd5764-cc2f-447a-bd51-458c344e4422','湖上雨吟','吳惟信','宋','宋诗','song-poetry','','[]','濕了荷花雨便休，晚風歸柳澹於秋。',32,'全唐诗/poet.song.204000.json','["濕了荷花雨便休，晚風歸柳澹於秋。", "一生不作機心事，合轉船頭向白鷗。"]'),
('fc5849c7-d346-4d9d-a483-fae85464c95e','雨後','吳惟信','宋','宋诗','song-poetry','','[]','雨後輕雲學水流，惜春人瘦怕春休。',32,'全唐诗/poet.song.204000.json','["雨後輕雲學水流，惜春人瘦怕春休。", "梨花却恐難尋夢，燕子何曾細說愁。"]'),
('0eba2fa8-19da-4e64-a71f-474f5c7a6517','賀史守鳳雛滿月','吳惟信','宋','宋诗','song-poetry','','[]','玉手歌姬托鳳雛，堂前畫額旋調朱。',32,'全唐诗/poet.song.204000.json','["玉手歌姬托鳳雛，堂前畫額旋調朱。", "春風吳會宜男草，試問他人種得無。"]'),
('babbc8af-f6a4-41b8-8ce9-0462a83a6f98','寄東畎曹侍郎','吳惟信','宋','宋诗','song-poetry','','[]','結網求魚事已遲，却非春草不歸詩。',32,'全唐诗/poet.song.204000.json','["結網求魚事已遲，却非春草不歸詩。", "斜陽一片山如畫，更把心期付與誰。"]'),
('8cdbce00-abf7-4ae4-b480-5ac99b8c75b0','題秋江晚照圖','吳惟信','宋','宋诗','song-poetry','','[]','水光只肯浄涵虛，分浦通村路却無。',32,'全唐诗/poet.song.204000.json','["水光只肯浄涵虛，分浦通村路却無。", "風日向低鴻雁落，釣竿一半出菰蒲。"]'),
('65b27f17-458f-4a43-a02a-76f4ded4efa6','曉吟','吳惟信','宋','宋诗','song-poetry','','[]','翠帳香消捲碧紗，風捎殘雨濕欄牙。',32,'全唐诗/poet.song.204000.json','["翠帳香消捲碧紗，風捎殘雨濕欄牙。", "蜻蜓亦被凉勾引，清曉低飛入水花。"]'),
('fc0fd174-ec2e-4cb9-b0f7-34debace1c3b','春詠','吳惟信','宋','宋诗','song-poetry','','[]','草堂燕子未歸時，香鼎灰飛入硯池。',32,'全唐诗/poet.song.204000.json','["草堂燕子未歸時，香鼎灰飛入硯池。", "看徹唐人詩一卷，夕陽猶在杏花枝。"]'),
('102fcd31-e8a0-4e0b-a01a-88412ab85485','贈別上官良史','吳惟信','宋','宋诗','song-poetry','','[]','不惜黄金一醉君，喚歌催舞語紛紛。',32,'全唐诗/poet.song.204000.json','["不惜黄金一醉君，喚歌催舞語紛紛。", "天涯明月空相憶，寒雁無聲入斷雲。"]'),
('eae62f49-c78f-4108-a21d-f283e6ab0368','秋夕','吳惟信','宋','宋诗','song-poetry','','[]','西風吹露下秋空，烏鵲無聲占碧桐。',32,'全唐诗/poet.song.204000.json','["西風吹露下秋空，烏鵲無聲占碧桐。", "天氣微凉人好睡，闌干閑在月明中。"]'),
('ecdfe146-7541-4730-8b38-ff3c291065af','野望','吳惟信','宋','宋诗','song-poetry','','[]','閑與蘆花立水邊，歸心客思兩茫然。',32,'全唐诗/poet.song.204000.json','["閑與蘆花立水邊，歸心客思兩茫然。", "夕陽收盡天風急，一樹寒鴉落野田。"]'),
('48349048-4c80-44f1-8a8f-7aec580054f0','辭史侍郎','吳惟信','宋','宋诗','song-poetry','','[]','事到依人易策勳，合歸收拾北山雲。',32,'全唐诗/poet.song.204000.json','["事到依人易策勳，合歸收拾北山雲。", "春風入手非閑用，種得梅花却寄君。"]'),
('563a6011-1a6b-4e79-aca6-9f5c6e5be258','春夢謠','吳惟信','宋','宋诗','song-poetry','','[]','銷金帳掩水沉煙，髻滑金釵落枕邊。',32,'全唐诗/poet.song.204000.json','["銷金帳掩水沉煙，髻滑金釵落枕邊。", "魂夢不知春已去，誤隨蝴蝶過秋千。"]'),
('e2433a22-6cf5-4217-a8e6-d70b9cc14300','拜和靖墓','吳惟信','宋','宋诗','song-poetry','','[]','墳草年年一度青，梅花無主自飄零。',32,'全唐诗/poet.song.204000.json','["墳草年年一度青，梅花無主自飄零。", "定知魂在梅花上，唯有春風喚得醒。"]'),
('d8e17b6a-70af-4ea8-9ba7-0806e908b527','重拜和靖墓','吳惟信','宋','宋诗','song-poetry','','[]','片玉沉山草亦珍，斷碑殘石當麒麟。',32,'全唐诗/poet.song.204000.json','["片玉沉山草亦珍，斷碑殘石當麒麟。", "君王別爲開門戶，不欲梅花見路人。"]'),
('ff6cf3ad-7076-4bd2-b9d2-42e1975b69c0','閨怨','吳惟信','宋','宋诗','song-poetry','','[]','病起傷春獨倚門，喚人鸚鵡隔簾聞。',32,'全唐诗/poet.song.204000.json','["病起傷春獨倚門，喚人鸚鵡隔簾聞。", "無情最是東風惡，瘦却梨花一片雲。"]'),
('bdfe078b-a2de-48c5-bbba-79c08af8b3e1','仙興','吳惟信','宋','宋诗','song-poetry','','[]','宮殿高高在五雲，鶴摇松露滴行人。',32,'全唐诗/poet.song.204000.json','["宮殿高高在五雲，鶴摇松露滴行人。", "洞門不放東風過，留得桃花一院春。"]'),
('3eb2a344-d7e4-4e5b-9e5b-04aafe2404ef','山居春興','吳惟信','宋','宋诗','song-poetry','','[]','林雪消寒滴，春風入草廬。',48,'全唐诗/poet.song.204000.json','["林雪消寒滴，春風入草廬。", "好山分客看，閑地課童鉏。", "竹瘦偏宜鶴，泉清直見魚。", "邇來因苦詠，零亂一床書。"]'),
('53061d3f-fad3-423d-9b00-d8b0a83f975d','寄大使趙清臣','吳惟信','宋','宋诗','song-poetry','','[]','擒吳纔了合封侯，何止區區古蔡州。',64,'全唐诗/poet.song.204000.json','["擒吳纔了合封侯，何止區區古蔡州。", "一着高時全國體，十年危處與心謀。", "山川恢拓春風遠，天地清明王氣浮。", "白雪滿頭勳業大，不應忘却赤松遊。"]'),
('f0a90803-36d7-40a5-bb61-edbfd2a10d71','寄蔣重珍祕書','吳惟信','宋','宋诗','song-poetry','','[]','焚香誦易與天游，君命相催不肯休。',64,'全唐诗/poet.song.204000.json','["焚香誦易與天游，君命相催不肯休。", "時節固知來則是，功名却以得爲憂。", "翠蓬雲氣生衣袂，金殿陽光動冕旒。", "此際一言能悟主，始堪回首舊林丘。"]'),
('5c9ef655-cafd-4178-b8e2-326d2d20586d','寄越上高疎寮','吳惟信','宋','宋诗','song-poetry','','[]','便教烟雨畫成圖，爭似歸來有賀湖。',64,'全唐诗/poet.song.204000.json','["便教烟雨畫成圖，爭似歸來有賀湖。", "鏡裏精神西晉有，詩家標準晚唐無。", "惜花春盡鶑吟苦，敲竹風清鶴夢孤。", "世事正多心早懶，著書贏得靜工夫。"]'),
('56e4b857-b412-45ed-ac3f-672f6a39519a','立春日即事','吳惟信','宋','宋诗','song-poetry','','[]','檢殘玉曆又春來，造化無私命轉乖。',64,'全唐诗/poet.song.204000.json','["檢殘玉曆又春來，造化無私命轉乖。", "照水莫嫌窮面目，看山長有好情懷。", "生期惠遠眠雲過，死問林逋借地埋。", "詩到夜寒吟更苦，一枝梅雪映書齋。"]'),
('fbccebc6-632c-4a89-aa58-acf52257e2de','送伯氏秋潭謀居','吳惟信','宋','宋诗','song-poetry','','[]','朝吳暮楚幾時休，未必江湖有白鷗。',64,'全唐诗/poet.song.204000.json','["朝吳暮楚幾時休，未必江湖有白鷗。", "萬事莫如歸去好，一椽當爲老來謀。", "春天吟思行花徑，夜月琴聲坐竹樓。", "但得餘齡無俯仰，曾公食粥亦風流。"]'),
('dc017ece-e412-4aa3-9412-9af365032a46','送王夢升入道','吳惟信','宋','宋诗','song-poetry','','[]','不肯輕迷固有天，星冠霞氅竟翩然。',64,'全唐诗/poet.song.204000.json','["不肯輕迷固有天，星冠霞氅竟翩然。", "人能變體方超俗，丹到成功即是仙。", "伏洞黑龍聽夜呪，傍花白鹿伴春眠。", "哦詩更欲全清致，當以彌明作正傳。"]'),
('d35ec29e-08c7-4046-8650-466a075f6d0e','贈史泳','吳惟信','宋','宋诗','song-poetry','','[]','烽火窮邊幾度愁，亦曾將死博封侯。',64,'全唐诗/poet.song.204000.json','["烽火窮邊幾度愁，亦曾將死博封侯。", "謗興在彼情誰恕，事過知君痛自休。", "跨馬甲衣春雪白，射雕弓箭曉星流。", "救時正屬英雄者，更著工夫必到頭。"]'),
('71b3afa7-ca05-45e0-9ba9-9ed27d5458f7','移居即事','吳惟信','宋','宋诗','song-poetry','','[]','山移無復昔人賢，隨分長安辦一椽。',64,'全唐诗/poet.song.204000.json','["山移無復昔人賢，隨分長安辦一椽。", "掃室敢言天下志，閉門儘可雪中眠。", "携瓶與客同沽酒，接綆過鄰自汲泉。", "到此始知閑是福，居山未必似居廛。"]'),
('ccbc8c91-523c-47b2-be81-ae6b1d6c7c67','呈雲麓史侍郎','吳惟信','宋','宋诗','song-poetry','','[]','若教儘儘說漂沉，却恐無憀老不禁。',64,'全唐诗/poet.song.204000.json','["若教儘儘說漂沉，却恐無憀老不禁。", "百拙難隨今日巧，一貧方識古人心。", "牛羊歸盡荒郊闊，猿鶴愁多故國深。", "亦欲以詩爲活計，世間何許覓知音。"]'),
('f2bae3de-5bdb-4855-bbf2-ab591f275577','謀生','吳惟信','宋','宋诗','song-poetry','','[]','謀生一事到成功，消得湖邊地幾弓。',64,'全唐诗/poet.song.204000.json','["謀生一事到成功，消得湖邊地幾弓。", "韋曲有花留杜老，洛陽無客問盧仝。", "春風燕子虛簷外，夜雨蛩聲小徑中。", "所立規模雖冷淡，絕勝彈鋏舊漂蓬。"]'),
('95411d91-d060-4a58-8d5d-3be35f187894','贈越僧意書記','吳惟信','宋','宋诗','song-poetry','','["\u897f\u6e56"]','一衲冰霜二十年，不知妙用自誰傳。',64,'全唐诗/poet.song.204000.json','["一衲冰霜二十年，不知妙用自誰傳。", "心能轉物方爲佛，詩到名家亦是仙。", "喜客稍寬沽酒禁，愛閑多結住山緣。", "今冬約我西湖上，同看梅花坐釣船。"]'),
('bf33dbb3-6c77-43c0-a84c-d9c0c259a5b1','自序','吳惟信','宋','宋诗','song-poetry','','[]','一劍辭家竟陸沉，夢思空向故廬深。',64,'全唐诗/poet.song.204000.json','["一劍辭家竟陸沉，夢思空向故廬深。", "槎迷河漢千年恨，樹隔關山萬里心。", "衣垢正憐貧未去，鏡明忽有老相尋。", "春歸不與人爲約，青草催詩亦懶吟。"]'),
('5e2feb57-ebdf-4bd5-af1f-d4c2a784272a','秋夕','吳惟信','宋','宋诗','song-poetry','','[]','雨聲雲氣暮蕭蕭，羅扇恩疎井樹凋。',32,'全唐诗/poet.song.204000.json','["雨聲雲氣暮蕭蕭，羅扇恩疎井樹凋。", "心事暗隨歸夢去，壁燈留與可憐宵。"]'),
('2d39efd9-a102-4e57-ae02-46dc1a273e9e','詠貓','吳惟信','宋','宋诗','song-poetry','','[]','弄花撲蝶悔當年，喫到殘糜味却鮮。',32,'全唐诗/poet.song.204000.json','["弄花撲蝶悔當年，喫到殘糜味却鮮。", "不肯春風留業種，破氈尋夢佛燈前。"]'),
('725590b1-890b-487c-8e7f-8c4b33bf84bd','次王漢和見寄韻','吳惟信','宋','宋诗','song-poetry','','[]','扇恩已盡漢宮秋，空憶金鞍遠玉樓。',32,'全唐诗/poet.song.204000.json','["扇恩已盡漢宮秋，空憶金鞍遠玉樓。", "九辯不歌黄菊老，斷烟零雨爲誰愁。"]'),
('1458594b-7d58-455d-b7e5-7931f8f6aa18','荷花','吳惟信','宋','宋诗','song-poetry','','[]','吳姬一曲採蓮歌，回首秋風卷碧波。',32,'全唐诗/poet.song.204000.json','["吳姬一曲採蓮歌，回首秋風卷碧波。", "翠蓋不能擎雨露，鴛鴦應怨夜寒多。"]'),
('ea8da3f1-190d-454d-8fc1-6351900cd581','蘭花','吳惟信','宋','宋诗','song-poetry','','[]','寒谷初消雪半林，紫花摇弄晝陰陰。',32,'全唐诗/poet.song.204000.json','["寒谷初消雪半林，紫花摇弄晝陰陰。", "是誰曾見吹香處，千古春風楚客心。"]'),
('92b03421-6d03-4f94-a4f6-ca05cc31c168','菖蒲','吳惟信','宋','宋诗','song-poetry','','[]','一掬寒泉塊石頭，兩三莖葉弄輕柔。',32,'全唐诗/poet.song.204000.json','["一掬寒泉塊石頭，兩三莖葉弄輕柔。", "夢回一霎龍湫雨，五月軒窗也带秋。"]'),
('121b0805-c386-4c6c-a464-0bf190eae247','太湖','吳惟信','宋','宋诗','song-poetry','','["\u592a\u6e56"]','遠山數筆抹秋煙，闊闊湖波冷浸天。',32,'全唐诗/poet.song.204000.json','["遠山數筆抹秋煙，闊闊湖波冷浸天。", "晚日未沉風漸起，蘆花狼藉滿魚船。"]'),
('ba29e118-5396-497a-8237-b409f2b36bd6','送薛沂叔過西湖','吳惟信','宋','宋诗','song-poetry','','["\u897f\u6e56"]','數畝松筠種不成，荒壇祭別酒頻傾。',64,'全唐诗/poet.song.204000.json','["數畝松筠種不成，荒壇祭別酒頻傾。", "老天辜負歸鄉志，冷地尋思到世情。", "日落關河孤鶴遠，夜凉燈火小蟲鳴。", "應須趁取黄金在，買宅西湖住一程。"]'),
('851b1465-77f9-4735-b1e2-8b28bb74395e','晚過西湖','吳惟信','宋','宋诗','song-poetry','','["\u897f\u6e56"]','鷺鷥立處無秋暑，舴艋行時正晚凉。',64,'全唐诗/poet.song.204000.json','["鷺鷥立處無秋暑，舴艋行時正晚凉。", "詩興似山來衮衮，歸心如水去洋洋。", "經風楊柳高偏折，隔浦芙蓉遠更香。", "俯仰之間易陳迹，不知醉了幾千場。"]'),
('0b131a85-4fb1-4e3a-9d05-2cfcbec972a1','上曾贊府三首  其一','吳惟信','宋','宋诗','song-poetry','','[]','自肯名爲懶，何曾與衆同。',48,'全唐诗/poet.song.204000.json','["自肯名爲懶，何曾與衆同。", "閑情長向道，妙語半談空。", "平日身多病，今年藥有功。", "門前栽五柳，春亦在其中。"]'),
('a8bac452-70ce-485c-bf93-b3e9016d557b','上曾贊府三首  其二','吳惟信','宋','宋诗','song-poetry','','[]','只向廛中隠，幽居地更偏。',48,'全唐诗/poet.song.204000.json','["只向廛中隠，幽居地更偏。", "竹風吹夜月，梅雪墮寒煙。", "心定欺雲石，神清照野泉。", "一峰擎壞塔，終日在吟邊。"]'),
('e922550c-a6e8-4d30-ba55-b8c8dd435203','上曾贊府三首  其三','吳惟信','宋','宋诗','song-poetry','','[]','四歲傳家子，心明語未真。',48,'全唐诗/poet.song.204000.json','["四歲傳家子，心明語未真。", "也知初受命，似覺便成人。", "舉動須呼僕，端身學拜親。", "若教樓上去，定道摘星辰。"]'),
('8443b5e3-2c9c-44e6-8662-f4c93b86bd27','送祝五戒赴陸宰館','吳惟信','宋','宋诗','song-poetry','','[]','屈指交游十載餘，見君歸墨又歸儒。',64,'全唐诗/poet.song.204000.json','["屈指交游十載餘，見君歸墨又歸儒。", "盧能解道元無物，顔子誰知也不愚。", "既向風幡明表裏，何須雪几費工夫。", "他年名上登科記，一半清芬在祖圖。"]'),
('d9a7602b-cdd5-4f51-ad9a-e07f2998ef6c','贈任處士','吳惟信','宋','宋诗','song-poetry','','["\u897f\u6e56"]','故園不戀戀西湖，賃得民居作隠居。',64,'全唐诗/poet.song.204000.json','["故園不戀戀西湖，賃得民居作隠居。", "開口不離仁義字，閉門惟讀聖賢書。", "老無子息偏憐鶴，閑有工夫儘釣魚。", "酒熟自斟詩自和，功名一念已消除。"]'),
('27409ed0-e6bf-4979-8def-d3e819fa392e','促趙裕卿酒','吳惟信','宋','宋诗','song-poetry','','[]','擬學粗豪去索嘗，獨醒豈易敵愁腸。',32,'全唐诗/poet.song.204000.json','["擬學粗豪去索嘗，獨醒豈易敵愁腸。", "白衣終到東籬下，自是淵明等得忙。"]'),
('a5838fb4-4b2a-4829-9323-d5766cf3f4bf','懷二兄','吳惟信','宋','宋诗','song-poetry','','[]','十年兄弟恨離群，書雁南來得所聞。',64,'全唐诗/poet.song.204000.json','["十年兄弟恨離群，書雁南來得所聞。", "惠遠栽蓮歸結社，班超投筆去從軍。", "傷心異路悲春草，淚眼同時濕暮雲。", "惟有母亡無返日，自添抔土上孤墳。"]'),
('eab9a542-5640-4b60-b406-fdcd5143eb69','懷上竺宛上人','吳惟信','宋','宋诗','song-poetry','','[]','鷲峯可是不清幽，却望雲峯憶舊游。',64,'全唐诗/poet.song.204000.json','["鷲峯可是不清幽，却望雲峯憶舊游。", "松徑露寒芳草暗，竹橋煙暝落梅愁。", "高齋閑課詩吟諷，小店賒沽酒獻酬。", "今日淒涼何許見，滿庭紅葉自傷秋。"]'),
('7e385da3-2312-4773-99ee-132a8d52bc6a','懷僧兄古庵','吳惟信','宋','宋诗','song-poetry','','[]','竟日看荆樹，深情慘弗舒。',48,'全唐诗/poet.song.204000.json','["竟日看荆樹，深情慘弗舒。", "已經三載別，祇得一封書。", "故國長同夢，窮途久異居。", "遥思禪定處，松月滿庭除。"]'),
('40037f11-a6fe-41fd-a325-ee94747260ae','贈老僧','吳惟信','宋','宋诗','song-poetry','','[]','風骨稜稜雪滿頭，帽塵慵拂涕慵收。',64,'全唐诗/poet.song.204000.json','["風骨稜稜雪滿頭，帽塵慵拂涕慵收。", "天晴放鶴方開戶，雨後看山不下樓。", "樹底持經陰徑遠，竹邊洗鉢小池幽。", "自慚猶有塵緣在，安得相從老一丘。"]'),
('cc87758e-5623-4d9d-9c3b-09ccd95f836e','贈廣淳破衣  其一','吳惟信','宋','宋诗','song-poetry','','[]','禪教不能收，辭山謁貴流。',48,'全唐诗/poet.song.204000.json','["禪教不能收，辭山謁貴流。", "雨花閑定石，煙柳暗詩樓。", "借得房逃暑，沽來酒制愁。", "狂豪疑賈閬，長髮未梳頭。"]'),
('a240749f-b83b-4ea9-beff-3c05430a6dde','贈廣淳破衣  其二','吳惟信','宋','宋诗','song-poetry','','[]','舊抄梵律已俱焚，一片閑情老白雲。',32,'全唐诗/poet.song.204000.json','["舊抄梵律已俱焚，一片閑情老白雲。", "定起石臺華雨冷，滿山松籟月中聞。"]'),
('90c30839-a230-4c95-88e1-5d3a9413f97c','贈廣淳破衣  其三','吳惟信','宋','宋诗','song-poetry','','[]','蒲團坐得心成佛，却便隨流似不曾。',64,'全唐诗/poet.song.204000.json','["蒲團坐得心成佛，却便隨流似不曾。", "對客清談皆有理，求他妙用獨無憑。", "窮通數外三春定，智慧光中萬古鐙。", "俗眼安知真實行，空於畫壁看高僧。"]'),
('433b73b5-d4a1-4f07-91d7-f6dc7dc9b694','贈廣淳破衣  其四','吳惟信','宋','宋诗','song-poetry','','[]','悟徹心宗即是禪，老來風骨尚依然。',64,'全唐诗/poet.song.204000.json','["悟徹心宗即是禪，老來風骨尚依然。", "自云林下渾無事，不到人間亦有年。", "秋磬聲清敲落月，曉瓶手冷汲寒泉。", "我來問道空歸去，寂寞雲山薄暮天。"]'),
('ee6f66d3-d57c-4f53-aa59-467fc0b67770','贈宛上人','吳惟信','宋','宋诗','song-poetry','','[]','寶書梵律自分科，黄卷青燈更琢磨。',64,'全唐诗/poet.song.204000.json','["寶書梵律自分科，黄卷青燈更琢磨。", "花落閑庭春定久，塵生虛榻夜吟多。", "琴長彈後聲偏韻，丹未燒前氣已和。", "我所重君清苦處，可曾一日離煙蘿。"]'),
('1c639a43-c486-49ca-94cc-1f94d94becfd','贈唐道士','吳惟信','宋','宋诗','song-poetry','','[]','自從入道戴星冠，名利何曾着眼看。',64,'全唐诗/poet.song.204000.json','["自從入道戴星冠，名利何曾着眼看。", "地盡種蔬因茹素，瓶長儲水爲澆丹。", "風生曉檻占天久，霜滴秋壇拜斗寒。", "幾度相尋尋不見，但聞金磬響雲端。"]'),
('0d78230b-48b6-41a1-b2da-3e17b82bb169','贈洪湯夫道士','吳惟信','宋','宋诗','song-poetry','','[]','住遍長安店，何曾說到窮。',48,'全唐诗/poet.song.204000.json','["住遍長安店，何曾說到窮。", "孤吟多夜雨，一醉自春風。", "魂夢雲山遠，狂豪天地空。", "仙家拋業久，何日返遼東。"]'),
('b0121b03-b650-4d75-aeea-d83462ab58c2','贈隠者','吳惟信','宋','宋诗','song-poetry','','[]','湖上居家住最幽，簷牙倒影落滄洲。',64,'全唐诗/poet.song.204000.json','["湖上居家住最幽，簷牙倒影落滄洲。", "詩成梅塢三更月，酒醒蓮塘半夜秋。", "移石爲添燒藥竈，賣□因起讀書樓。", "經年不入煙城去，長倚欄干看白鷗。"]'),
('cc487ee6-23b3-4f64-ba2d-b299e650ff51','贈隠士','吳惟信','宋','宋诗','song-poetry','','[]','晦迹雪岩日久長，唐人冠帽道衣裳。',64,'全唐诗/poet.song.204000.json','["晦迹雪岩日久長，唐人冠帽道衣裳。", "草堂夜月琴聲細，花塢春風杖策香。", "飲酒旋尋瓢作盞，架書高沓石爲牀。", "客來總是詩朋友，一笑人間萬事忘。"]'),
('76b2306d-33b4-4848-9288-6147e80ec6d1','贈毛時可','吳惟信','宋','宋诗','song-poetry','','[]','久向長安住，多於陋巷中。',48,'全唐诗/poet.song.204000.json','["久向長安住，多於陋巷中。", "固窮全事節，傳道與童蒙。", "自喜精詩律，家曾立戰功。", "所言皆合理，心共古人同。"]'),
('2a98de09-8e55-4c8f-8a3b-f72976a0e014','贈范仲約','吳惟信','宋','宋诗','song-poetry','','[]','本是煙蘿客，如何却混塵。',48,'全唐诗/poet.song.204000.json','["本是煙蘿客，如何却混塵。", "中年百事懶，上國一家貧。", "屋老鋪黄葉，樓空映水蘋。", "詩成多自和，賞識恐無人。"]'),
('0692ef18-d5af-49d3-955e-1999c75beda3','贈俞進可  其一','吳惟信','宋','宋诗','song-poetry','','[]','已得詩名久，君猶閉戶吟。',48,'全唐诗/poet.song.204000.json','["已得詩名久，君猶閉戶吟。", "百篇皆有意，一事不關心。", "故國誰相問，高流自遠尋。", "江梅花落去，休更立牆陰。"]'),
('c354b538-8f66-4eb5-8c03-1b5df16bd4e4','贈俞進可  其二','吳惟信','宋','宋诗','song-poetry','','[]','貧爲耽詩得，詩高貧未除。',48,'全唐诗/poet.song.204000.json','["貧爲耽詩得，詩高貧未除。", "身從鄉井隠，名待御屏書。", "寡合人爲傲，回觀世自疎。", "寥寥諸葛志，寧久在茅廬。"]'),
('e6a8e924-0d50-4a97-847d-bedadaef0c42','贈永嘉張德載','吳惟信','宋','宋诗','song-poetry','','[]','文星變化成人品，指點虛空不住吟。',64,'全唐诗/poet.song.204000.json','["文星變化成人品，指點虛空不住吟。", "漸向鏡中知白髮，何曾醉裏惜黄金。", "孤燈夜雨長安夢，落葉秋風故國心。", "莫謂飄沉消銳氣，皇天自是一知音。"]'),
('1f42991d-292d-4f16-8b5f-579a0e831132','贈劉致高','吳惟信','宋','宋诗','song-poetry','','[]','自古騷人心自別，過從不是俗交朋。',64,'全唐诗/poet.song.204000.json','["自古騷人心自別，過從不是俗交朋。", "談詩海內逃名客，學道山中出定僧。", "小艇春游時載酒，高樓雨坐夜懸燈。", "深知大隠工夫到，只恐明時有詔徵。"]'),
('af440fc9-7dac-4c2c-a4cc-7f795ae9bc6c','贈韓時齋','吳惟信','宋','宋诗','song-poetry','','[]','道向時中悟，高齋直寄名。',48,'全唐诗/poet.song.204000.json','["道向時中悟，高齋直寄名。", "句清人不到，心死自無營。", "簾捲秋花影，牆翻雨籜聲。", "慈湖碑字古，歷歷見平生。"]'),
('bd7af410-46e0-46a9-9390-8a6851e23513','贈沈復齋','吳惟信','宋','宋诗','song-poetry','','[]','拋却螢囊讀罷書，甘心奉道樂清虛。',64,'全唐诗/poet.song.204000.json','["拋却螢囊讀罷書，甘心奉道樂清虛。", "氅逢拜斗身方服，巾待過庭手未除。", "無事遍求仙術學，有邪只用鬼兵驅。", "莫將雞犬雲中去，且占人間福地居。"]'),
('78dcbdae-96d0-44f8-86ae-dc1909148704','贈妙書記','吳惟信','宋','宋诗','song-poetry','','[]','已自到家鄉，清陰坐竹房。',48,'全唐诗/poet.song.204000.json','["已自到家鄉，清陰坐竹房。", "事親專一念，對客說諸方。", "斷簡藏充棟，新詩寫過牆。", "近來因院計，添得鏡中霜。"]'),
('43e53dff-eeb1-4fb2-ae0e-fcf3517d202f','贈天台項方城','吳惟信','宋','宋诗','song-poetry','','[]','天台山下住，蕭散過平生。',48,'全唐诗/poet.song.204000.json','["天台山下住，蕭散過平生。", "魂夢江湖闊，吟哦筆硯清。", "客心雲自在，人品玉分明。", "又向長安道，相逢話別情。"]'),
('c8273665-2218-465d-9a8d-5dc1c9a87cc9','贈別  其一','吳惟信','宋','宋诗','song-poetry','','[]','歌樓回首已茫然，手托蓬窗夜不眠。',32,'全唐诗/poet.song.204000.json','["歌樓回首已茫然，手托蓬窗夜不眠。", "月色水光摇蕩處，鴛鴦飛過別離船。"]'),
('ed15f3b8-24c0-447f-be1f-08d33547ea46','贈別  其二','吳惟信','宋','宋诗','song-poetry','','[]','手彈珠淚向離筵，殘日依依上客船。',32,'全唐诗/poet.song.204000.json','["手彈珠淚向離筵，殘日依依上客船。", "流水自隨人去遠，綠楊只在曲江邊。"]'),
('ede361c7-e200-4fd0-ac55-ed5b13b8e7d5','贈別  其三','吳惟信','宋','宋诗','song-poetry','','[]','臨臨欲去又添杯，一語殷勤道幾回。',32,'全唐诗/poet.song.204000.json','["臨臨欲去又添杯，一語殷勤道幾回。", "他日相思如有信，粉牋莫带淚痕來。"]'),
('d82ed59a-fe00-4a0d-ac34-1852376dfc9e','贈別  其四','吳惟信','宋','宋诗','song-poetry','','[]','笙歌一曲强相留，酒不能消滿面愁。',32,'全唐诗/poet.song.204000.json','["笙歌一曲强相留，酒不能消滿面愁。", "相對正彈離別淚，杜鵑聲到夕陽樓。"]'),
('b3730c76-ef87-48d3-91a1-aa34efeb6cbd','寄金陵樓制參監丞','吳惟信','宋','宋诗','song-poetry','','[]','不以一閑爲至樂，擬將短鋏向誰彈。',64,'全唐诗/poet.song.204000.json','["不以一閑爲至樂，擬將短鋏向誰彈。", "事於錯處知天理，心到灰時始歲寒。", "梁燕語分春寂寞，海棠愁入雨闌干。", "故人散盡江湖遠，雖有新詩寄亦難。"]'),
('2fec9562-9d34-47cf-9382-b555a2a9f60c','寄嘉興黄尉府','吳惟信','宋','宋诗','song-poetry','','[]','雙井傳家法最嚴，僊翁未學子真潜。',64,'全唐诗/poet.song.204000.json','["雙井傳家法最嚴，僊翁未學子真潜。", "固知豈弟爲民福，却恐清廉博衆嫌。", "去草旋開觀射圃，傍花深下讀書簾。", "心閑萬事皆歸理，何必蒙莊悟養恬。"]'),
('618eb1db-9ea5-46c2-82db-9f97e234c8f1','寄戴舍人','吳惟信','宋','宋诗','song-poetry','','[]','名在登科記，人間盡得知。',48,'全唐诗/poet.song.204000.json','["名在登科記，人間盡得知。", "文高多法古，官冷不趨時。", "減食因添鶴，收書爲教兒。", "近來聞注易，新集苦無詩。"]'),
('1afc6de8-6f13-4c96-85cc-2b8e111b0c51','寄詩友','吳惟信','宋','宋诗','song-poetry','','[]','丹井清泠夜向分，露庭吟苦更誰聞。',64,'全唐诗/poet.song.204000.json','["丹井清泠夜向分，露庭吟苦更誰聞。", "松凉鶴立千峯月，草濕龍歸一洞雲。", "回首江湖塵漠漠，傷心天地氣紛紛。", "何當共作誅茅計，免向秋風怨失群。"]'),
('dc2bebea-6e5f-42ca-98bc-4f546db7be44','寄桐廬戴講書','吳惟信','宋','宋诗','song-poetry','','[]','人間無好友，思憶到君深。',48,'全唐诗/poet.song.204000.json','["人間無好友，思憶到君深。", "湖上行春酒，山中坐月心。", "飄流貧未去，老大病相侵。", "乍見又輕別，東風恨一襟。"]'),
('e3ad43da-8730-4634-8063-7174faebf9df','寄巴上人','吳惟信','宋','宋诗','song-poetry','','[]','相思不但是黄昏，纔到凄凉便憶君。',64,'全唐诗/poet.song.204000.json','["相思不但是黄昏，纔到凄凉便憶君。", "明月當天人寂寂，西風捲地葉紛紛。", "歸心隨水流千里，別恨因秋湊十分。", "燈火何時共良夜，一杯香茗細論文。"]'),
('412ffe8c-5a75-40e7-afd3-6f192be36c71','寄天竺山人','吳惟信','宋','宋诗','song-poetry','','[]','白雲天竺寺，誰似爾清閑。',48,'全唐诗/poet.song.204000.json','["白雲天竺寺，誰似爾清閑。", "詩可名身後，人傳到世間。", "梅花香雪磵，樹色鎖春山。", "空有相尋約，高風豈易攀。"]'),
('c6bb1cae-0a12-4e28-ab32-8d13dceff040','寄沈二山人','吳惟信','宋','宋诗','song-poetry','','["\u897f\u6e56"]','休說邊埃掃不清，如君出處極分明。',64,'全唐诗/poet.song.204000.json','["休說邊埃掃不清，如君出處極分明。", "西湖舊有騷人分，南岳新添散吏名。", "吟苦只因聽雨久，心閑直待買山成。", "堂堂京國誰知己，百尺樓空一劍橫。"]'),
('f8110d60-30bc-4195-9bc5-96df6b3bb56c','師兄菴住香山寄  其一','吳惟信','宋','宋诗','song-poetry','','["\u592a\u6e56"]','主持蘭若太湖傍，愈覺清高不比常。',64,'全唐诗/poet.song.204000.json','["主持蘭若太湖傍，愈覺清高不比常。", "窗下圍棋松日薄，徑中行藥竹風凉。", "詩成封去鄰僧和，茶嫩惟同野客嘗。", "見說近時勤行業，朝朝親炷佛前香。"]'),
('f7f446dd-27a3-4dc7-aa7a-39eb309c9980','師兄菴住香山寄  其二','吳惟信','宋','宋诗','song-poetry','','[]','身陷清貧樂有餘，風流人物稱山居。',64,'全唐诗/poet.song.204000.json','["身陷清貧樂有餘，風流人物稱山居。", "虛堂掃地猶持課，隠几看雲罷讀書。", "破碎衣裳多自補，髼鬆頭髮少曾梳。", "有時行向湖邊去，閑對漁翁話古初。"]'),
('fcc62bff-00df-4ad7-96db-a2c451379067','寄趙寒泉','吳惟信','宋','宋诗','song-poetry','','[]','全家移入山中住，見說經年不到城。',64,'全唐诗/poet.song.204000.json','["全家移入山中住，見說經年不到城。", "閑雅足知空世念，譏彈未必損詩名。", "高樓聽雨開書坐，幽磵尋春采藥行。", "寺近只容僧問字，松風滿屋笑談清。"]'),
('1223e8e2-4cf5-456d-aa2a-994b75ec62c4','寄邵判司隠君','吳惟信','宋','宋诗','song-poetry','','[]','隠君住處枕湖濱，正與逋仙是密鄰。',64,'全唐诗/poet.song.204000.json','["隠君住處枕湖濱，正與逋仙是密鄰。", "踏雪訪梅千嶂曉，带煙看柳滿樓春。", "髮因累少莖莖綠，詩爲工多字字新。", "聞說近來渾懶出，竹光花影鎖閑身。"]'),
('0a89353c-747f-4c52-83ee-9a9693372ee5','寄徐□','吳惟信','宋','宋诗','song-poetry','','[]','白雪滿頭顱，何堪涉畏途。',48,'全唐诗/poet.song.204000.json','["白雪滿頭顱，何堪涉畏途。", "不知鄉信去，曾達故人無。", "日落鴉聲急，天空雁影孤。", "定應吟望處，思憶到江湖。"]'),
('5d197abc-c94b-42db-bda6-6c06ac33fcf7','寄何洪','吳惟信','宋','宋诗','song-poetry','','[]','久貧朋友斷，子獨喜吾貧。',48,'全唐诗/poet.song.204000.json','["久貧朋友斷，子獨喜吾貧。", "不是三生得，如何一似親。", "和詩書紙盡，招飲典衣頻。", "未遂功名志，空林且寄身。"]'),
('f785dd1d-243c-4980-acdc-5de29e7fa6a6','寄孟宰','吳惟信','宋','宋诗','song-poetry','','[]','在家只有一年閑，至樂多生筆硯間。',32,'全唐诗/poet.song.204000.json','["在家只有一年閑，至樂多生筆硯間。", "天上有樓人不見，吟魂迷在雨中山。"]'),
('48361e7d-6d1e-420b-b6a8-4cc36a0d6d84','寄何尉  其一','吳惟信','宋','宋诗','song-poetry','','[]','栽松藝竹舊林丘，失意歸來更不愁。',32,'全唐诗/poet.song.204000.json','["栽松藝竹舊林丘，失意歸來更不愁。", "縱使浮名磨滅得，好詩雲鎖越山頭。"]'),
('9f7b1fae-c776-48ed-a49d-f384c73492ca','寄何尉  其二','吳惟信','宋','宋诗','song-poetry','','[]','月影亭亭上小窗，烘乾瓦背夜來霜。',32,'全唐诗/poet.song.204000.json','["月影亭亭上小窗，烘乾瓦背夜來霜。", "扁舟欲載青山去，尚戀梅花一陣香。"]'),
('d5f71b70-c26d-4020-9d6c-e2d8099d438d','寄沈雲卿','吳惟信','宋','宋诗','song-poetry','','[]','津亭記得話分離，別後愁多只自知。',64,'全唐诗/poet.song.204000.json','["津亭記得話分離，別後愁多只自知。", "梅塢雪消春到處，草堂燈暗夜深時。", "縱然頻有相思夢，爭似同吟一首詩。", "幾欲裁書憑雁寄，碧天無際雁來遲。"]'),
('73236406-bbd1-4ed2-b6fc-e7a529c3daa6','寄毛時可','吳惟信','宋','宋诗','song-poetry','','[]','可憐未露囊中穎，一味清貧骨也清。',64,'全唐诗/poet.song.204000.json','["可憐未露囊中穎，一味清貧骨也清。", "陋巷孰知顔氏樂，京師空有子真名。", "命書平日窮幽眇，詩社多年說老成。", "風雪滿天燈暈冷，梅花紙帳各關情。"]'),
('36094186-cf20-4783-917e-d181997a3a96','寄葛司理  其一','吳惟信','宋','宋诗','song-poetry','','[]','井冷丹沉事跡存，仙翁秘訣授雲孫。',64,'全唐诗/poet.song.204000.json','["井冷丹沉事跡存，仙翁秘訣授雲孫。", "不同白鹿眠花徑，却跨青鸞出洞門。", "調尉明知逃吏隠，詳刑陰布活人恩。", "歸來日日出堂醉，春草池邊着夢魂。"]'),
('758cc3f5-39c5-4e86-aa69-3be057e102b9','寄葛司理  其二','吳惟信','宋','宋诗','song-poetry','','[]','幽居直恐世間無，疊石爲山展畫圖。',64,'全唐诗/poet.song.204000.json','["幽居直恐世間無，疊石爲山展畫圖。", "亭館看花春思遠，樓臺倚月夜吟孤。", "不論勝負收棋局，欲辯醇漓蘸酒壺。", "東閣開延天下士，昂頭相對說江湖。"]'),
('8a094594-a13b-42c4-a0ec-2039f08ed927','寄范文子','吳惟信','宋','宋诗','song-poetry','','[]','身老心無事，何曾戀故鄉。',48,'全唐诗/poet.song.204000.json','["身老心無事，何曾戀故鄉。", "風煙擬畫卷，冰雪滿詩囊。", "魂夢江湖闊，語言蘭蕙香。", "城中雖久住，多只到僧房。"]'),
('195a4d34-38a7-4d33-8f13-de9736e02de0','寄沈子壽','吳惟信','宋','宋诗','song-poetry','','[]','年年桃板上，數字見閑情。',48,'全唐诗/poet.song.204000.json','["年年桃板上，數字見閑情。", "重佛非求福，爲儒不望榮。", "回瀾知有道，卧雪可無名。", "一院梅花月，多應鶴共行。"]'),
('b7eff162-de48-4c9d-875c-d4600529b3f1','寄朱嗣宗','吳惟信','宋','宋诗','song-poetry','','[]','京國春寒情脈脈，關山月落夢悠悠。',32,'全唐诗/poet.song.204000.json','["京國春寒情脈脈，關山月落夢悠悠。", "離愁又在高樓上，滿池夕陽江水流。"]'),
('1718e64e-cc0e-46fa-9189-2ceae8fc5397','寄聞季實','吳惟信','宋','宋诗','song-poetry','','[]','君雖龜邑住，筆下自煙霞。',48,'全唐诗/poet.song.204000.json','["君雖龜邑住，筆下自煙霞。", "仁不違三月，心長在五車。", "雄豪輕俗輩，名字落詩家。", "無計論文醉，溪橋酒獨賒。"]'),
('9253e213-ea2b-4655-a358-d616d289eecc','寄倪升之','吳惟信','宋','宋诗','song-poetry','','[]','尋常曾見說，家遠欲歸難。',48,'全唐诗/poet.song.204000.json','["尋常曾見說，家遠欲歸難。", "身暫投蓮社，心猶在杏壇。", "攤書燈下讀，磨劍月中看。", "近日無消息，相思雨雪寒。"]'),
('f883d5ba-f394-4f01-a544-0673290c2053','寄朱仁叔倫魁','吳惟信','宋','宋诗','song-poetry','','[]','論文豁意氣，把酒見情親。',48,'全唐诗/poet.song.204000.json','["論文豁意氣，把酒見情親。", "一別不知返，煙花空自春。", "邊愁生鼓角，客夢落風塵。", "相約在何許，買山歸卜鄰。"]'),
('5a0a559e-782d-4b6b-9efe-1f5d347f8014','寄孔海翁號蕙林','吳惟信','宋','宋诗','song-poetry','','[]','一蕙香天下，求多却恐無。',48,'全唐诗/poet.song.204000.json','["一蕙香天下，求多却恐無。", "詩非今世悟，心與古人俱。", "鶴守林逋宅，鷗閑賀監湖。", "往來應自在，知識半樵夫。"]'),
('54a17d5d-0d9a-4d68-9caf-584c5270c325','寄趙芸窗','吳惟信','宋','宋诗','song-poetry','','[]','一住湖邊更不移，晚年幽趣只心知。',64,'全唐诗/poet.song.204000.json','["一住湖邊更不移，晚年幽趣只心知。", "竹樓夜月供琴索，莎岸春風颺釣絲。", "朝客委評新買畫，騷人聽說舊吟詩。", "神仙秘術參求遍，間洩天機向醉時。"]'),
('bc1d3af0-d67a-4511-a442-70c41cfef4f8','寄何宜齋  其一','吳惟信','宋','宋诗','song-poetry','','[]','野笛雨中吹，樓高客夢危。',24,'全唐诗/poet.song.204000.json','["野笛雨中吹，樓高客夢危。", "春風在何許，披拂好花枝。"]'),
('558dbd69-be21-47e6-b743-0c84fa4a9a61','寄何宜齋  其二','吳惟信','宋','宋诗','song-poetry','','[]','官廨相鄰古寺基，幽閑全似舊家時。',64,'全唐诗/poet.song.204000.json','["官廨相鄰古寺基，幽閑全似舊家時。", "惜花言語春風得，對酒心情夜月知。", "談道偶留僧坐久，借書惟恐僕歸遲。", "平生物理難齊處，讀徹犧經更不疑。"]'),
('9a50424e-bc1c-438e-9ca5-52cc8fe707f3','寄何宜齋  其三','吳惟信','宋','宋诗','song-poetry','','[]','爭期風翮上亨衢，果見移家入帝都。',64,'全唐诗/poet.song.204000.json','["爭期風翮上亨衢，果見移家入帝都。", "甕下不能留吏部，湖邊正可着林逋。", "高樓詩思春雲遠，深院琴聲夜月孤。", "半點紅塵應不到，晴梅影裏醉誰扶。"]'),
('62b96ad4-626e-4a5d-8474-d9e9aa8e7c44','寄桐廬張尉','吳惟信','宋','宋诗','song-poetry','','[]','一廉儒者政，半隠寄其名。',48,'全唐诗/poet.song.204000.json','["一廉儒者政，半隠寄其名。", "心古門庭闊，吟多筆研清。", "雲晴春嶂薄，潮落暮江平。", "必是閑無事，琴餘鶴數聲。"]'),
('dd7ed6cf-8350-40f0-b89a-e2aac176b1c0','寄平江吳煥章','吳惟信','宋','宋诗','song-poetry','','[]','卯喏吏歸簾影靜，午香夢熟漏聲遲。',32,'全唐诗/poet.song.204000.json','["卯喏吏歸簾影靜，午香夢熟漏聲遲。", "是中多少春風在，散落人間自不知。"]'),
('085c0b9c-9566-48b4-8cb1-df2da92316dd','寄意書記','吳惟信','宋','宋诗','song-poetry','','[]','名不昭時迹晦沉，讀書辜負雪窗深。',64,'全唐诗/poet.song.204000.json','["名不昭時迹晦沉，讀書辜負雪窗深。", "貧參萬事方知命，人到中年始識心。", "柳得煙多鶑尚戀，花隨雨盡蝶空尋。", "江湖身老春風晚，誰肯相從說苦吟。"]'),
('c75bbdef-5553-4bbf-8cb2-3f5b1ba54a65','詩寄俞晉可','吳惟信','宋','宋诗','song-poetry','','[]','一片心稽古，難教事物移。',48,'全唐诗/poet.song.204000.json','["一片心稽古，難教事物移。", "不知顔子若，亦有杜陵詩。", "江海無諸老，文章授小兒。", "非干寒苦事，短髮自成絲。"]'),
('a63bc1dc-0683-4c49-9570-cfddc93859d9','寄石越翁','吳惟信','宋','宋诗','song-poetry','','[]','異時交義比金蘭，守着龕燈話歲寒。',64,'全唐诗/poet.song.204000.json','["異時交義比金蘭，守着龕燈話歲寒。", "相去雖無千里遠，別來欲寄一書難。", "酒杯慵向花前舉，琴索空移月下彈。", "却憶湖山行樂地，越翁近日共誰看。"]'),
('7a72c795-f1ec-4630-bae3-a39d32db791a','寄俞放翁','吳惟信','宋','宋诗','song-poetry','','[]','門枕官河水，閑居少客過。',48,'全唐诗/poet.song.204000.json','["門枕官河水，閑居少客過。", "一生持酒戒，終日受詩魔。", "兒女催婚嫁，功名負琢磨。", "遥憐明鏡裏，白髮恨尤多。"]'),
('bf81224c-917c-4ec7-a5de-97c494044b78','曾懶翁復寄俞進可  其一','吳惟信','宋','宋诗','song-poetry','','[]','銀臺花落夜將闌，天亦那知客思單。',64,'全唐诗/poet.song.204000.json','["銀臺花落夜將闌，天亦那知客思單。", "鶴帳不知雲外夢，燕堂空鎖雨中寒。", "千年風雅教誰主，一卷離騷合自看。", "又恐孤山梅漸老，明朝問路過長安。"]'),
('6fbc8489-3315-4445-8b5e-6e6dbf55a680','曾懶翁復寄俞進可  其二','吳惟信','宋','宋诗','song-poetry','','[]','望望春來一解顔，春多風雨怯衣單。',64,'全唐诗/poet.song.204000.json','["望望春來一解顔，春多風雨怯衣單。", "柳煙漠漠山堂曉，梅雪紛紛水國寒。", "貧裏詩囊當自佩，醉中匣劍共君看。", "交游肯作雲翻覆，鑿齒東來喜道安。"]'),
('fa91a5bd-2c4e-433b-9377-bb45d3bef060','寄合淝兄','吳惟信','宋','宋诗','song-poetry','','[]','弟兄惆悵各分飛，說着何曾不淚垂。',64,'全唐诗/poet.song.204000.json','["弟兄惆悵各分飛，說着何曾不淚垂。", "且道十年無一信，是誰千里最相思。", "採薇猶記相思處，煮豆渾忘共泣時。", "莫把詩名沉塞北，歸來故國看梅枝。"]'),
('632c5089-8cdf-4fc1-93f7-cdab3565c509','寄遠  其一','吳惟信','宋','宋诗','song-poetry','','[]','別後一身長是客，何須更說負煙蘿。',32,'全唐诗/poet.song.204000.json','["別後一身長是客，何須更說負煙蘿。", "近來心事深如海，梅損清香雨雪多。"]'),
('3da5aed1-5745-412c-afaa-0e0186329d33','寄遠  其二','吳惟信','宋','宋诗','song-poetry','','[]','江風月白水平沙，一曲琵琶別酒家。',32,'全唐诗/poet.song.204000.json','["江風月白水平沙，一曲琵琶別酒家。", "淚洒秋風消息斷，可憐猶自信燈花。"]'),
('8eebcd99-c831-4bff-868e-8f6eb571fe1f','寄遠  其三','吳惟信','宋','宋诗','song-poetry','','[]','雨聲入夢江湖闊，暝色分愁草樹衰。',32,'全唐诗/poet.song.204000.json','["雨聲入夢江湖闊，暝色分愁草樹衰。", "君亦不來書不去，小樓閑過雁多時。"]'),
('54208555-a183-4c12-b1db-95e38206079d','寄遠  其四','吳惟信','宋','宋诗','song-poetry','','[]','澹煙芳草鄉心遠，細雨梨花客夢孤。',32,'全唐诗/poet.song.204000.json','["澹煙芳草鄉心遠，細雨梨花客夢孤。", "十載故廬茅捲盡，春風知有燕歸無。"]'),
('ddaf5f1b-7266-48dc-a256-98130f0a6485','寄贈沈子壽','吳惟信','宋','宋诗','song-poetry','','[]','君是愚堂主，明明道在愚。',48,'全唐诗/poet.song.204000.json','["君是愚堂主，明明道在愚。", "自從都放下，更不用工夫。", "盡去心中事，惟留肘後符。", "近來詩懶作，多看海山圖。"]'),
('3cfeee77-9ea1-4162-a7ef-e9330530296b','酬別意上人','吳惟信','宋','宋诗','song-poetry','','[]','塵中孤影鏡中絲，往事星星不忍思。',64,'全唐诗/poet.song.204000.json','["塵中孤影鏡中絲，往事星星不忍思。", "回首便成千里夢，尋盟當以幾時期。", "秋江浩蕩鷗翻浪，月樹蕭疎鵲遶枝。", "倘有一書相問訊，只消多寫暮雲詩。"]'),
('4a8db952-2cc6-4f96-bb00-ebc256c275c7','謝友人訪問','吳惟信','宋','宋诗','song-poetry','','[]','道在甘淪落，情交自淺深。',48,'全唐诗/poet.song.204000.json','["道在甘淪落，情交自淺深。", "雲山千里夢，燈火半生心。", "是友真難得，如君豈易尋。", "細論身後事，不覺日西沉。"]'),
('ad368467-18d6-42f5-978e-6a01cf2dfd79','謝平江吳守送萬壽安泊','吳惟信','宋','宋诗','song-poetry','','[]','萬間垂芘一夫窮，應念空成白首翁。',64,'全唐诗/poet.song.204000.json','["萬間垂芘一夫窮，應念空成白首翁。", "且喜有僧同夜話，不愁無路借春風。", "江湖氣吐詩壇下，星斗光生劍匣中。", "從此自知當變化，夢魂先別灞橋東。"]'),
('3ff35ef3-3bef-46d6-abd4-18c4259716cc','柳','吳惟信','宋','宋诗','song-poetry','','[]','灞橋煙水碧沉沉，萬縷低垂結翠陰。',64,'全唐诗/poet.song.204000.json','["灞橋煙水碧沉沉，萬縷低垂結翠陰。", "學舞腰肢風外細，凝愁顔色雨中深。", "絮漫天地凄凉淚，萍滿池塘造化心。", "記得贈行曾折處，短長亭畔聽鶑吟。"]'),
('6e31d64c-fcf7-401c-8382-d69e64bced98','梅花  其一','吳惟信','宋','宋诗','song-poetry','','[]','長是開初恨歲闌，南枝不管北枝寒。',64,'全唐诗/poet.song.204000.json','["長是開初恨歲闌，南枝不管北枝寒。", "鉏雲猶記當時種，步月寧辭永夜看。", "香借好風聞却易，影粘殘雪畫應難。", "逋仙骨冷吟聲絕，惆悵無人共倚欄。"]'),
('f37326dc-a9a5-4472-9b3f-eeb0cbae9df2','梅花  其二','吳惟信','宋','宋诗','song-poetry','','[]','客枕誰驚蝶夢闌，角聲吹動五更寒。',64,'全唐诗/poet.song.204000.json','["客枕誰驚蝶夢闌，角聲吹動五更寒。", "斷橋流水無人處，淡月疎星只自看。", "勾引閑情何日了，形容幽韻入詩難。", "冷香深恐輕狼藉，叮囑林神護石欄。"]'),
('45f157d0-75ff-4f34-96f8-1770ce4d9f38','筆  其一','吳惟信','宋','宋诗','song-poetry','','[]','早露鋒鋩獲見尋，最於文苑用功深。',32,'全唐诗/poet.song.204000.json','["早露鋒鋩獲見尋，最於文苑用功深。", "棄捐應只分毫事，誰肯留連一寸心。"]'),
('bbc3f465-b00b-4500-8301-b7fa38e8b6e8','筆  其二','吳惟信','宋','宋诗','song-poetry','','[]','鋒芒雖早露，用舍見升沉。',48,'全唐诗/poet.song.204000.json','["鋒芒雖早露，用舍見升沉。", "白禿千莖髮，丹留一寸心。", "策勳芸閣久，潔己石潭深。", "却笑江淹輩，區區夢裏尋。"]'),
('ee18c23b-8feb-4903-9704-b4cfc35b66d9','雨中聞笛','吳惟信','宋','宋诗','song-poetry','','[]','霜竹凄清带雨噴，濕煙粘草近黄昏。',32,'全唐诗/poet.song.204000.json','["霜竹凄清带雨噴，濕煙粘草近黄昏。", "誰教吹暗千林綠，不道飛花正斷魂。"]'),
('0b67ebd1-9783-4092-a812-37f8875fa3f3','嚴陵道中  其一','吳惟信','宋','宋诗','song-poetry','','[]','長安迴首遠，漸漸近嚴陵。',48,'全唐诗/poet.song.204000.json','["長安迴首遠，漸漸近嚴陵。", "客夢春江櫓，鄉心野店燈。", "路行三百里，山看萬千層。", "處處皆幽勝，題詩媿不能。"]'),
('44552e16-7278-43f4-b696-8054b816197d','嚴陵道中  其二','吳惟信','宋','宋诗','song-poetry','','[]','自信平生命，羈孤竟未通。',48,'全唐诗/poet.song.204000.json','["自信平生命，羈孤竟未通。", "春煙行路遠，夜雨客房空。", "道術徒稽古，人心不重窮。", "好山何日買，清夢鳥聲中。"]'),
('f336f55c-51ef-44b9-80ac-0bd0c14bb6b3','嚴陵道中  其三','吳惟信','宋','宋诗','song-poetry','','[]','祇見青山不見家，石欄空倚夕陽斜。',32,'全唐诗/poet.song.204000.json','["祇見青山不見家，石欄空倚夕陽斜。", "梅花欲盡東風急，春事看看到杏花。"]'),
('33b5540d-ada0-430f-9e74-9d8ee852b74d','嚴陵道中  其四','吳惟信','宋','宋诗','song-poetry','','[]','拋書閑倚店家門，往事關心孰共論。',32,'全唐诗/poet.song.204000.json','["拋書閑倚店家門，往事關心孰共論。", "燕子未歸春尚冷，一簾細雨濕黄昏。"]'),
('dbc8d98e-860e-40a8-81d6-6f33343b861a','嚴陵道中  其五','吳惟信','宋','宋诗','song-poetry','','[]','漠漠春雲暗釣臺，雲拖雨脚過山來。',32,'全唐诗/poet.song.204000.json','["漠漠春雲暗釣臺，雲拖雨脚過山來。", "客中心事深於海，小立東風看落梅。"]'),
('d307b3eb-8cd9-4fa0-bf6c-c4cf53d66cd4','烏龍道中','吳惟信','宋','宋诗','song-poetry','','[]','蕭瑟江梅墮晚風，桃花紅盡杏花紅。',32,'全唐诗/poet.song.204000.json','["蕭瑟江梅墮晚風，桃花紅盡杏花紅。", "家山不見空回首，一片春愁細雨中。"]'),
('982fbb03-ad80-425c-a82c-72ba17163696','蘇堤  其一','吳惟信','宋','宋诗','song-poetry','','[]','自向桃源失意回，人間無地避風埃。',32,'全唐诗/poet.song.204000.json','["自向桃源失意回，人間無地避風埃。", "六橋雨雪孤山路，不爲梅花也不來。"]'),
('a27b60af-3cca-4375-8285-31a36af8af39','蘇堤  其二','吳惟信','宋','宋诗','song-poetry','','[]','貧况今年極向年，過湖尚欠買船錢。',32,'全唐诗/poet.song.204000.json','["貧况今年極向年，過湖尚欠買船錢。", "步行自行蘇堤去，恐有沙鷗在柳邊。"]'),
('b3fe4f8a-4306-4592-93a4-917ca970ebae','山中','吳惟信','宋','宋诗','song-poetry','','[]','石壁飛泉洒不乾，松陰滿目寺門寒。',32,'全唐诗/poet.song.204000.json','["石壁飛泉洒不乾，松陰滿目寺門寒。", "梅花開盡無人到，萬疊春山獨自看。"]'),
('cb78b563-da7a-4ec3-b299-84018f41061a','題台州巾峰','吳惟信','宋','宋诗','song-poetry','','[]','寺在煙雲表，登臨思豁然。',48,'全唐诗/poet.song.204000.json','["寺在煙雲表，登臨思豁然。", "絕憐千嶂月，曾照一詩仙。", "眼闊疑遺世，身高見盡天。", "孤吟功未到，待借竹房眠。"]'),
('8f6bc2ba-3623-458a-88f7-1aaf771f84ed','湖上','吳惟信','宋','宋诗','song-poetry','','[]','湖上風煙古，今朝又一行。',48,'全唐诗/poet.song.204000.json','["湖上風煙古，今朝又一行。", "天寒吟詩苦，歲晚客心驚。", "饑雀窺梅瘦，翔鷗傍柳明。", "惜無人在眼，細細說平生。"]'),
('ef144de1-13dc-438f-b9aa-955805d37f80','雪後孤山','吳惟信','宋','宋诗','song-poetry','','[]','斷碑孤塚樹蒼蒼，鶴自飛歸道士房。',32,'全唐诗/poet.song.204000.json','["斷碑孤塚樹蒼蒼，鶴自飛歸道士房。", "春在梅花尋不見，滿山殘雪只聞香。"]'),
('587702c8-0bc1-4b50-8774-886cfdd86923','秋日道中','吳惟信','宋','宋诗','song-poetry','','[]','水邊籬落總斜曛，策策西風捲白雲。',32,'全唐诗/poet.song.204000.json','["水邊籬落總斜曛，策策西風捲白雲。", "萬里秋光人不管，蓼花桐葉自平分。"]'),
('b2114acb-4e29-46db-81cb-51af654ae048','初春湖上','吳惟信','宋','宋诗','song-poetry','','[]','薄薄晴煙鎖六橋，酒旗無力任西飄。',32,'全唐诗/poet.song.204000.json','["薄薄晴煙鎖六橋，酒旗無力任西飄。", "眼前春意知多少，盡屬梅梢與柳條。"]'),
('136c9bee-7963-43e5-a095-a1124a0a8c71','春日湖上  其一','吳惟信','宋','宋诗','song-poetry','','[]','傍水秋千柳影遮，銜泥雙燕入誰家。',32,'全唐诗/poet.song.204000.json','["傍水秋千柳影遮，銜泥雙燕入誰家。", "空山雨過晚風急，吹落牆陰紅杏花。"]'),
('a83bc63c-02dc-4c08-a725-5b75d31157a6','春日湖上  其二','吳惟信','宋','宋诗','song-poetry','','[]','柳絮漫空雪樣輕，梨花風起近清明。',32,'全唐诗/poet.song.204000.json','["柳絮漫空雪樣輕，梨花風起近清明。", "山南山北遊人閙，屋後屋前春鳥鳴。"]'),
('ff294b7a-dfe4-443e-8390-97cbff9facc7','竹  其一','吳惟信','宋','宋诗','song-poetry','','[]','所愛幽窗下，烟叢與露枝。',48,'全唐诗/poet.song.204000.json','["所愛幽窗下，烟叢與露枝。", "纔聞風起處，便是雨來時。", "節直將誰比，心空只自知。", "青青長在眼，休說化龍遲。"]'),
('44ff18d1-558c-4b16-a44c-b2d06992ec75','竹  其二','吳惟信','宋','宋诗','song-poetry','','[]','耐久相看是此君，眼前纔有便無塵。',64,'全唐诗/poet.song.204000.json','["耐久相看是此君，眼前纔有便無塵。", "儘多轉好延留客，雖少猶能爽快人。", "清影疎疎垂地面，高標直直上雲津。", "忍饑食肉俱休學，一擊從今認所真。"]'),
('6e9bd99f-91bc-4f8a-a28c-bdc6206bb731','竹  其三','吳惟信','宋','宋诗','song-poetry','','[]','天下清高物，無過是此君。',48,'全唐诗/poet.song.204000.json','["天下清高物，無過是此君。", "托根纔有地，長節便摩雲。", "翠色晴時見，愁聲雨夜聞。", "粉痕如早脫，龍化復何云。"]'),
('b48ad672-c703-4c7d-a80b-00d6930078ec','新竹','吳惟信','宋','宋诗','song-poetry','','[]','綠玉初抽粉尚深，清風便伴此君吟。',32,'全唐诗/poet.song.204000.json','["綠玉初抽粉尚深，清風便伴此君吟。", "雖然未見凌霜操，已是先虛應物心。"]'),
('21adcfc1-673a-425d-9360-c7625b03f1e2','山梅','吳惟信','宋','宋诗','song-poetry','','[]','寒鎖孤山見所長，斷橋水冷月如霜。',32,'全唐诗/poet.song.204000.json','["寒鎖孤山見所長，斷橋水冷月如霜。", "自將一點春風恨，散作黄昏萬斛香。"]'),
('55a770c9-9ee1-4dab-9448-cb05a4ef1d60','瓶中落梅','吳惟信','宋','宋诗','song-poetry','','[]','□英雪粲去難招，遺粉餘香亦暗消。',32,'全唐诗/poet.song.204000.json','["□英雪粲去難招，遺粉餘香亦暗消。", "休說惜春人未老，小窗明月夢無憀。"]'),
('99eda7c7-ec81-4f02-af0a-d4d9941fe3ff','掀蓬梅','吳惟信','宋','宋诗','song-poetry','','[]','斷橋日老水瀰茫，誰託丹扉夜望長。',64,'全唐诗/poet.song.204000.json','["斷橋日老水瀰茫，誰託丹扉夜望長。", "零雪正埋和靖骨，淡煙微見壽陽妝。", "一時韻巧傳清思，幾度凝愁憶暗香。", "舉世可無題品手，擅場到底屬何郎。"]'),
('fd30190b-b0b3-4dc9-945a-6631234b4a8f','和友人玉簪花韻','吳惟信','宋','宋诗','song-poetry','','[]','一撒輕雲埋曉凉，等閑曾入漢宮莊。',32,'全唐诗/poet.song.204000.json','["一撒輕雲埋曉凉，等閑曾入漢宮莊。", "千年拋擲瑶池遠，化作雲階月地香。"]'),
('a3bc5e0a-2e4a-4ef5-b5ae-e665de1308d3','良月對菊','吳惟信','宋','宋诗','song-poetry','','[]','唐人十日詠，早有怨人心。',48,'全唐诗/poet.song.204000.json','["唐人十日詠，早有怨人心。", "况在嚴霜後，猶開滿地金。", "遠香秋夢斷，艷色雨吟深。", "未信淵明死，寥寥無賞音。"]'),
('dd135758-bccc-4b78-9262-7d4081497e80','尋梅','吳惟信','宋','宋诗','song-poetry','','[]','春山合碧映春泉，今日尋梅憶去年。',32,'全唐诗/poet.song.204000.json','["春山合碧映春泉，今日尋梅憶去年。", "陰逕誰知藏造化，晴花一樹鎖寒煙。"]'),
('922a4df9-8c96-423c-9691-d4361d6398fb','野步尋梅','吳惟信','宋','宋诗','song-poetry','','[]','夕陽一半落群峰，寒葉零霜野望空。',32,'全唐诗/poet.song.204000.json','["夕陽一半落群峰，寒葉零霜野望空。", "陰谷忽然逢造化，小梅枝上見春風。"]'),
('eaaeff5e-760e-42cd-aae2-99a72e26c6a6','餞梅','吳惟信','宋','宋诗','song-poetry','','[]','半逐清流半委塵，殘花枝上又紛紛。',32,'全唐诗/poet.song.204000.json','["半逐清流半委塵，殘花枝上又紛紛。", "晚來猶自東風惡，吹得幽香滿澗雲。"]'),
('e665fc7e-4dda-4420-93dd-11af65369c88','雨中對梅寄何戶曹  其一','吳惟信','宋','宋诗','song-poetry','','[]','頗愛連山雪映溪，南枝休笑北枝低。',64,'全唐诗/poet.song.204000.json','["頗愛連山雪映溪，南枝休笑北枝低。", "揚州有客同吟詠，湖上何人更品題。", "雲未商量春後雪，花先零落雨中泥。", "清愁一點無歸着，回首東風起杖藜。"]'),
('b6814a87-95a2-4679-92a3-136eb6681e5c','雨中對梅寄何戶曹  其二','吳惟信','宋','宋诗','song-poetry','','[]','休說登山與繞溪，林間曾見入簷低。',64,'全唐诗/poet.song.204000.json','["休說登山與繞溪，林間曾見入簷低。", "盡開花去渾如雪，忽有香來即是題。", "九客不容同氣味，六宮回首隔雲泥。", "策勳商鼎何愁晚，幽意分明在短藜。"]'),
('7d2f7651-6697-4163-97d3-5de66115572d','杜鵑','吳惟信','宋','宋诗','song-poetry','','[]','錦江宮苑已成塵，啼血千年恨益深。',32,'全唐诗/poet.song.204000.json','["錦江宮苑已成塵，啼血千年恨益深。", "月滿空山花滿地，一聲愁殺未歸人。"]'),
('651801c6-b9c5-4898-bb6c-e284d7610a8d','孤雁  其一','吳惟信','宋','宋诗','song-poetry','','[]','成行遠遠別衡陽，豈道如今却斷行。',64,'全唐诗/poet.song.204000.json','["成行遠遠別衡陽，豈道如今却斷行。", "聲咽爲啼千嶂月，翅低因負五更霜。", "雖云傳信元無托，縱不遭烹亦可傷。", "遥相倦飛沙上去，蘆花吹雪水茫茫。"]'),
('7d384af3-26f0-474e-b292-5b1edd865b8f','孤雁  其二','吳惟信','宋','宋诗','song-poetry','','[]','飲啄堪憐久弗齊，念群零落楚雲西。',32,'全唐诗/poet.song.204000.json','["飲啄堪憐久弗齊，念群零落楚雲西。", "羽翰縱有飛高勢，月滿蘆花又獨棲。"]'),
('588ff51c-0d92-43a8-85f7-86f82c20406a','雨夜聞猿','吳惟信','宋','宋诗','song-poetry','','[]','山風吹滿石床雲，花落紅缸夜欲分。',32,'全唐诗/poet.song.204000.json','["山風吹滿石床雲，花落紅缸夜欲分。", "喚起十年鄉國恨，一聲猿向雨中聞。"]'),
('e401b502-7ade-4271-a4e1-cd9066e51051','空齋','吳惟信','宋','宋诗','song-poetry','','[]','空齋日日清吟過，溪上梅開也不知。',32,'全唐诗/poet.song.204000.json','["空齋日日清吟過，溪上梅開也不知。", "坐久正愁爐火冷，北風吹折蠹杉枝。"]'),
('662236c4-8dea-4a87-94bb-8a9b98baf50c','多景樓','吳惟信','宋','宋诗','song-poetry','','[]','此地昔曾遊，今朝復上樓。',48,'全唐诗/poet.song.204000.json','["此地昔曾遊，今朝復上樓。", "江楓秋雨過，塞草夕陽愁。", "渡急傳郵箭，沙危閣戰舟。", "欄干空自倚，何許是神州。"]'),
('50ee8c4d-7227-4325-b7a7-3fddaa25df33','書山家','吳惟信','宋','宋诗','song-poetry','','[]','山家元住石橋西，籬落周遭盡藥畦。',32,'全唐诗/poet.song.204000.json','["山家元住石橋西，籬落周遭盡藥畦。", "剝啄柴門人未應，鷓鴣飛上野棠梨。"]'),
('02e01b6b-3490-4161-b671-086af5369ad4','次妙上人山居韻','吳惟信','宋','宋诗','song-poetry','','[]','茅宇無人過，荆扉盡日關。',48,'全唐诗/poet.song.204000.json','["茅宇無人過，荆扉盡日關。", "酒中生快樂，詩裏着清閑。", "朋友數竿竹，畫圖千疊山。", "何如終隠此，塵境莫思還。"]'),
('9790ee47-6cba-40e6-95f4-0b36f2876f7b','村居','吳惟信','宋','宋诗','song-poetry','','[]','喜得身閑散，村居儘不妨。',48,'全唐诗/poet.song.204000.json','["喜得身閑散，村居儘不妨。", "花開和蝶看，酒熟带醅嘗。", "草徑偏臨水，柴門正向陽。", "故交應笑我，近日學耕桑。"]'),
('a61317a7-c127-477a-8361-ef115da86ac9','山庵即事','吳惟信','宋','宋诗','song-poetry','','[]','陰陰定是過殘年，積雪纔晴又滿天。',64,'全唐诗/poet.song.204000.json','["陰陰定是過殘年，積雪纔晴又滿天。", "山寺尋梅誰怕冷，地爐燒竹自無煙。", "齋蔬清潔朝朝食，詩草縱橫日日編。", "更有身心空寂處，夜禪多在佛燈前。"]'),
('05d89412-1d83-4c5e-9a07-0ab9b6dae6a6','夏日閑居','吳惟信','宋','宋诗','song-poetry','','[]','急雨開新霽，薰風獻嫩凉。',48,'全唐诗/poet.song.204000.json','["急雨開新霽，薰風獻嫩凉。", "苔花侵畫壁，雲葉護書牀。", "枕上青山遠，詩中白晝長。", "地偏人不到，幽鳥語脩篁。"]'),
('ecd20bbc-48f4-4e54-8243-21636de60c78','春日書壁','吳惟信','宋','宋诗','song-poetry','','[]','開盡桃花落盡梅，衡門寂寂掩蒼苔。',32,'全唐诗/poet.song.204000.json','["開盡桃花落盡梅，衡門寂寂掩蒼苔。", "多情惟有雙飛燕，不道人貧便不來。"]'),
('694acfd2-a405-4ec5-932d-bdb57fc57fe8','鳳凰臺懷古','吳惟信','宋','宋诗','song-poetry','','[]','憑高北望舊神州，江繞秦淮萬古流。',32,'全唐诗/poet.song.204000.json','["憑高北望舊神州，江繞秦淮萬古流。", "塞草寒沙埋戰血，更無林葉共傷秋。"]'),
('0156a2fc-1351-4931-ac85-6a141508ea1e','隠居  其一','吳惟信','宋','宋诗','song-poetry','','[]','床有詩書壁有琴，翠筠佳木午窗陰。',32,'全唐诗/poet.song.204000.json','["床有詩書壁有琴，翠筠佳木午窗陰。", "只因知得清閑貴，是事從今不動心。"]'),
('29d254ca-e6b3-4a72-aad3-801d10ad17ff','隠居  其二','吳惟信','宋','宋诗','song-poetry','','[]','身居脩竹茂林間，婆餠聲中白晝閑。',32,'全唐诗/poet.song.204000.json','["身居脩竹茂林間，婆餠聲中白晝閑。", "此地遯潛無不可，何須更買沃洲山。"]'),
('9c28a098-c62c-4e92-81da-a9b226865a86','題冰壺隠居','吳惟信','宋','宋诗','song-poetry','','[]','平生以筆代耕耘，老矣營居志亦勤。',64,'全唐诗/poet.song.204000.json','["平生以筆代耕耘，老矣營居志亦勤。", "送子誰爲盤谷序，招賢親草北山文。", "湖鷗近屋拳秋雨，野鶴分松宿暮雲。", "從此只尋閑處去，紅塵一語自紛紛。"]'),
('d0d30583-2629-4cda-825b-8b4ac0362a5c','題李師德書樓','吳惟信','宋','宋诗','song-poetry','','[]','樓高山對起，天予逸人居。',48,'全唐诗/poet.song.204000.json','["樓高山對起，天予逸人居。", "萬事不到處，滿床皆是書。", "風雲知遠大，日月付乘除。", "眇眇新吟思，誰憐合古初。"]'),
('791560e8-0acd-45ce-aff3-4f11f9f3a071','題劉同卿九里松熙游園','吳惟信','宋','宋诗','song-poetry','','[]','勝槩未教容易見，必須委曲一登躋。',64,'全唐诗/poet.song.204000.json','["勝槩未教容易見，必須委曲一登躋。", "到天不覺乘槎遠，出洞方知採藥迷。", "柳舞鶑啼春雨過，花香人醉夕陽低。", "規模儘可垂千古，却恐無詩爲品題。"]'),
('ed209ab7-3ccd-4349-95e7-1d6a13504e25','郵亭書懷','吳惟信','宋','宋诗','song-poetry','','[]','晚向郵亭立，原荒草樹稀。',48,'全唐诗/poet.song.204000.json','["晚向郵亭立，原荒草樹稀。", "天隨雲氣變，雨带雪花飛。", "客鬢今年白，故園何日歸。", "知音空滿眼，范叔自無衣。"]'),
('85b16621-70d7-4918-b668-aa174cc063b1','過朴翁故居','吳惟信','宋','宋诗','song-poetry','','[]','電露榮華一夢休，琴書多是越僧收。',32,'全唐诗/poet.song.204000.json','["電露榮華一夢休，琴書多是越僧收。", "年年柳下遊人過，指點春風認竹樓。"]'),
('621828d7-34bd-49d8-86ae-a35ac7fffdd6','幽居遣懷','吳惟信','宋','宋诗','song-poetry','','[]','百年身已任浮沉，但得幽居不厭深。',64,'全唐诗/poet.song.204000.json','["百年身已任浮沉，但得幽居不厭深。", "鶴立庭階花寂寂，鶑聲池館柳陰陰。", "看書消豁三竿日，琢句驅馳一寸心。", "莫爲無才人所棄，携壺野逸自相尋。"]'),
('7ba148c7-4542-47a9-81fc-a93c23c28e0f','明山樓即事','吳惟信','宋','宋诗','song-poetry','','[]','城高樓又闊，不與別樓同。',48,'全唐诗/poet.song.204000.json','["城高樓又闊，不與別樓同。", "對此山千疊，陶然聖一中。", "秋聲爭起樹，野色半沉空。", "後有登臨約，留題愧未工。"]'),
('f52afc8f-d8af-4fcc-97d2-1b21201fdf39','書酒樓壁','吳惟信','宋','宋诗','song-poetry','','[]','春光知我上高樓，樓外飛花逐水流。',32,'全唐诗/poet.song.204000.json','["春光知我上高樓，樓外飛花逐水流。", "蜀魄一聲雲盡碧，淡煙芳草夕陽收。"]'),
('4770bfec-e263-4cef-891d-03dc6f556455','寄題月窗','吳惟信','宋','宋诗','song-poetry','','[]','中宵浩彩潑蒼冥，人靜櫺空物象清。',64,'全唐诗/poet.song.204000.json','["中宵浩彩潑蒼冥，人靜櫺空物象清。", "若以升沉爲得失，求之見識却分明。", "煙迷野草牛先喘，露滴簷枝鵲自驚。", "此地琢磨功業就，昌黎合棄短長檠。"]'),
('c5063253-b4b9-4da7-871f-014b281634ad','古寺  其一','吳惟信','宋','宋诗','song-poetry','','[]','古院無人至，閑門曉亦開。',48,'全唐诗/poet.song.204000.json','["古院無人至，閑門曉亦開。", "山麞欹定石，野蟻集生臺。", "春動煙浮樹，陰庭雪綴苔。", "午窗幽夢斷，萬籟發清哀。"]'),
('15049c96-c4b9-438e-a4ec-e4421587bc51','古寺  其二','吳惟信','宋','宋诗','song-poetry','','[]','山煙藏古寺，鴟殿與雲齊。',48,'全唐诗/poet.song.204000.json','["山煙藏古寺，鴟殿與雲齊。", "松鼠下階走，竹雞當戶啼。", "泉寒飛瀑遠，僧老誦經低。", "細讀苔碑了，東風起杖藜。"]'),
('0a8415a6-46f2-4408-b172-c1287014ba94','廢寺','吳惟信','宋','宋诗','song-poetry','','[]','山煙寒似暝，鴟殿與雲齊。',48,'全唐诗/poet.song.204000.json','["山煙寒似暝，鴟殿與雲齊。", "栗鼠下階走，竹雞當戶啼。", "碑荒文字古，僧老語言低。", "欲住嗟無計，斜陽映杖藜。"]'),
('f1948560-6e1c-4f02-acec-85c93f817807','題僧兄山居','吳惟信','宋','宋诗','song-poetry','','[]','白髮蕭蕭萬事忘，安閑過似老漁郎。',64,'全唐诗/poet.song.204000.json','["白髮蕭蕭萬事忘，安閑過似老漁郎。", "半窗殘日敲棋響，一院秋風搗藥香。", "澆菊旋分苔澗水，開松新架草堂凉。", "過從皆是詩朋友，開口何曾論短長。"]'),
('46f456c6-3c9c-49d0-951f-79afb83f49f0','次僧兄山居韻  其一','吳惟信','宋','宋诗','song-poetry','','["\u592a\u6e56"]','僧兄肥遯地，正在太湖頭。',48,'全唐诗/poet.song.204000.json','["僧兄肥遯地，正在太湖頭。", "新句老而健，一錢貧不留。", "寡交山自看，多病藥相投。", "終日書堂坐，風筠冷似秋。"]'),
('34a55f5f-2dcb-432c-bbe9-476ae1382389','次僧兄山居韻  其二','吳惟信','宋','宋诗','song-poetry','','[]','素抱居山志，今番始有涯。',48,'全唐诗/poet.song.204000.json','["素抱居山志，今番始有涯。", "琴牀臨砌竹，棋局近庭花。", "詩興常便酒，蔬腸漸畏茶。", "清閑兄自樂，世事絕無些。"]'),
('9fef3dfa-47ce-4bf1-bbc8-2961fdecbf8c','春日書僧舍壁  其一','吳惟信','宋','宋诗','song-poetry','','[]','一宿山中萬慮忘，石泉聲細鳥聲長。',32,'全唐诗/poet.song.204000.json','["一宿山中萬慮忘，石泉聲細鳥聲長。", "落花滿地遊人去，寂寞棋窗又夕陽。"]'),
('9088446e-7696-4fa6-8719-5d92a14f0479','春日書僧舍壁  其二','吳惟信','宋','宋诗','song-poetry','','[]','松風聲裏草堂幽，欲問歸津又小留。',32,'全唐诗/poet.song.204000.json','["松風聲裏草堂幽，欲問歸津又小留。", "人自看詩春自老，毋煩海燕說閑愁。"]'),
('a9acf8ed-b167-43a6-90ee-fa94e1acc187','閑居即事書僧舍壁','吳惟信','宋','宋诗','song-poetry','','[]','自說居山好，多年靜掩扉。',48,'全唐诗/poet.song.204000.json','["自說居山好，多年靜掩扉。", "松陰圍坐石，苔色上禪衣。", "鶴瘦迎風舞，雲閑带雨歸。", "地幽人事斷，客至亦忘機。"]'),
('f11b52e3-8185-4e55-826e-efed6e428e62','宿餘暉菴','吳惟信','宋','宋诗','song-poetry','','[]','菴在村煙底，除非到者知。',48,'全唐诗/poet.song.204000.json','["菴在村煙底，除非到者知。", "因投今夜宿，記得去年詩。", "窗外雨猶滴，佛前燈未吹。", "無人同淡話，看殺菊花枝。"]'),
('46356f00-e1b6-49ec-9471-a169b6d86c27','送北澗常州住院','吳惟信','宋','宋诗','song-poetry','','[]','一生玉雪照人間，古意因君喚得還。',64,'全唐诗/poet.song.204000.json','["一生玉雪照人間，古意因君喚得還。", "丹鳳未應棲惡木，白雲又見出空山。", "吟分柳色春風暖，船載梅花月夜閑。", "從此共誰歌大雅，羈孤寒影欲追攀。"]'),
('7ae5d318-ed89-41ad-88ad-2158ab28648e','下竺後塔','吳惟信','宋','宋诗','song-poetry','','[]','僧持咒語下層巒，遠客無言自倚欄。',64,'全唐诗/poet.song.204000.json','["僧持咒語下層巒，遠客無言自倚欄。", "龍带雨歸陰洞暗，鶴沖烟入暮松寒。", "奔騰瀑布穿雲落，斷裂碑文刮蘚看。", "未有因緣來此住，三生石上指空彈。"]'),
('87d351f7-60fb-4eec-b9d2-ff498b1cfdd0','登下竺塔','吳惟信','宋','宋诗','song-poetry','','[]','浮圖靈鷲上，迢遞入晴氛。',48,'全唐诗/poet.song.204000.json','["浮圖靈鷲上，迢遞入晴氛。", "絕頂我忽到，下方鐘屢聞。", "林深餘臘雪，谷暖漲春雲。", "更待溪梅發，相期一訪君。"]'),
('bf98e9cd-0a60-477b-8440-e100cef4821c','送人之姑蘇','吳惟信','宋','宋诗','song-poetry','','[]','鶴唳空山曉，凝情畏別離。',48,'全唐诗/poet.song.204000.json','["鶴唳空山曉，凝情畏別離。", "且知君返日，正是我行時。", "花月吳城夢，松風竺寺時。", "暮雲空自隔，初不隔相思。"]'),
('6c77c34e-2d86-4bcc-b511-4873e8984c2f','送友上邊','吳惟信','宋','宋诗','song-poetry','','[]','壯年游遠塞，失意去從軍。',48,'全唐诗/poet.song.204000.json','["壯年游遠塞，失意去從軍。", "劍在猶凝血，家空未策勳。", "鄉心懸夜月，殺氣暗秋雲。", "近日方知命，兵書欲盡焚。"]'),
('c29c4726-bfee-4374-871b-3633ed42e219','送馮中可訥上邊','吳惟信','宋','宋诗','song-poetry','','[]','兵法通儒用，觀光上玉京。',48,'全唐诗/poet.song.204000.json','["兵法通儒用，觀光上玉京。", "一言旋造化，萬古立功名。", "劍入邊雲靜，船開江月明。", "深知有志者，不肯負平生。"]'),
('55a19de8-0ec0-46a5-ab60-4892c18839f4','送陸居士歸天台','吳惟信','宋','宋诗','song-poetry','','[]','道貌塵中見，何時下翠蘿。',48,'全唐诗/poet.song.204000.json','["道貌塵中見，何時下翠蘿。", "閑情秋水淡，歸夢白雲多。", "纓過龍湫濯，詩當雁蕩歌。", "清豪不易得，一別又如何。"]'),
('9d1b9928-05a5-4be0-a940-4a155825b581','送樓致和歸四明','吳惟信','宋','宋诗','song-poetry','','[]','長安塵土處，數日又隨君。',48,'全唐诗/poet.song.204000.json','["長安塵土處，數日又隨君。", "頗訝歸何速，猶勝信不聞。", "寒霜殺岸柳，曉艇入江雲。", "無語各回首，離愁落葉分。"]'),
('01ddee73-ea5e-47ad-8ccf-1e4954b5991d','上卜君壽省元','吳惟信','宋','宋诗','song-poetry','','[]','沉香亭北何時去，飯顆山前瘦一生。',64,'全唐诗/poet.song.204000.json','["沉香亭北何時去，飯顆山前瘦一生。", "已悟本心元有道，可能浮世便無名。", "江梅索笑何郎句，秋菊餐英楚客情。", "天意未教頭白盡，合應留取短長檠。"]'),
('03e35c1e-7a76-44d7-9be1-4ea31df39ca3','壽吳平江','吳惟信','宋','宋诗','song-poetry','','[]','寬閑中立大規模，民亦相隨入正途。',64,'全唐诗/poet.song.204000.json','["寬閑中立大規模，民亦相隨入正途。", "愛物只憑心造化，養生無出定工夫。", "山移別圃新花木，鶴立閑廳古畫圖。", "印匣不開公事少，一簾春雨夢江湖。"]'),
('c3311fd3-e9d0-40f2-8fd7-cfcc7ce5fd5a','呈蒙齋','吳惟信','宋','宋诗','song-poetry','','[]','出處真麟鳳，詩書得正傳。',48,'全唐诗/poet.song.204000.json','["出處真麟鳳，詩書得正傳。", "仁心全造化，風骨半神仙。", "門柳摇春雨，庭花鎖暮煙。", "雲臺非隠地，即日帝王宣。"]'),
('0a3f752c-c5e6-4979-b067-c30d7fee385f','上湖守趙希蒼  其一','吳惟信','宋','宋诗','song-poetry','','[]','方今選牧匪爲輕，果見名邦付老成。',64,'全唐诗/poet.song.204000.json','["方今選牧匪爲輕，果見名邦付老成。", "白髮益堅憂國念，丹心常藴愛君誠。", "月遷花影尨無吠，風舞棠陰鶴自行。", "看著碧瀾堂下水，與君政事一般清。"]'),
('146b4aaf-6951-42ea-86a7-3a9a79ef2ceb','上湖守趙希蒼  其二','吳惟信','宋','宋诗','song-poetry','','[]','德大才優世所宗，漢唐諸老莫如公。',64,'全唐诗/poet.song.204000.json','["德大才優世所宗，漢唐諸老莫如公。", "高明正直行王事，耿介清廉繼父風。", "六邑人居條教內，萬家春出笑談中。", "即看詔促歸清禁，手把梅花馬首東。"]'),
('c0a6b813-d12b-4a2a-a3a5-0897882750cf','上高疎寮處州守','吳惟信','宋','宋诗','song-poetry','','[]','神仙來守神仙地，銘石庭空畫戟森。',64,'全唐诗/poet.song.204000.json','["神仙來守神仙地，銘石庭空畫戟森。", "道接聖賢韓愈學，詩關風教杜陵心。", "二年鼓角傳清調，萬古溪山得賞音。", "即有詔書催入覲，金蓮夜草玉堂深。"]'),
('442b9309-9d87-4b8b-b787-5dfdfb27c2eb','呈岳總卿','吳惟信','宋','宋诗','song-poetry','','[]','黄塵漠漠路漫漫，舊釣空思水國寒。',32,'全唐诗/poet.song.204000.json','["黄塵漠漠路漫漫，舊釣空思水國寒。", "鄉信不來雲樹遠，斜陽無語下欄干。"]'),
('8915119c-2499-4fda-b038-54572a55645b','傷春','吳惟信','宋','宋诗','song-poetry','','[]','白髮傷春又一年，閒將心事卜金錢。',32,'全唐诗/poet.song.204000.json','["白髮傷春又一年，閒將心事卜金錢。", "梨花瘦盡東風軟，商略平生到杜鵑。"]'),
('76dbf544-307e-4e44-a25a-21f65757cb54','春日書懷','姚鏞','宋','宋诗','song-poetry','','[]','柔風散原野，百草摇春心。',84,'全唐诗/poet.song.204000.json','["柔風散原野，百草摇春心。", "叢薄曜陽彩，嚶鳴調好音。", "節物一以變，萬感集素襟。", "玄髮不常居，華景無停陰。", "胡爲苦貧賤，征塵翳瑶簪。", "萱葉覆堂階，荆花感晴林。", "明當理星駕，歸息清溪潯。"]'),
('c3f9f2b1-738d-4e96-a5aa-ca38c0ea8a5d','雜詩','姚鏞','宋','宋诗','song-poetry','','[]','北風日以勁，古道無人行。',72,'全唐诗/poet.song.204000.json','["北風日以勁，古道無人行。", "陽坡樹已黄，陰崖草猶青。", "四時相代謝，誰爲此枯榮。", "攬衣坐幽磴，下有流泉聲。", "聽之不成調，挹之有餘清。", "悠悠京洛塵，污人頭上纓。"]'),
('25234f77-a530-403b-a509-aa51f62a7b47','春館','姚鏞','宋','宋诗','song-poetry','','[]','山館四無鄰，東風伴幽寂。',48,'全唐诗/poet.song.204000.json','["山館四無鄰，東風伴幽寂。", "瓶花羞晚紅，庭草衒春碧。", "猿攀松樹枝，鶴踏蒼苔色。", "麾之不肯去，聽讀麻衣易。"]');
